import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js';

// =============================================================================
// 1. HELPER: CÔNG CỤ XỬ LÝ DỮ LIỆU
// =============================================================================

// zNum: Ép kiểu SỐ
const zNum = z.preprocess((val) => {
  if (val === null || val === undefined || val === '') return 0;
  const n = parseFloat(val);
  return isNaN(n) ? 0 : n;
}, z.number().default(0));

// zStr: Ép kiểu CHUỖI
const zStr = z.preprocess((val) => {
  if (Array.isArray(val)) return val.join(", ");
  if (typeof val === 'object' && val !== null) return JSON.stringify(val);
  return val == null ? "" : String(val);
}, z.string().default(''));

// zArr: Mảng mặc định
const zArr = z.array(z.any()).default([]);

// zRank: Ép kiểu PHẨM CẤP
const zRank = z.preprocess((val) => {
  let s = String(val || '').toUpperCase().trim();
  const validRanks = ['UR', 'SR', 'SSS', 'SS', 'S', 'A', 'B', 'C', 'D', 'E', 'F'];
  for (const r of validRanks) {
    if (new RegExp(`\\b${r}\\b`).test(s) || s.includes(`[${r}]`)) return r;
  }
  if (s.includes('VĨNH HẰNG') || s.includes('KHỞI NGUYÊN')) return 'UR';
  if (s.includes('QUY TẮC') || s.includes('DUY NHẤT')) return 'SR';
  if (s.includes('THẦN') || s.includes('KHÁI NIỆM')) return 'SSS';
  if (s.includes('CAM') || s.includes('BÁN THẦN')) return 'SS';
  if (s.includes('VÀNG') || s.includes('HUYỀN THOẠI')) return 'S';
  if (s.includes('TÍM') || s.includes('SỬ THI') || s.includes('LÃNH CHÚA')) return 'A';
  if (s.includes('LAM') || s.includes('TINH ANH')) return 'B';
  if (s.includes('LỤC') || s.includes('XANH')) return 'C';
  if (s.includes('TRẮNG') || s.includes('PHỔ THÔNG')) return 'E';

  return 'F'; 
}, z.enum(['F','E','D','C','B','A','S','SS','SSS','SR','UR']).default('F'));

// [NEW] zEffectMap: Xử lý trường Hiệu Quả (Record)
// Tự động chuyển chuỗi cũ thành object để tránh lỗi
const zEffectMap = z.preprocess((val) => {
  if (typeof val === 'string' && val.trim() !== '') {
    // Thử parse nếu là JSON string
    try { 
        const parsed = JSON.parse(val);
        if (typeof parsed === 'object' && parsed !== null && !Array.isArray(parsed)) return parsed;
    } catch {}
    // Nếu là chuỗi thường, chuyển thành object có key mặc định
    return { "Mô Tả Chung": val };
  }
  if (typeof val === 'object' && val !== null && !Array.isArray(val)) return val;
  return {};
}, z.record(z.string(), zStr).default({}));

