const MVU_ZOD_SCHEMA_TAG = 'Luân Hồi Nhạc Viên_Hệ Thống Biến v1.4.8R'; 
const CALL_ORIG_SETVAR = false;
const escPtr = (s) => String(s).replace(/~/g, '~0').replace(/\//g, '~1');
const dotToPtr = (dotPath) => '/' + String(dotPath).split('.').filter(Boolean).map(escPtr).join('/');

// 🟢 HÀM MỚI: Lấy tên người dùng thực tế
function getUserName() {
    try {
        if (typeof name1 !== 'undefined' && name1) return name1;
        if (window.SillyTavern && typeof window.SillyTavern.getContext === 'function') {
            const ctx = window.SillyTavern.getContext();
            if (ctx && ctx.userName) return ctx.userName;
        }
        if (localStorage.getItem('user_name')) return localStorage.getItem('user_name');
    } catch (e) { console.error('Lỗi lấy tên người dùng:', e); }
    return 'Bạn'; 
}

function getMvu() {
  return window.MVU || window.mvu || window.Mvu || window.__MVU__ || null;
}

function waitForMvu({ timeout = 8000, interval = 50 } = {}) {
  return new Promise((resolve, reject) => {
    const start = Date.now();
    const t = setInterval(() => {
      const mvu = getMvu();
      const ok = mvu && (typeof mvu.applyPatch === 'function' || typeof mvu.patch === 'function' || typeof mvu.dispatch === 'function');
      if (ok) { clearInterval(t); resolve(mvu); return; }
      if (Date.now() - start > timeout) { clearInterval(t); reject(new Error('MVU not ready')); }
    }, interval);
  });
}

function getState(mvu) {
  if (typeof mvu.getState === 'function') return mvu.getState() ?? {};
  if (mvu.state && typeof mvu.state === 'object') return mvu.state;
  return {};
}

function ptrTokens(ptr) {
  const p = String(ptr || '');
  if (!p || p === '/') return [];
  return p.split('/').slice(1).map((t) => t.replace(/~1/g, '/').replace(/~0/g, '~'));
}

function getByPtr(obj, ptr) {
  const toks = ptrTokens(ptr);
  let cur = obj;
  for (const k of toks) {
    if (cur == null) return undefined;
    cur = cur[k];
  }
  return cur;
}

function parentPtr(ptr) {
  const toks = ptrTokens(ptr);
  if (toks.length <= 1) return '/';
  return '/' + toks.slice(0, -1).map(escPtr).join('/');
}

function buildMissingAddPatches(current, defaults, basePtr = '') {
  const patches = [];
  if (defaults == null || typeof defaults !== 'object') return patches;
  if (Array.isArray(defaults)) {
    if (current === undefined) {
      patches.push({ op: 'add', path: basePtr || '/', value: defaults });
    }
    return patches;
  }
  const curObj = current && typeof current === 'object' && !Array.isArray(current) ? current : {};
  for (const k of Object.keys(defaults)) {
    const nextPtr = (basePtr || '') + '/' + escPtr(k);
    if (!(k in curObj) || curObj[k] === undefined) {
      patches.push({ op: 'add', path: nextPtr, value: defaults[k] });
    } else {
      patches.push(...buildMissingAddPatches(curObj[k], defaults[k], nextPtr));
    }
  }
  return patches;
}

function ensureParentsPatches(state, targetPtr) {
  const patches = [];
  const toks = ptrTokens(targetPtr);
  if (toks.length === 0) return patches;
  let cur = state;
  let runningPtr = '';
  for (let i = 0; i < toks.length - 1; i++) {
    const key = toks[i];
    runningPtr = runningPtr + '/' + escPtr(key);
    const val = cur && typeof cur === 'object' ? cur[key] : undefined;
    if (val === undefined) {
      patches.push({ op: 'add', path: runningPtr, value: {} });
      cur = {};
    } else {
      cur = val;
    }
  }
  return patches;
}

function applyPatchViaMvu(mvu, patches) {
  if (!patches || patches.length === 0) return;
  if (typeof mvu.applyPatch === 'function') return mvu.applyPatch(patches);
  if (typeof mvu.patch === 'function') return mvu.patch(patches);
  if (typeof mvu.dispatch === 'function') {
    return mvu.dispatch({ type: 'patch', patch: patches, patches });
  }
}

async function mvu_set(pathOrPtr, value) {
  const mvu = await waitForMvu().catch(() => null);
  if (!mvu) return;
  const ptr = String(pathOrPtr).startsWith('/') ? String(pathOrPtr) : dotToPtr(pathOrPtr);
  const state = getState(mvu);
  const exists = getByPtr(state, ptr) !== undefined;
  const patches = [];
  patches.push(...ensureParentsPatches(state, ptr));
  patches.push({ op: exists ? 'replace' : 'add', path: ptr, value });
  return applyPatchViaMvu(mvu, patches);
}

async function mvu_add(pathOrPtr, value) {
  const mvu = await waitForMvu().catch(() => null);
  if (!mvu) return;
  const ptr = String(pathOrPtr).startsWith('/') ? String(pathOrPtr) : dotToPtr(pathOrPtr);
  const state = getState(mvu);
  const patches = [];
  patches.push(...ensureParentsPatches(state, ptr));
  patches.push({ op: 'add', path: ptr, value });
  return applyPatchViaMvu(mvu, patches);
}

async function mvu_remove(pathOrPtr) {
  const mvu = await waitForMvu().catch(() => null);
  if (!mvu) return;
  const ptr = String(pathOrPtr).startsWith('/') ? String(pathOrPtr) : dotToPtr(pathOrPtr);
  return applyPatchViaMvu(mvu, [{ op: 'remove', path: ptr }]);
}

