          mvu_set('/Nhân Vật Chính/Thông Tin Cơ Bản/Họ Tên', realName);

          const currentLeader = getByPtr(cur, '/Mạo Hiểm Đoàn/Đoàn Trưởng');
          if (currentLeader === '{{user}}') {
              mvu_set('/Mạo Hiểm Đoàn/Đoàn Trưởng', realName);
