                  mvu_set(`/Túi Đồ/${itemId}/Người Sở Hữu`, realName);
              }
          });
      }
  } catch(e) { console.error("Lỗi fix tên user:", e); }
  // -----------------------------------------------------------

  if (!window.__MVU_ZOD_PATCHED__) {
    if (typeof window.setvar === 'function') {
      const orig = window.setvar;
      window.setvar = (p, v, ...rest) => {
        mvu_set(p, v);
        if (CALL_ORIG_SETVAR) return orig(p, v, ...rest);
      };
