      background: rgba(8, 8, 16, 0.9);
      border-radius: 8px;
      border: 1px solid rgba(130, 130, 130, 0.4);
      min-height: 180px;
      max-height: 320px;
      overflow-y: auto;
      font-size: 0.98rem;
      line-height: 1.7;
      color: #dedede;
      white-space: pre-wrap;
    }

    .log::-webkit-scrollbar {
      width: 6px;
    }

    .log::-webkit-scrollbar-thumb {
      background: rgba(255, 255, 255, 0.18);
      border-radius: 3px;
    }

    .log-line {
      opacity: 0;
      transform: translateY(6px);
      transition: all 0.4s ease;
    }

    .log-line.show {
      opacity: 1;
      transform: translateY(0);
    }

    .log-line.system {
      color: #9ad0ff;
    }

    .log-line.warning {
      color: #ffb36a;
    }

    .log-line.danger {
      color: #ff6b6b;
    }

    .log-line.emphasis {
      color: #e0c979;
    }

    .cursor {
      display: inline-block;
      width: 10px;
      height: 1.1em;
      margin-left: 2px;
      vertical-align: text-bottom;
      background: rgba(255, 255, 255, 0.8);
      animation: blink 0.8s infinite;
    }

    @keyframes blink {
      0%,
      49% {
        opacity: 1;
      }
      50%,
      100% {
        opacity: 0;
      }
    }

    /* ✅ Mới: Hộp nhập xuất (không tự động gửi) */
    .output-box {
      display: none;
      position: relative;
      z-index: 1;
      margin-top: 12px;
      padding: 14px 14px 12px;
      background: rgba(8, 8, 16, 0.92);
      border-radius: 8px;
      border: 1px solid rgba(130, 130, 130, 0.4);
    }

    .output-title {
      color: #e0c979;
      letter-spacing: 0.12em;
      margin-bottom: 10px;
      font-size: 0.98rem;
    }

    .output-textarea {
      width: 100%;
      min-height: 180px;
      max-height: 360px;
      resize: vertical;
      background: rgba(15, 15, 25, 0.95);
      border-radius: 6px;
      border: 1px solid rgba(200, 200, 200, 0.28);
      color: #f5f5f5;
      padding: 10px 12px;
      font-size: 0.95rem;
      line-height: 1.65;
      outline: none;
      white-space: pre-wrap;
    }

    .output-textarea:focus {
      border-color: rgba(224, 201, 120, 0.8);
      box-shadow: 0 0 4px rgba(224, 201, 120, 0.6);
    }

    .output-actions {
      margin-top: 10px;
      display: flex;
      gap: 10px;
      flex-wrap: wrap;
      justify-content: flex-end;
    }

    .btn-sub {
      padding: 8px 14px;
      border-radius: 999px;
      border: 1px solid rgba(224, 201, 120, 0.55);
      background: rgba(30, 24, 12, 0.6);
      color: #e9ddbb;
      cursor: pointer;
      transition: all 0.22s ease;
      font-size: 0.92rem;
      letter-spacing: 0.08em;
    }

    .btn-sub:hover {
      transform: translateY(-1px);
      box-shadow: 0 0 14px rgba(224, 201, 120, 0.28);
      filter: brightness(1.08);
    }

    .output-tip {
      margin-top: 10px;
      color: #8f8f8f;
      font-size: 0.88rem;
      font-style: italic;
    }

    .footer {
      margin-top: 18px;
      display: flex;
      justify-content: space-between;
      align-items: center;
      position: relative;
      z-index: 1;
      flex-wrap: wrap;
      gap: 10px;
    }

    .hint {
      font-size: 0.9rem;
      color: #888;
      font-style: italic;
    }

    .btn-main {
      padding: 9px 26px;
      font-size: 1rem;
      border-radius: 999px;
      border: 1px solid rgba(224, 201, 120, 0.7);
      background: radial-gradient(circle at 0 0, rgba(224, 201, 120, 0.55), rgba(40, 30, 10, 0.95));
      color: #111;
      letter-spacing: 0.2em;
      text-indent: 0.2em;
      cursor: pointer;
      transition: all 0.25s ease;
      min-width: 180px;
    }

    .btn-main:hover {
      transform: translateY(-1px);
      box-shadow: 0 0 18px rgba(224, 201, 120, 0.55);
      filter: brightness(1.08);
    }

    .btn-main:disabled {
      opacity: 0.4;
      cursor: not-allowed;
      box-shadow: none;
      filter: none;
    }

    @media (max-width: 640px) {
      .shell {
        padding: 20px 16px 18px;
      }

      .title-main {
        font-size: 2.1rem;
        letter-spacing: 0.25em;
      }

      .log {
        max-height: 260px;
      }

      .choose-box {
        grid-template-columns: 1fr;
      }

      .footer {
        flex-direction: column;
        align-items: flex-start;
      }

      .btn-main {
        align-self: stretch;
        text-align: center;
      }

      .output-actions {
        justify-content: stretch;
      }

      .btn-sub {
        flex: 1;
        text-align: center;
      }
    }
  </style>
</head>
<body>
  <div class="shell" id="shell">
    <div class="header">
      <div class="title-main">Luân Hồi Nhạc Viên</div>
      <div class="title-sub">INITIAL LINK · Giao Thức Truy Cập Linh Hồn Ban Đầu</div>
      <div class="divider"></div>
    </div>

    <div class="choose-box">
      <div class="choose-row">
        <label for="parkSelect">Nhạc Viên：</label>
        <select id="parkSelect">
          <option value="">Vui lòng chọn Nhạc Viên</option>
          <option value="Luân Hồi Nhạc Viên">Luân Hồi Nhạc Viên</option>
          <option value="Thánh Vực Nhạc Viên">Thánh Vực Nhạc Viên</option>
          <option value="Thủ Vọng Nhạc Viên">Thủ Vọng Nhạc Viên</option>
          <option value="Thánh Quang Nhạc Viên">Thánh Quang Nhạc Viên</option>
          <option value="Tử Vong Nhạc Viên">Tử Vong Nhạc Viên</option>
          <option value="Thiên Khải Nhạc Viên">Thiên Khải Nhạc Viên</option>
        </select>
      </div>
      <div class="choose-row">
        <label for="professionSelect">Thiên Phú：</label>
        <select id="professionSelect">
          <option value="">Vui lòng chọn Thiên Phú ban đầu</option>
          <option value="Đao Thuật Chuyên Tinh">Đao Thuật Chuyên Tinh</option>
          <option value="Trọng Trang Tinh Thông">Trọng Trang Tinh Thông</option>
          <option value="Lôi Đình Thân Hòa">Lôi Đình Thân Hòa</option>
          <option value="Tử Linh Khế Ấn">Tử Linh Khế Ấn</option>
          <option value="Thư Kích Chuyên Tinh">Thư Kích Chuyên Tinh</option>
          <option value="Nguyên Tố Liệu Dũ">Nguyên Tố Liệu Dũ</option>
          <option value="Phù Văn Đoán Khắc">Phù Văn Đoán Khắc</option>
          <option value="Huyễn Tượng Chi Phối">Huyễn Tượng Chi Phối</option>
          <option value="Thời Không Mẫn Nhuệ">Thời Không Mẫn Nhuệ</option>
          <option value="Vi Ước Truy Liệp">Vi Ước Truy Liệp</option>
          <option value="Huyết Mạch Giác Tỉnh">Huyết Mạch Giác Tỉnh</option>
          <option value="Cơ Giới Cải Tạo">Cơ Giới Cải Tạo</option>
          <option value="CUSTOM">Thiên Phú Tùy Chỉnh</option>
        </select>
      </div>
      <div class="choose-row" id="customRow" style="display:none;">
        <label for="customProfession">Tùy Chỉnh：</label>
        <input id="customProfession" type="text" placeholder="Nhập tên Thiên Phú, ví dụ: Hôi Vụ Hành Lữ Giả" />
      </div>

      <div class="choose-row">
        <label for="idInput">Số Hiệu：</label>
        <input id="idInput" type="text" placeholder="Tùy chọn: Tùy chỉnh số hiệu Kẻ Giao Ước, ví dụ: R-1037" />
      </div>
    </div>

    <div class="log" id="logBox"></div>

    <div class="output-box" id="outputBox">
      <div class="output-title">Văn Bản Mở Đầu · Đã Tạo (Sẽ không tự động gửi)</div>
      <textarea class="output-textarea" id="outputText" spellcheck="false"></textarea>
      <div class="output-actions">
        <button class="btn-sub" id="insertBtn">Nhấn để điền vào ô nhập liệu AI</button>
        <button class="btn-sub" id="copyBtn">Sao chép vào bảng nhớ tạm</button>
        <button class="btn-sub" id="collapseBtn">Thu gọn</button>
      </div>
      <div class="output-tip" id="outputTip">· Gợi ý: Nếu không tự động điền được, vui lòng dùng "Sao chép" rồi dán thủ công vào ô chat (sẽ không tự động gửi). ·</div>
    </div>

    <div class="footer">
      <div class="hint" id="hintText">· Đang chờ hệ thống kiểm tra xong ·</div>
      <button class="btn-main" id="confirmBtn" disabled>Vươn tay chạm vào Ấn Ký Nhạc Viên</button>
    </div>
  </div>

  <script>
    document.addEventListener("DOMContentLoaded", function () {
      const logBox = document.getElementById("logBox");
      const confirmBtn = document.getElementById("confirmBtn");
      const hintText = document.getElementById("hintText");
      const parkSelect = document.getElementById("parkSelect");
      const professionSelect = document.getElementById("professionSelect");
      const customRow = document.getElementById("customRow");
      const customProfessionInput = document.getElementById("customProfession");
      const idInput = document.getElementById("idInput");

      const outputBox = document.getElementById("outputBox");
      const outputText = document.getElementById("outputText");
      const insertBtn = document.getElementById("insertBtn");
      const copyBtn = document.getElementById("copyBtn");
      const collapseBtn = document.getElementById("collapseBtn");
      const outputTip = document.getElementById("outputTip");

      const userName = "{{user}}" || "Kẻ Giao Ước";

      const professionDescriptions = {
        "Đao Thuật Chuyên Tinh":
          "Cơ bắp của bạn tự động ghi nhớ góc độ phát lực, lưỡi dao trong tay như phần xương kéo dài. Bạn giỏi biến \"trảm kích\" từ động tác thành thói quen, rồi từ thói quen thành bản năng.",
        "Trọng Trang Tinh Thông":
          "Sức chịu đựng tải trọng và va chạm của bạn vượt xa người thường, sự ràng buộc của giáp trụ trở thành điểm tựa. Bạn dễ dàng giữ vững trong khi chịu sát thương và chuyển phòng thủ thành lực đẩy.",
        "Lôi Đình Thân Hòa":
          "Sự bài xích giữa bạn và hồ quang điện năng lượng cao bị suy yếu, sự phóng điện và dẫn điện trở nên \"nghe lời\" hơn bên cạnh bạn. Sự bùng nổ đến nhanh hơn, nhưng khi mất kiểm soát cũng chói mắt và chết chóc hơn.",
        "Tử Linh Khế Ấn":
          "Bạn có thể nghe thấy tiếng vọng của cái chết dễ dàng hơn và dệt tàn dư thành sức mạnh khả dụng. Cái giá là ranh giới giữa bạn và \"người sống\" sẽ dần mờ nhạt, đôi khi nghe thấy những lời thì thầm không nên tồn tại.",
        "Thư Kích Chuyên Tinh":
          "Cảm nhận của bạn về khoảng cách, độ lệch gió và nhịp thở chính xác lạ thường. Bạn không theo đuổi sự hoa mỹ, chỉ cần một phát trúng đích —— thay đổi cục diện trước khi kẻ thù nhận ra.",
        "Nguyên Tố Liệu Dũ":
          "Bạn có thể cưỡng ép kết hợp Nguyên Tố Học và Y Học: dùng lửa hàn gắn vết thương, dùng nước rửa trôi sự thối rữa, dùng gió ổn định hơi thở. Chữa trị và phá hủy chỉ cách nhau một tầng \"tỷ lệ\".",
        "Phù Văn Đoán Khắc":
          "Bạn giỏi khắc quy tắc vào kim loại, máu thịt hay thậm chí là không khí. Ký hiệu là bánh răng của bạn, công thức là vũ khí của bạn —— trước khi trận chiến bắt đầu, bạn đã viết sẵn bản thảo kết cục.",
        "Huyễn Tượng Chi Phối":
          "Sự thao túng cảm giác và tâm trí của bạn như một nghệ thuật hoang tưởng. Hiện thực trong mắt bạn chỉ là kịch bản có thể chỉnh sửa, còn kẻ thù chỉ là những khán giả bất đắc dĩ.",
        "Thời Không Mẫn Nhuệ":
          "Bạn nhạy cảm hơn với \"sai lệch\" của khe hở không gian và nhịp điệu thời gian, có thể giành được ưu thế nửa nhịp trong khoảnh khắc quan trọng. Bạn hiếm khi đối đầu trực diện, chỉ xuất hiện sai chỗ vào đúng thời điểm.",
        "Vi Ước Truy Liệp":
          "Bạn nhạy bén hơn với mục tiêu dị thường, kẻ vi phạm và lỗ hổng hợp đồng, khứu giác như khắc vào xương tủy. Bạn vừa là thợ săn, vừa là móc câu thu hồi do ý chí Nhạc Viên thả xuống.",
        "Huyết Mạch Giác Tỉnh":
          "Trong máu bạn đang ngủ say chiếc chìa khóa chưa biết, mỗi lần thức tỉnh đều có thể mở cửa, cũng có thể xé toạc khung cửa. Sức mạnh và sự mất kiểm soát chỉ cách nhau một bước, Nhạc Viên mong chờ sự \"bước sai\" của bạn.",
        "Cơ Giới Cải Tạo":
          "Bạn sẵn sàng coi cơ thể như mô-đun có thể thay thế. Bánh răng, kim loại và lõi năng lượng có thể tìm thấy chỗ đứng trên người bạn —— thậm chí cả \"nhân tính\", cũng giống như linh kiện có thể tháo lắp."
      };

      let logFinished = false;

      const lines = [
        { text: "···Tín hiệu cảm biến bị mất.", cls: "system" },
        { text: "Đang tái thiết lập liên kết thần kinh···", cls: "system" },
        { text: "Phát hiện cặn linh hồn chưa biết, đang cố gắng phân tích dữ liệu nguồn···", cls: "warning" },
        { text: "——Phân tích thành công.", cls: "system" },
        { text: `Định danh linh hồn: ${userName === "{{user}}" ? "Cá thể chưa đăng ký" : userName}`, cls: "system" },
        { text: "Tỷ lệ thích ứng Kẻ Giao Ước: 73.1% (Ngưỡng khả dụng)", cls: "warning" },
        { text: "Nhạc Viên mục tiêu: Đang chờ chọn.", cls: "system" },
        { text: "Trạng thái hiện tại: Hấp hối / Linh hồn bán tách rời.", cls: "danger" },
        { text: "——Kết quả phán định: Phù hợp điều kiện ký kết 『Khế Ước Ban Đầu』.", cls: "emphasis" },
        { text: " ", cls: "" },
        { text: "【__PARK__】 đang vươn một bàn tay về phía bạn.", cls: "emphasis" },
        { text: "Bạn có thể chọn cho mình một Nhạc Viên, chọn một con đường khởi đầu.", cls: "" },
        { text: "Cái giá là —— Thất bại tương đương xử quyết, linh hồn thuộc về Nhạc Viên.", cls: "danger" },
        { text: " ", cls: "" },
        { text: "Vui lòng xác nhận lựa chọn của bạn, sau đó chạm vào ấn ký đó.", cls: "emphasis" }
      ];

      function appendLine(content, cls) {
        const line = document.createElement("div");
        line.className = "log-line" + (cls ? " " + cls : "");
        line.textContent = content.replace("__PARK__", parkSelect.value || "Luân Hồi Nhạc Viên");
        logBox.appendChild(line);
        requestAnimationFrame(() => {
          line.classList.add("show");
        });
        logBox.scrollTop = logBox.scrollHeight;
      }

      function updateParkHandLine() {
        const park = parkSelect.value || "Luân Hồi Nhạc Viên";
        const nodes = logBox.querySelectorAll(".log-line");
        nodes.forEach((n) => {
          if (n.textContent && n.textContent.includes("đang vươn một bàn tay về phía bạn")) {
            n.textContent = `【${park}】 đang vươn một bàn tay về phía bạn.`;
          }
        });
      }

      function updateButtonState() {
        const hasPark = !!parkSelect.value;
        let hasProfession = !!professionSelect.value;

        if (professionSelect.value === "CUSTOM") {
          customRow.style.display = "flex";
          if (!customProfessionInput.value.trim()) {
            hasProfession = false;
          }
        } else {
          customRow.style.display = "none";
        }

        if (logFinished && hasPark && hasProfession) {
          confirmBtn.disabled = false;
          hintText.textContent = "· Sau khi chọn xong, có thể chạm vào Ấn Ký Nhạc Viên ·";
        } else if (logFinished) {
          hintText.textContent = "· Vui lòng chọn Nhạc Viên và Thiên Phú trước ·";
          confirmBtn.disabled = true;
        }

        updateParkHandLine();
      }

      function playLog() {
        let index = 0;
        function next() {
          if (index >= lines.length) {
            logFinished = true;
            updateButtonState();
            const cursor = document.createElement("span");
            cursor.className = "cursor";
            logBox.appendChild(cursor);
            logBox.scrollTop = logBox.scrollHeight;
            return;
          }
          const { text, cls } = lines[index++];
          appendLine(text, cls);
          setTimeout(next, 650);
        }
        next();
      }

      function showOutput(text) {
        outputBox.style.display = "block";
        outputText.value = text;
        outputText.focus();
        outputText.select();
        outputTip.textContent = "· Đã tạo: Bạn có thể sao chép, hoặc nhấn \"Điền vào ô nhập liệu AI\" (chỉ điền, không tự động gửi). ·";
        logBox.scrollTop = logBox.scrollHeight;
      }

      function trySetIntoInputInDocument(doc, text) {
        if (!doc) return false;

        const placeholder = "Đang kết nối mở đầu Luân Hồi Nhạc Viên……";

        function isVisible(el) {
          if (!el) return false;
          const style = doc.defaultView ? doc.defaultView.getComputedStyle(el) : null;
          if (style && (style.visibility === "hidden" || style.display === "none")) return false;
          return !!(el.offsetWidth || el.offsetHeight || el.getClientRects().length);
        }

        const candidates = [
          ...Array.from(doc.querySelectorAll("textarea")),
          ...Array.from(doc.querySelectorAll('input[type="text"], input:not([type])')),
          ...Array.from(doc.querySelectorAll('[contenteditable="true"]'))
        ].filter((el) => {
          if (el.disabled) return false;
          if (el.getAttribute && el.getAttribute("readonly") !== null) return false;
          return isVisible(el);
        });

        if (!candidates.length) return false;

        // Ưu tiên chọn textarea / contenteditable
        candidates.sort((a, b) => {
          const score = (el) => {
            const tag = (el.tagName || "").toLowerCase();
            const ce = el.getAttribute && el.getAttribute("contenteditable") === "true";
            let s = 0;
            if (tag === "textarea") s += 3;
            if (ce) s += 2;
            const rect = el.getBoundingClientRect ? el.getBoundingClientRect() : { width: 0, height: 0 };
            s += Math.min(2, (rect.width * rect.height) / 200000); // Lớn hơn một chút được cộng điểm
            return s;
          };
          return score(b) - score(a);
        });

        const target = candidates[0];

        // Điền vào nhưng không gửi
        if (target.tagName === "TEXTAREA" || target.tagName === "INPUT") {
          const old = target.value || "";
          if (old.includes(placeholder)) {
            target.value = old.replace(placeholder, text);
          } else if (old.trim().length === 0) {
            target.value = text;
          } else {
            target.value = old + "\n\n" + text;
          }
          target.dispatchEvent(new Event("input", { bubbles: true }));
          target.focus();
          return true;
        }

        // contenteditable
        if (target.getAttribute && target.getAttribute("contenteditable") === "true") {
          const old = target.innerText || "";
          if (old.includes(placeholder)) {
            target.innerText = old.replace(placeholder, text);
          } else if (old.trim().length === 0) {
            target.innerText = text;
          } else {
            target.innerText = old + "\n\n" + text;
          }
          target.dispatchEvent(new Event("input", { bubbles: true }));
          target.focus();
          return true;
        }

        return false;
      }

      function insertToMainInput(text) {
        // 1) Cùng nguồn có thể truy cập: Ưu tiên ghi trực tiếp vào ô nhập liệu của parent / opener (không gửi)
        try {
          if (window.parent && window.parent !== window) {
            try {
              if (trySetIntoInputInDocument(window.parent.document, text)) return true;
            } catch (_) {}
          }
          if (window.opener) {
            try {
              if (trySetIntoInputInDocument(window.opener.document, text)) return true;
            } catch (_) {}
          }
        } catch (_) {}

        // 2) Khác nguồn không thể truy cập: Chỉ gửi postMessage khi người dùng nhấp (trang chủ quyết định cách "điền")
        try {
          if (window.parent && window.parent !== window) {
            window.parent.postMessage({ type: "KSCG_INSERT_TEXT", content: text }, "*");
          }
          if (window.opener) {
            window.opener.postMessage({ type: "KSCG_INSERT_TEXT", content: text }, "*");
          }
        } catch (_) {}

        // Không thể xác nhận thành công hay không
        return false;
      }

      playLog();

      parkSelect.addEventListener("change", updateButtonState);
      professionSelect.addEventListener("change", updateButtonState);
      customProfessionInput.addEventListener("input", updateButtonState);
      idInput.addEventListener("input", updateButtonState);

      confirmBtn.addEventListener("click", function () {
        if (!parkSelect.value || !professionSelect.value) return;

        confirmBtn.disabled = true;
        hintText.textContent = "· Đang tạo văn bản mở đầu ·";

        const park = parkSelect.value || "Luân Hồi Nhạc Viên";
        let profession = professionSelect.value;
        let desc;

        if (profession === "CUSTOM") {
          profession = customProfessionInput.value.trim() || "Thiên Phú Chưa Đặt Tên";
          desc = "Bạn chưa viết chú thích cho thiên phú này, Nhạc Viên sẽ dùng chiến tích để giúp bạn bổ sung.";
        } else {
          desc = professionDescriptions[profession] || "Bạn chưa hiểu thiên phú này sẽ đưa bạn đi về đâu.";
        }

        const contractId = idInput.value.trim();
        const openingText = generateOpeningText(park, profession, desc, contractId);

        // ✅ Không gửi trực tiếp: Vào ô nhập liệu trước
        showOutput(openingText);

        // Cho phép tạo lại (không thay đổi quy trình ban đầu của bạn, chỉ mở khóa nút)
        confirmBtn.disabled = false;
        hintText.textContent = "· Đã tạo: Vui lòng sao chép bên dưới hoặc nhấn điền vào ô nhập liệu AI (sẽ không tự động gửi) ·";
      });

      function generateOpeningText(park, profession, professionDesc, contractId) {
        const user = userName === "{{user}}" ? "Kẻ Giao Ước" : userName;
        return (
          `# ${park}·Mở Đầu\n\n` +
          `Bạn tỉnh lại trong bóng tối hoàn toàn. Không có hơi thở, không có nhịp tim, ngay cả đường nét cơ thể cũng như bị tước bỏ, chỉ còn lại ý thức trôi nổi trong hư không lạnh lẽo.\n\n` +
          `Ngay sau đó, những dòng chữ vàng nhạt hiện ra trước mặt bạn —— chúng không phải ánh sáng, mà là thông tin được khắc thẳng vào linh hồn.\n\n` +
          `> 【${park}】đang kiểm tra linh hồn.\n` +
          `> Định danh: ${user}\n` +
          `> Trạng thái sinh lý: Tử vong / Ngưỡng giới hạn.\n` +
          `> Phán định thích ứng: Thông qua.\n` +
          `> Nhạc Viên trực thuộc: ${park}\n` +
          `> Thiên phú ban đầu: ${profession}\n` +
          `> Số hiệu Kẻ Giao Ước: ${contractId || "Đang phân bổ ngẫu nhiên"}\n\n` +
          `Một ánh mắt lạnh lùng nhưng không thù địch nào đó đang đánh giá bạn từ trên cao xuống. Đó không phải là góc nhìn của con người, mà giống như đang thẩm định một nguồn tài nguyên có thể tái chế.\n\n` +
          `Nó vươn một bàn tay về phía bạn —— không phải bàn tay bằng xương bằng thịt, mà là một bản khế ước lạnh băng ngay cả trong chú thích.\n\n` +
          `Chỉ cần đáp lại, bạn sẽ được ghi nhận là 「${park}·Kẻ Giao Ước Dự Bị Giai 1」, được đưa vào vô số thế giới với thiên phú 「${profession}」.\n` +
          `Người thành công đạt được sức mạnh, địa vị và những thứ không thể diễn tả. Kẻ thất bại, sẽ bị thi hành 【Xử Quyết Bắt Buộc】 —— tháo gỡ linh hồn, thu hồi toàn bộ lợi ích cùng cặn bã.\n\n` +
          `Là người sở hữu thiên phú ${profession}, bạn được phép mang theo khuynh hướng và khiếm khuyết sau:\n` +
          `${professionDesc}\n\n` +
          `Không ai giải thích thêm quy tắc cho bạn, bởi vì ở đây, "không rõ ràng" cũng là một loại thử thách.\n\n` +
          `Sâu trong bóng tối, có thứ gì đó đang chăm chú nhìn bạn.\n\n` +
          `Bạn vươn tay ra. Đầu ngón tay chạm vào Ấn Ký Nhạc Viên lơ lửng đó.\n\n` +
          `——Đau nhói, tự tách rời, dữ liệu hóa, ghi nhập số hiệu.\n\n` +
          `Khi ý thức tụ lại lần nữa, bạn đã đứng trong một đại sảnh xa lạ và lạnh lẽo.\n\n` +
          `Tiếng nhắc nhở của 【${park}】 vang lên bên tai:\n\n` +
          `> Chào mừng gia nhập, Kẻ Giao Ước.\n` +
          `> Thiên phú ban đầu: ${profession} đã ghi nhận xong.\n` +
          (contractId
            ? `> Số hiệu Kẻ Giao Ước: ${contractId} đã ghi nhập.\n`
            : `> Đang phân bổ ngẫu nhiên số hiệu Kẻ Giao Ước\n`) +
          `> Vui lòng kiểm tra tình trạng thiên phú và kỹ năng của bạn\n` +
          `> - Hệ thống sẽ phân bổ thuộc tính sáu chiều dựa trên thiên phú và trải nghiệm cá nhân của Kẻ Giao Ước trước khi tiến vào\n` +
          `  - Tổng thuộc tính sáu chiều không nhỏ hơn 50 điểm, không vượt quá 60 điểm. Vui lòng kiểm tra thuộc tính ban đầu của bạn.\n\n` +
          `Từ khoảnh khắc này, mỗi lần "sống sót" của bạn, đều sẽ được ghi vào danh sách kết toán của Nhạc Viên, bạn sẽ có ba giờ để chuẩn bị.`
        );
      }

      // ✅ Nút hộp xuất: Sao chép / Điền vào / Thu gọn
      copyBtn.addEventListener("click", function () {
        const text = outputText.value || "";
        if (!text.trim()) return;

        try {
          navigator.clipboard.writeText(text).then(() => {
            outputTip.textContent = "· Đã sao chép vào bảng nhớ tạm: Quay lại giao diện trò chuyện và dán (sẽ không tự động gửi). ·";
          }).catch(() => {
            outputText.focus();
            outputText.select();
            outputTip.textContent = "· Sao chép thất bại: Đã chọn văn bản cho bạn, vui lòng nhấn Ctrl+C để sao chép thủ công. ·";
          });
        } catch (e) {
          outputText.focus();
          outputText.select();
          outputTip.textContent = "· Sao chép thất bại: Đã chọn văn bản cho bạn, vui lòng nhấn Ctrl+C để sao chép thủ công. ·";
        }
      });

      insertBtn.addEventListener("click", function () {
        const text = outputText.value || "";
        if (!text.trim()) return;

        const ok = insertToMainInput(text);
        if (ok) {
          outputTip.textContent = "· Đã điền vào ô nhập liệu AI (chưa gửi). Quay lại giao diện trò chuyện xác nhận rồi gửi thủ công. ·";
          try {
            if (window.opener) window.opener.focus();
            else if (window.parent && window.parent !== window) window.parent.focus();
          } catch (_) {}
          return;
        }

        outputTip.textContent =
          "· Đã thử điền vào: Nếu trang chủ hỗ trợ tin nhắn KSCG_INSERT_TEXT, sẽ tự động điền; nếu không vui lòng nhấn \"Sao chép\" rồi dán thủ công (sẽ không tự động gửi). ·";
      });

      collapseBtn.addEventListener("click", function () {
        outputBox.style.display = "none";
      });

      // Lắng nghe đầu vào: Khi nhập [kscg] vào ô chat, thay thế bằng văn bản gợi ý và bật trang này lên
      try {
        const targetPattern = /\[kscg\]/g;
        document.addEventListener("input", function (event) {
          const el = event.target;
          if (el.tagName === "INPUT" || el.tagName === "TEXTAREA") {
            const val = el.value;
            if (targetPattern.test(val)) {
              el.value = val.replace(targetPattern, "Đang kết nối mở đầu Luân Hồi Nhạc Viên……");
              const html = document.documentElement.outerHTML;
              const win = window.open("", "_blank");
              if (win) {
                win.document.write(html);
                win.document.close();
              } else {
                alert("Trình duyệt đã chặn cửa sổ bật lên, vui lòng cho phép và thử lại.");
              }
            }
          }
        });

        window.replaceKSCG = function (text) {
          const targetPattern2 = /\[kscg\]/g;
          if (targetPattern2.test(text)) {
            return "Đang kết nối mở đầu Luân Hồi Nhạc Viên……";
          }
          return text;
        };

        if (window.parent && window.parent !== window) {
          window.parent.replaceKSCG = function () {
            return document.documentElement.outerHTML;
          };
        }

        window.openReincarnationIntro = function () {
          const html = document.documentElement.outerHTML;
          const win = window.open("", "_blank");
          if (win) {
            win.document.write(html);
            win.document.close();
          }
        };

        console.log("[kscg] Kịch bản kích hoạt mở đầu đã sẵn sàng");
      } catch (e) {
        console.error("Lỗi khi thiết lập trình lắng nghe [kscg]:", e);
      }
    });
  </script>
