    @keyframes light-gold-shimmer { 0% { text-shadow: 0 0 5px #f1c40f, 0 0 10px #f39c12; } 50% { text-shadow: 0 0 15px #f1c40f, 0 0 25px #f39c12, 0 0 35px #e67e22; filter: brightness(120%); } 100% { text-shadow: 0 0 5px #f1c40f, 0 0 10px #f39c12; } }
    @keyframes gold-blaze { 0% { text-shadow: 0 0 8px #f39c12, 0 0 16px #e67e22; filter: brightness(100%); } 25% { text-shadow: 0 0 15px #f1c40f, 0 0 25px #f39c12, 0 0 35px #d35400; filter: brightness(130%); } 50% { text-shadow: 0 0 20px #f1c40f, 0 0 30px #f39c12, 0 0 40px #e67e22; filter: brightness(150%); } 75% { text-shadow: 0 0 15px #f1c40f, 0 0 25px #f39c12, 0 0 35px #d35400; filter: brightness(130%); } 100% { text-shadow: 0 0 8px #f39c12, 0 0 16px #e67e22; filter: brightness(100%); } }
    @keyframes dark-gold-inferno { 0% { background-position: 0% 50%; text-shadow: 0 0 10px #d35400, 0 0 20px #c0392b; filter: brightness(100%) contrast(110%); } 33% { text-shadow: 0 0 20px #f39c12, 0 0 30px #e67e22, 0 0 40px #d35400; filter: brightness(140%) contrast(120%); } 66% { background-position: 100% 50%; text-shadow: 0 0 25px #f1c40f, 0 0 35px #f39c12, 0 0 45px #e67e22; filter: brightness(160%) contrast(130%); } 100% { background-position: 0% 50%; text-shadow: 0 0 10px #d35400, 0 0 20px #c0392b; filter: brightness(100%) contrast(110%); } }
    @keyframes legend-flame { 0% { text-shadow: 0 0 10px #e74c3c, 0 0 20px #c0392b, 0 0 30px #922b21; filter: brightness(100%); } 25% { text-shadow: 0 0 20px #e74c3c, 0 0 35px #c0392b, 0 0 50px #922b21, 0 0 65px #641e16; filter: brightness(130%); } 50% { text-shadow: 0 0 25px #ff6b6b, 0 0 40px #e74c3c, 0 0 55px #c0392b, 0 0 70px #922b21; filter: brightness(150%); } 75% { text-shadow: 0 0 20px #e74c3c, 0 0 35px #c0392b, 0 0 50px #922b21, 0 0 65px #641e16; filter: brightness(130%); } 100% { text-shadow: 0 0 10px #e74c3c, 0 0 20px #c0392b, 0 0 30px #922b21; filter: brightness(100%); } }
    @keyframes epic-burn { 0% { text-shadow: 0 0 10px #e67e22, 0 0 20px #d35400, 0 0 30px #a04000; filter: brightness(100%); } 33% { text-shadow: 0 0 20px #f39c12, 0 0 35px #e67e22, 0 0 50px #d35400, 0 0 65px #a04000; filter: brightness(140%); } 66% { text-shadow: 0 0 25px #f1c40f, 0 0 40px #f39c12, 0 0 55px #e67e22, 0 0 70px #d35400; filter: brightness(170%); } 100% { text-shadow: 0 0 10px #e67e22, 0 0 20px #d35400, 0 0 30px #a04000; filter: brightness(100%); } }
    @keyframes holy-radiance { 0% { text-shadow: 0 0 15px #fff, 0 0 25px #f1c40f, 0 0 35px #f39c12; filter: brightness(100%); } 25% { text-shadow: 0 0 25px #fff, 0 0 40px #f1c40f, 0 0 55px #f39c12, 0 0 70px #e67e22; filter: brightness(150%); } 50% { text-shadow: 0 0 35px #fff, 0 0 50px #f1c40f, 0 0 65px #f39c12, 0 0 80px #e67e22, 0 0 95px #d35400; filter: brightness(200%); } 75% { text-shadow: 0 0 25px #fff, 0 0 40px #f1c40f, 0 0 55px #f39c12, 0 0 70px #e67e22; filter: brightness(150%); } 100% { text-shadow: 0 0 15px #fff, 0 0 25px #f1c40f, 0 0 35px #f39c12; filter: brightness(100%); } }
    @keyframes void-chaos { 0% { text-shadow: 0 0 15px #e74c3c, 0 0 30px #c0392b; color: #e74c3c; filter: hue-rotate(0deg); } 20% { text-shadow: 0 0 25px #9b59b6, 0 0 40px #8e44ad, 0 0 55px #5b2c6f; color: #9b59b6; filter: hue-rotate(72deg); } 40% { text-shadow: 0 0 30px #3498db, 0 0 45px #2980b9, 0 0 60px #1a5276; color: #3498db; filter: hue-rotate(144deg); } 60% { text-shadow: 0 0 25px #2ecc71, 0 0 40px #27ae60, 0 0 55px #1e8449; color: #2ecc71; filter: hue-rotate(216deg); } 80% { text-shadow: 0 0 25px #f1c40f, 0 0 40px #f39c12, 0 0 55px #d68910; color: #f1c40f; filter: hue-rotate(288deg); } 100% { text-shadow: 0 0 15px #e74c3c, 0 0 30px #c0392b; color: #e74c3c; filter: hue-rotate(360deg); } }
    @keyframes cosmic-flow { 0% { background-position: 0% 50%; color: #ff00ff; text-shadow: 0 0 5px #ff00ff; } 25% { color: #00ffff; text-shadow: 0 0 5px #00ffff; } 50% { background-position: 100% 50%; color: #ffff00; text-shadow: 0 0 5px #ffff00; } 75% { color: #00ffff; text-shadow: 0 0 5px #00ffff; } 100% { background-position: 0% 50%; color: #ff00ff; text-shadow: 0 0 5px #ff00ff; } }

    /* Quality Classes */
    .q-white { color: #bdc3c7; }
    .q-green { color: #2ecc71; text-shadow: 0 0 4px #27ae60, 0 0 8px rgba(39, 174, 96, 0.5); animation: green-glow 2.5s ease-in-out infinite; }
    .q-blue { color: #3498db; text-shadow: 0 0 6px #2980b9, 0 0 12px rgba(52, 152, 219, 0.6); animation: blue-pulse 2s ease-in-out infinite; font-weight: 600; }
    .q-purple { color: #9b59b6; text-shadow: 0 0 8px #8e44ad, 0 0 16px rgba(155, 89, 182, 0.7); font-weight: 700; animation: purple-flare 2s ease-in-out infinite; }
    .q-d-purple { color: #d7bde2; text-shadow: 0 0 8px #bb8fce, 0 0 16px #9b59b6, 0 0 24px #8e44ad; font-weight: 800; animation: dark-purple-glow 2.5s ease-in-out infinite; letter-spacing: 0.3px; }
    .q-l-gold { color: #f1c40f; text-shadow: 0 0 8px #f39c12, 0 0 16px rgba(241, 196, 15, 0.7); font-weight: 700; animation: light-gold-shimmer 2s ease-in-out infinite; }
    .q-gold { color: #f39c12; text-shadow: 0 0 10px #e67e22, 0 0 20px #f1c40f; font-weight: 800; animation: gold-blaze 1.5s ease-in-out infinite; filter: drop-shadow(0 0 4px #f39c12); }
    .q-d-gold { background: linear-gradient(90deg, #d35400, #e67e22, #f39c12, #f1c40f, #f39c12, #e67e22, #d35400); background-size: 400% 100%; -webkit-background-clip: text; -webkit-text-fill-color: transparent; font-weight: 900; animation: dark-gold-inferno 2s ease-in-out infinite; filter: drop-shadow(0 0 5px #e67e22); }
    .q-legend { color: #e74c3c; text-shadow: 0 0 12px #c0392b, 0 0 24px #e74c3c, 0 0 36px #922b21; font-weight: 900; animation: legend-flame 1.5s ease-in-out infinite; filter: drop-shadow(0 0 6px #e74c3c); letter-spacing: 0.5px; }
    .q-epic { color: #e67e22; text-shadow: 0 0 15px #d35400, 0 0 25px #e67e22, 0 0 40px #a04000; font-weight: 900; animation: epic-burn 1.2s ease-in-out infinite; border-bottom: 2px solid #e67e22; filter: drop-shadow(0 0 8px #e67e22); letter-spacing: 0.8px; }
    .q-holy { color: #fff; text-shadow: 0 0 15px #fff, 0 0 25px #f1c40f, 0 0 40px #f39c12; font-weight: 900; animation: holy-radiance 1.5s ease-in-out infinite; filter: drop-shadow(0 0 10px #fff); letter-spacing: 1px; text-transform: uppercase; }
    .q-void { font-weight: 900; animation: void-chaos 3s linear infinite; text-decoration: underline wavy; filter: drop-shadow(0 0 12px currentColor); letter-spacing: 1.5px; text-transform: uppercase; }

    /* Rank/Grade Classes */
    .g-f { color: #7f8c8d; }
    .g-e { color: #ecf0f1; }
    .g-d { color: #2ecc71; text-shadow: 0 0 4px #27ae60; }
    .g-c { color: #3498db; text-shadow: 0 0 6px #2980b9; animation: blue-pulse 2.5s ease-in-out infinite; }
    .g-b { color: #9b59b6; text-shadow: 0 0 8px #8e44ad; font-weight: bold; animation: purple-flare 2s ease-in-out infinite; }
    .g-a { color: #d7bde2; text-shadow: 0 0 10px #8e44ad, 0 0 5px #fff; font-weight: bold; animation: dark-purple-glow 2.5s ease-in-out infinite; }
    .g-s { color: #f1c40f; text-shadow: 0 0 10px #f39c12; font-weight: bold; animation: gold-blaze 2s ease-in-out infinite; }
    .g-ss { background: linear-gradient(to right, #f1c40f, #e67e22, #f39c12); background-size: 200% 100%; -webkit-background-clip: text; -webkit-text-fill-color: transparent; font-weight: 800; animation: dark-gold-inferno 2s ease-in-out infinite; filter: drop-shadow(0 0 5px #f39c12); }
    .g-sss { background: linear-gradient(45deg, #e74c3c, #f1c40f, #2ecc71, #3498db, #e74c3c); background-size: 400% 400%; -webkit-background-clip: text; -webkit-text-fill-color: transparent; font-weight: 900; animation: rainbow-flow 3s ease infinite; filter: drop-shadow(0 0 8px #f1c40f); letter-spacing: 0.5px; }
    .g-sr { color: #fff; text-shadow: 0 0 10px #00ffff, 0 0 20px #ff00ff, 0 0 30px #ffff00; animation: cosmic-flow 4s linear infinite; font-weight: 900; filter: drop-shadow(0 0 10px #00ffff); }
    .g-ur { background: linear-gradient(90deg, #ff00ff, #00ffff, #ffff00, #ff00ff); background-size: 300% 100%; -webkit-background-clip: text; -webkit-text-fill-color: transparent; animation: void-chaos 3s linear infinite; font-weight: 900; filter: drop-shadow(0 0 15px #ff00ff); border-bottom: 2px solid rgba(255,255,255,0.5); letter-spacing: 1px; text-transform: uppercase; }

    /* Tier Badges (T0-T9) */
    .tier-badge { font-size: 10px; padding: 2px 6px; border-radius: 3px; margin-left: 8px; font-weight: bold; text-transform: uppercase; display: inline-block; }
    .tier-t0 { background: #7f8c8d; color: #ecf0f1; border: 1px solid #95a5a6; } 
    .tier-t1 { background: #27ae60; color: #fff; border: 1px solid #2ecc71; box-shadow: 0 0 3px rgba(46, 204, 113, 0.3); } 
    .tier-t2 { background: #2980b9; color: #fff; border: 1px solid #3498db; box-shadow: 0 0 5px rgba(52, 152, 219, 0.4); } 
    .tier-t3 { background: #8e44ad; color: #fff; border: 1px solid #9b59b6; box-shadow: 0 0 6px rgba(155, 89, 182, 0.5); } 
    .tier-t4 { background: linear-gradient(135deg, #f39c12, #d35400); color: #fff; border: 1px solid #f1c40f; box-shadow: 0 0 8px rgba(243, 156, 18, 0.6); animation: shimmer 3s infinite; } 
    .tier-t5 { background: linear-gradient(135deg, #c0392b, #e74c3c); color: #fff; border: 1px solid #e74c3c; box-shadow: 0 0 10px rgba(231, 76, 60, 0.7); animation: burning 2s infinite alternate; } 
    .tier-t6 { background: linear-gradient(90deg, #7b1fa2, #4a148c); color: #fff; border: 1px solid #8e24aa; box-shadow: 0 0 12px rgba(123, 31, 162, 0.8), inset 0 0 5px rgba(255, 255, 255, 0.3); font-weight: 800; letter-spacing: 0.5px; }
    .tier-t7 { background: linear-gradient(120deg, #f1c40f, #ecf0f1, #f1c40f); background-size: 200% auto; color: #333; border: 1px solid #fff; box-shadow: 0 0 15px rgba(241, 196, 15, 0.6); animation: gold-flow 2s linear infinite; font-weight: 900; }
    .tier-t8 { background: #000; color: #00ffff; border: 1px solid #00ffff; box-shadow: 0 0 10px #00ffff, inset 0 0 10px #0000ff; animation: star-pulse 2s infinite; font-weight: 900; text-shadow: 0 0 5px #00ffff; }
    .tier-t9 { background: #111; color: #ff00ff; border: 1px solid transparent; box-shadow: 0 0 20px #ff00ff; animation: glitch 1s infinite alternate-reverse; font-weight: 900; text-decoration: underline double; text-shadow: 2px 0 #00ffff, -2px 0 #ff0000; }

    /* --- ITEM DETAILS, GEMS & AFFIXES --- */
    .item-detail-panel { background: #222; border: 1px solid #444; border-top: none; padding: 10px; margin-top: -2px; margin-bottom: 5px; border-radius: 0 0 4px 4px; display: none; font-size: 12px; animation: fadeIn 0.2s ease; position: relative; z-index: 10; }
    .detail-header { display: flex; justify-content: space-between; border-bottom: 1px solid #444; padding-bottom: 5px; margin-bottom: 5px; }
    .detail-stats { color: #bdc3c7; margin-bottom: 5px; display: grid; grid-template-columns: 1fr 1fr; gap: 5px; font-size: 11px; }
    .detail-desc { color: #7f8c8d; font-style: italic; margin-top: 5px; padding-top: 5px; border-top: 1px dashed #333; }

    .affix-section { margin-top: 6px; padding-top: 6px; border-top: 1px dashed #444; }
    .affix-title { font-size: 11px; color: #e67e22; margin-bottom: 4px; }
    .affix-item-wrapper { display: flex; flex-direction: column; margin-bottom: 3px; }
    .affix-item { background: #2c2c2c; border-left: 2px solid #3498db; padding: 4px 6px; border-radius: 2px; font-size: 11px; cursor: pointer; transition: background 0.2s; display: flex; justify-content: space-between; align-items: center; }
    .affix-item:hover { background: #3a3a3a; }
    .affix-name { color: #ecf0f1; font-weight: bold; }
    .affix-toggle { font-size: 9px; color: #7f8c8d; }
    .affix-detail { display: none; padding: 5px 8px; background: #222; color: #bdc3c7; font-size: 11px; line-height: 1.4; border-radius: 0 0 3px 3px; border: 1px dashed #333; border-top: none; }

    .gem-section { margin-top: 6px; padding-top: 6px; border-top: 1px dashed #444; }
    .gem-title { font-size: 11px; color: #9b59b6; margin-bottom: 4px; }
    .gem-item-wrapper { display: flex; flex-direction: column; margin-bottom: 3px; }
    .gem-item { background: #2c2c2c; border-left: 2px solid #9b59b6; padding: 4px 6px; border-radius: 2px; font-size: 11px; cursor: pointer; transition: background 0.2s; display: flex; justify-content: space-between; align-items: center; }
    .gem-item:hover { background: #3a3a3a; }
    .gem-name { color: #f1c40f; font-weight: bold; }
    .gem-toggle { font-size: 9px; color: #7f8c8d; }

    /* --- SKILLS & EFFECTS --- */
    .ability-list { display: flex; flex-direction: column; gap: 8px; }
    .ability-item { background: #333; border-radius: 4px; border-left: 3px solid #555; overflow: hidden; }
    .ability-item.skill { border-left-color: var(--primary-color); }
    .ability-item.talent { border-left-color: #f39c12; }
    .ability-item.buff { border-left-color: #2ecc71; }
    .ability-item.record { border-left-color: #e67e22; }
    .ability-main { padding: 10px; cursor: pointer; transition: background 0.2s; }
    .ability-main:hover { background: #3a3a3a; }
    .ability-header { display: flex; justify-content: space-between; margin-bottom: 4px; font-weight: bold; font-size: 13px; }
    .ability-desc { font-size: 12px; color: #bdc3c7; margin-top: 4px; font-style: italic; }
    .ability-toggle { font-size: 10px; color: #7f8c8d; float: right; }
    .ability-detail { display: none; padding: 10px; background: #2a2a2a; border-top: 1px solid #444; animation: fadeIn 0.2s ease; }
    .ability-detail-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 6px; font-size: 11px; }
    .ability-detail-row { display: flex; justify-content: space-between; padding: 4px 6px; background: #333; border-radius: 3px; }
    .ability-detail-row.full { grid-column: 1 / -1; }
    .ability-detail-label { color: #7f8c8d; }
    .ability-detail-value { color: #ecf0f1; }
    .ability-detail-desc { grid-column: 1 / -1; padding: 8px; background: #333; border-radius: 3px; color: #bdc3c7; line-height: 1.5; white-space: pre-wrap; }

    .ability-sub-list { display: flex; flex-direction: column; gap: 3px; margin-top: 4px; }
    .ability-sub-item-wrapper { display: flex; flex-direction: column; }
    .ability-sub-item { display: flex; justify-content: space-between; align-items: center; padding: 4px 6px; background: #2a2a2a; border-radius: 2px; cursor: pointer; transition: background 0.2s; border-left: 2px solid #555; }
    .ability-sub-item:hover { background: #333; }
    .ability-sub-name { font-size: 11px; font-weight: bold; color: #ecf0f1; display: flex; align-items: center; gap: 4px; }
    .ability-sub-toggle { font-size: 9px; color: #7f8c8d; }
    .ability-sub-detail { display: none; padding: 6px; background: #222; border: 1px dashed #333; border-top: none; font-size: 11px; color: #bdc3c7; line-height: 1.4; border-radius: 0 0 2px 2px; }

    /* Other Components */
    .prof-panel { background: #252525; padding: 15px; border-radius: 4px; border: 1px solid #333; margin-bottom: 15px; }
    .prof-header { display: flex; justify-content: space-between; font-weight: bold; color: #e67e22; font-size: 14px; margin-bottom: 10px; border-bottom: 1px solid #444; padding-bottom: 5px; }
    .prof-desc-full { font-size: 12px; color: #bdc3c7; line-height: 1.6; padding: 10px; background: #2a2a2a; border-radius: 4px; margin-bottom: 15px; }
    .recipe-list { margin-top: 10px; }
    .recipe-list-title { font-size: 12px; color: #7f8c8d; margin-bottom: 8px; font-weight: bold; }
    .recipe-item { background: #333; padding: 8px; margin-bottom: 5px; border-radius: 3px; font-size: 12px; cursor: pointer; transition: background 0.2s; border-left: 3px solid #e67e22; }
    .recipe-item:hover { background: #444; }
    .recipe-detail { display: none; padding: 10px; background: #222; border-top: 1px solid #444; font-size: 11px; color: #bdc3c7; margin-bottom: 5px; }
    .recipe-detail-row { display: flex; justify-content: space-between; margin-bottom: 4px; border-bottom: 1px dashed #333; padding-bottom: 3px; }

    .currency-bar { display: flex; justify-content: center; gap: 15px; margin-top: 10px; padding-top: 10px; border-top: 1px solid #444; flex-wrap: wrap; }
    .curr-item { font-size: 12px; display: flex; align-items: center; gap: 4px; }
    .tab-pane { display: none; } .tab-pane.active { display: block; }
    @keyframes fadeIn { from { opacity: 0; transform: translateY(-5px); } to { opacity: 1; transform: translateY(0); } }
    .empty-msg { text-align: center; color: #555; padding: 20px; font-style: italic; }

    /* Char Cards */
    .char-list { display: flex; flex-direction: column; gap: 8px; }
    .char-card { background: #2a2a2a; border: 1px solid #3d3d3d; border-radius: 4px; overflow: hidden; }
    .char-card.follower { border-left: 3px solid #9b59b6; } .char-card.npc { border-left: 3px solid #3498db; }
    .char-card-main { padding: 10px; cursor: pointer; transition: all 0.2s; } .char-card-main:hover { background: #333; }
    .char-card-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 6px; }
    .char-card-name { font-weight: bold; font-size: 13px; color: var(--primary-color); display: flex; align-items: center; gap: 6px; }
    .char-card-badges { display: flex; gap: 4px; }
    .char-type-badge { font-size: 9px; padding: 2px 5px; border-radius: 3px; font-weight: bold; }
    .char-type-badge.follower { background: #9b59b6; color: white; } .char-type-badge.npc { background: #3498db; color: white; }
    .char-card-info { display: grid; grid-template-columns: 1fr 1fr; gap: 4px; font-size: 11px; color: #95a5a6; }
    .char-card-info span { display: flex; align-items: center; gap: 4px; }
    .affection-bar { width: 60px; height: 4px; background: #444; border-radius: 2px; overflow: hidden; display: inline-block; vertical-align: middle; margin-left: 5px; }
    .affection-fill { height: 100%; background: linear-gradient(90deg, #e74c3c, #f39c12, #2ecc71); border-radius: 2px; transition: width 0.3s; }
    .char-card-detail { display: none; background: #1f1f1f; border-top: 1px solid #333; animation: fadeIn 0.2s ease; }
    .char-detail-tabs { display: flex; border-bottom: 1px solid #333; background: #252525; flex-wrap: wrap; }
    .char-detail-tab { padding: 8px 12px; font-size: 11px; color: #7f8c8d; cursor: pointer; border-bottom: 2px solid transparent; transition: all 0.2s; }
    .char-detail-tab:hover { color: #bdc3c7; background: #2a2a2a; }
    .char-detail-tab.active { color: var(--primary-color); border-bottom-color: var(--primary-color); }
    .char-detail-content { padding: 10px; max-height: 400px; overflow-y: auto; }
    .char-detail-pane { display: none; } .char-detail-pane.active { display: block; }
    .char-info-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 8px; font-size: 11px; }
    .char-info-row { display: flex; justify-content: space-between; padding: 4px 8px; background: #2a2a2a; border-radius: 3px; }
    .char-info-label { color: #7f8c8d; } .char-info-value { color: #ecf0f1; }
    .char-intro { padding: 10px; background: #2a2a2a; border-radius: 4px; font-size: 12px; color: #bdc3c7; line-height: 1.6; white-space: pre-wrap; }
    .char-attr-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 6px; margin-bottom: 10px; }
    .char-attr-box { background: #2a2a2a; padding: 6px; border-radius: 3px; text-align: center; border: 1px solid #333; }
    .char-attr-label { font-size: 10px; color: #7f8c8d; } .char-attr-value { font-size: 14px; font-weight: bold; color: var(--primary-color); }
    .char-equip-list { display: flex; flex-direction: column; gap: 6px; }
    .char-inv-grid { display: grid; grid-template-columns: repeat(2, 1fr); gap: 6px; }
    .char-inv-item-wrapper { display: flex; flex-direction: column; width: 100%; margin-bottom: 2px; }
