      .sidebar .nav-btn, .sidebar .profile-card, .sidebar .nav-divider { display: none; }
      .profile-card { display: flex !important; flex-direction: column !important; align-items: center !important; text-align: center !important; padding: 10px !important; background: #252525 !important; border: 1px solid #444 !important; margin-bottom: 10px !important; gap: 5px !important; width: 100%; order: -1; }
