      .sidebar { display: flex; flex-direction: row; flex-wrap: wrap; gap: 5px; padding: 8px; align-items: center; justify-content: flex-start; }
      .attr-grid { grid-template-columns: repeat(3, 1fr); }
      .derived-grid { grid-template-columns: repeat(2, 1fr); }
