      .char-info-grid, .space-detail-grid, .inv-detail-grid, .ability-detail-grid { grid-template-columns: 1fr; }
      .resource-row { grid-template-columns: 1fr; gap: 8px; }
      .currency-bar { gap: 8px; justify-content: space-between; }
      .curr-item { font-size: 10px; width: 48%; }
      .item-detail-panel, .ability-detail, .char-card-detail, .space-card-detail, .faction-card-detail { position: relative; left: auto; right: auto; bottom: auto; top: auto; border: none; box-shadow: none; border-top: 1px solid #444; width: 100% !important; }
      .faction-card-info { flex-direction: column; gap: 5px; }
      .team-sub-row { grid-template-columns: 1fr; }
      .toggle-dashboard-btn { width: 40px; height: 40px; font-size: 18px; bottom: 10px; right: 10px; }
    }
  </style>
  <script type="module">
    const pageStates = {
      skills: 1, talents: 1, buffs: 1, titles: 1, records: 1,
      team: 1, chars: 1, factions: 1, inv: 1, quests: 1, recipes: 1, subProf: 1
    };
    const itemsPerPage = 10;
    let charFilterState = 'all';


    const getQualityClass = (q) => {
      if(!q) return 'q-white';
      const qStr = String(q);
      if(qStr.includes('Bất Hủ') || qStr.includes('Khởi Nguyên') || qStr.includes('Vĩnh Hằng') || qStr.includes('Nguyên Sơ')) return 'q-void';
      if(qStr.includes('Truyền Thuyết')) return 'q-legend';
      if(qStr.includes('Sử Thi')) return 'q-epic';
      if(qStr.includes('Thánh Linh') || qStr.includes('Thần Thánh')) return 'q-holy';
      if(qStr.includes('Ám Kim')) return 'q-d-gold';
      if(qStr.includes('Đạm Kim')) return 'q-l-gold';
      if(qStr.includes('Vàng') || qStr.includes('Kim')) return 'q-gold';
      if(qStr.includes('Ám Tử') || qStr.includes('Ám Tím') || qStr.includes('Huyền Thoại')) return 'q-d-purple';
      if(qStr.includes('Tím') || qStr.includes('Tử')) return 'q-purple';
      if(qStr.includes('Lam') || qStr.includes('Xanh') || qStr.includes('Tinh Anh')) return 'q-blue';
      if(qStr.includes('Lục') || qStr.includes('Xanh Lá')) return 'q-green'; 
      return 'q-white';
    };

    const getRankClass = (rank) => {
      if(!rank) return '';
      const r = String(rank).toUpperCase();
      if(r.includes('UR') || r.includes('QUY TẮC')) return 'g-ur';
      if(r.includes('SR')) return 'g-sr';
      if(r.includes('SSS')) return 'g-sss';
      if(r.includes('SS')) return 'g-ss';
      if(r.includes('S')) return 'g-s';
      if(r.includes('A')) return 'g-a';
      if(r.includes('B')) return 'g-b';
      if(r.includes('C')) return 'g-c';
      if(r.includes('D')) return 'g-d';
      if(r.includes('E')) return 'g-e';
      return 'g-f';
    };

    const renderAbility = (item, type) => {
      const name = item['Tên'] || 'Chưa Đặt Tên';
      let level = '';
      const val = item['Cấp Độ'];
      if (val !== undefined && val !== null && val !== '') level = `Lv.${val}`;
      else if (item['Số Tầng Cộng Dồn']) level = `x${item['Số Tầng Cộng Dồn']}`;

      const rank = item['Phẩm Cấp'] || item['Rank'] || '';
      const rankClass = getRankClass(rank);

      let effectHtml = '';
      const effectData = item['Hiệu Quả']; // Zod variable
      const desc = item['Mô Tả'] || '';

      if (typeof effectData === 'object' && effectData !== null && !Array.isArray(effectData)) {
          let subItemsHtml = '';
          Object.entries(effectData).forEach(([k, v]) => {
             subItemsHtml += `
               <div class="ability-sub-item-wrapper">
                 <div class="ability-sub-item" onclick="event.stopPropagation(); $(this).next().slideToggle(150);">
                   <span class="ability-sub-name">🔹 ${k}</span>
                   <span class="ability-sub-toggle">▼</span>
                 </div>
                 <div class="ability-sub-detail">${v}</div>
               </div>
             `;
          });
          effectHtml = `<div class="ability-sub-list" style="margin-bottom:8px; padding-bottom:8px; border-bottom:1px dashed #444;">${subItemsHtml}</div>`;
      } else if (effectData) {
          effectHtml = `<div class="ability-desc" style="margin-bottom:5px; color:#e0e0e0;">${effectData}</div>`;
      }

      const excludeKeys = ['Tên', 'Phẩm Cấp', 'Rank', 'Hiệu Quả', 'Mô Tả', 'Cấp Độ'];
      const detailRows = [];
      Object.entries(item).forEach(([key, value]) => {
        if(excludeKeys.includes(key)) return;
        if(value === null || value === undefined || value === '') return;
        if(typeof value === 'object') { detailRows.push({ key, value: JSON.stringify(value), full: true }); } 
        else { detailRows.push({ key, value: String(value), full: false }); }
      });

      let detailHtml = detailRows.length > 0 ? detailRows.map(row => `
        <div class="ability-detail-row ${row.full ? 'full' : ''}">
          <span class="ability-detail-label">${row.key}</span>
          <span class="ability-detail-value">${row.value}</span>
        </div>
      `).join('') : '<div class="ability-detail-row full"><span class="ability-detail-value" style="color:#7f8c8d;">Tạm không có thêm thông tin</span></div>';

      return `
        <div class="ability-item ${type}">
          <div class="ability-main">
            <div class="ability-header">
              <span class="${rankClass}" style="${rankClass === 'g-f' ? 'color:#ecf0f1' : ''}">${name}</span>
              <span>
                <span style="font-size:11px; color:#95a5a6; background:#222; padding:1px 5px; border-radius:3px;">${level}</span>
                <span class="ability-toggle">▼ Chi tiết</span>
              </span>
            </div>
            ${desc ? `<div class="ability-desc" style="font-style:italic; opacity:0.8;">${desc}</div>` : ''}
          </div>
          <div class="ability-detail">
            ${effectHtml}
            <div class="ability-detail-grid">${detailHtml}</div>
          </div>
        </div>
      `;
    };

    const renderPagination = (idPrefix, currentPage, totalPages) => {
      if (totalPages <= 1) return '';
      return `<div class="pagination-bar" id="pag-${idPrefix}"><button class="page-btn" id="btn-prev-${idPrefix}" ${currentPage <= 1 ? 'disabled' : ''}>◀ Trước</button><span class="page-info" id="info-${idPrefix}">${currentPage} / ${totalPages}</span><button class="page-btn" id="btn-next-${idPrefix}" ${currentPage >= totalPages ? 'disabled' : ''}>Sau ▶</button></div>`;
    };

    const renderSubProfPagination = (idPrefix, currentPage, totalPages) => {
      if (totalPages <= 1) return '';
      return `<div class="subprof-pagination-container" id="pag-${idPrefix}"><button class="page-btn" id="btn-prev-${idPrefix}" ${currentPage <= 1 ? 'disabled' : ''} style="margin-right:5px;">◀</button><span class="page-info" id="info-${idPrefix}" style="margin-right:5px;line-height:24px;">${currentPage} / ${totalPages}</span><button class="page-btn" id="btn-next-${idPrefix}" ${currentPage >= totalPages ? 'disabled' : ''}>▶</button></div>`;
    };

    const renderRecipeItem = (id, recipe) => {
      const name = recipe['Tên'] || 'Công thức chưa biết';
      const excludeKeys = ['Tên'];
      let detailsHtml = '';
      Object.entries(recipe).forEach(([key, val]) => {
          if(excludeKeys.includes(key)) return;
          if(val === null || val === undefined) return;
          let displayVal = typeof val === 'object' ? JSON.stringify(val) : val;
          detailsHtml += `<div class="recipe-detail-row"><span style="color:#7f8c8d;">${key}</span><span style="color:#ecf0f1;">${displayVal}</span></div>`;
      });
      if(!detailsHtml) detailsHtml = '<div style="color:#7f8c8d; font-style:italic;">Tạm không có thông tin chi tiết</div>';
      return `<div class="recipe-item-wrapper"><div class="recipe-item">📜 ${name}</div><div class="recipe-detail">${detailsHtml}</div></div>`;
    };

    const renderEquipDetailContent = (item, qClass) => {
      let affixesHtml = '';
      const affixes = item['Từ Tố'] || [];
      if (Array.isArray(affixes) && affixes.length > 0) {
        affixesHtml = affixes.map(affix => {
          let name = 'Từ tố', desc = '';
          if (typeof affix === 'string') { const p = affix.split(/[:：]/); name = p[0]; desc = p.slice(1).join(':'); }
          else { name = affix['Tên'] || 'Từ tố'; desc = affix['Hiệu Quả'] || affix['Mô Tả'] || ''; }
          return `<div class="affix-item-wrapper"><div class="affix-item"><span class="affix-name">${name}</span><span class="affix-toggle">▼</span></div><div class="affix-detail">${desc}</div></div>`;
        }).join('');
        affixesHtml = `<div class="affix-section"><div class="affix-title">✦ Từ Tố Trang Bị</div><div class="affix-list">${affixesHtml}</div></div>`;
      }

      let gemsHtml = '';
      const gems = item['Ngọc'] || [];
      if (Array.isArray(gems) && gems.length > 0) {
        gemsHtml = gems.map(gem => {
          let name = 'Ngọc', desc = '';
           if (typeof gem === 'string') { const p = gem.split(/[:：]/); name = p[0]; desc = p.slice(1).join(':'); }
           else { name = gem['Tên'] || 'Ngọc'; desc = gem['Hiệu Quả'] || gem['Mô Tả'] || ''; }
           return `<div class="gem-item-wrapper"><div class="gem-item"><span class="gem-name">${name}</span><span class="gem-toggle">▼</span></div><div class="affix-detail">${desc}</div></div>`;
        }).join('');
        gemsHtml = `<div class="gem-section"><div class="gem-title">💎 Khảm Nạm</div><div class="gem-list">${gemsHtml}</div></div>`;
      }

      return `
        <div class="detail-header"><span class="${qClass}">${item['Tên']}</span><span style="color:#f1c40f">Điểm: ${item['Điểm Đánh Giá'] || 0}</span></div>
        <div class="detail-stats">
          ${item['Tấn Công'] ? `<div>⚔️ ATK: ${item['Tấn Công']}</div>` : ''}
          ${item['Phòng Ngự'] ? `<div>🛡️ DEF: ${item['Phòng Ngự']}</div>` : ''}
          ${item['Loại'] ? `<div>🏷️ Loại: ${item['Loại']}</div>` : ''}
          ${item['Chất Lượng'] ? `<div>💎 Phẩm: ${item['Chất Lượng']}</div>` : ''}
        </div>
        ${item['Hiệu Ứng Đặc Biệt'] ? `<div style="margin-top:5px; font-size:11px; color:#3498db;">✨ Hiệu ứng: ${item['Hiệu Ứng Đặc Biệt']}</div>` : ''}
        <div class="detail-desc">${item['Mô Tả'] || 'Không có mô tả'}</div>
        ${affixesHtml}
        ${gemsHtml}
      `;
    };

    const renderCharEquip = (slotName, item) => {
      if(!item || !item['Tên'] || item['Tên'] === 'Chưa Trang Bị') return `<div class="char-equip-item-wrapper"><div class="char-equip-item" data-has="false"><span class="char-equip-slot">${slotName}</span><span class="char-equip-name q-white">Chưa Trang Bị</span></div></div>`;
      const qClass = getQualityClass(item['Chất Lượng']);
      const detailContent = renderEquipDetailContent(item, qClass);
      return `<div class="char-equip-item-wrapper"><div class="char-equip-item" data-has="true"><span class="char-equip-slot">${slotName}</span><span class="char-equip-name ${qClass}">${item['Tên']}</span><span class="char-equip-quality">${item['Chất Lượng'] || ''}</span></div><div class="item-detail-panel">${detailContent}</div></div>`;
    };

    const renderCharCard = (id, char) => {
      const count = char['Số Lượng'] || 1, name = char['Tên'] || 'Chưa biết', location = char['Vị Trí'] || 'Chưa biết';
      const status = char['Trạng Thái'] || 'Bình thường', affection = char['Độ Hảo Cảm'] || 0, isAbsent = char['Đã Rời Đi Chưa'] === 'Có';
      const tier = char['Vị Giai'] || 'Chưa biết', level = char['Cấp Độ'] || 0, identity = char['Thân Phận'] || 'Chưa biết';
      const job = char['Nghề Nghiệp'] || 'Chưa xác định', race = char['Chủng Tộc'] || 'Chưa xác định', stance = char['Lập Trường'] || 'Trung Lập';
      const faction = char['Thế Lực Trực Thuộc'] || char['Thế Lực'] || 'Không', personality = char['Tính Cách'] || 'Chưa biết', hobby = char['Sở Thích'] || 'Không';
      const rawStage = char['Giai Đoạn Hiện Tại'] || '', appearance = char['Mô Tả Ngoại Hình'] || 'Tạm không có mô tả', intro = char['Giới Thiệu'] || char['Giới Thiệu Nhân Vật'] || 'Tạm không có giới thiệu';
      const innerThought = char['Suy Nghĩ Nội Tâm'] || '', charType = char['Loại Nhân Vật'] || char['Loại'] || 'NPC';
      const isFollower = charType === 'Tùy Tùng', affectionPct = Math.min(100, Math.max(0, (affection + 100) / 2));

      let badgeText = char['Vị Giai'] || char['Boss'] || 'T0_Bình Thường';
      let displayStage = '';
      if (rawStage) {
          const isRankKeyword = /T\d|Giai|Boss|Bá Chủ|Chí Cao|Lĩnh Chủ|Đầu Mục|Tinh Anh|Tứ|Ngũ|Lục|Thất|Bát|Cửu|Trưởng Thành|Ấu Thể|Sơ Sinh|Thành Thục|Hoàn Chỉnh|Non Nớt/.test(rawStage);
          const isMoodKeyword = /Hoảng|Sợ|Vui|Buồn|Giận|Ngơ|Bám|Hứng|Hờn|Loạn|Khinh|Nộ|Khủng|Tức|Cảm|Bất|Ngu|Ngốc/.test(rawStage);
          const isJustNumber = /^\d+$/.test(rawStage); 
          if ((isRankKeyword || isJustNumber || rawStage.length < 10) && !isMoodKeyword) badgeText = rawStage; else displayStage = rawStage;
      }

      let tierClass = 'tier-t0';
      const txt = (String(badgeText) + " " + String(tier)).toLowerCase();
      const hasNum = (n) => new RegExp(`(?:^|\\D)${n}(?:$|\\D)`).test(txt);

      if (txt.includes('t9') || txt.includes('cổ thần') || txt.includes('nguyên sơ')) tierClass = 'tier-t9';
      else if (txt.includes('t8') || txt.includes('chân thần') || hasNum(8)) tierClass = 'tier-t8';
      else if (txt.includes('t7') || txt.includes('bán thần') || txt.includes('chí cao') || hasNum(7) || hasNum(9)) tierClass = 'tier-t7';
      else if (txt.includes('t6') || txt.includes('vương giả') || hasNum(6)) tierClass = 'tier-t6';
      else if (txt.includes('t5') || txt.includes('thế giới') || txt.includes('lãnh chúa') || hasNum(5)) tierClass = 'tier-t5';
      else if (txt.includes('t4') || txt.includes('bá chủ') || txt.includes('anh hùng') || hasNum(4)) tierClass = 'tier-t4';
      else if (txt.includes('t3') || txt.includes('dũng sĩ') || hasNum(3)) tierClass = 'tier-t3';
      else if (txt.includes('t2') || txt.includes('tinh anh') || hasNum(2)) tierClass = 'tier-t2';
      else if (txt.includes('t1') || txt.includes('binh tốt') || hasNum(1)) tierClass = 'tier-t1';

      const sixDim = char['Thuộc Tính Cơ Bản'] || {}, derived = char['Thuộc Tính Dẫn Xuất'] || {};
      const hpCur = char.HP_Cur || 0, hpMax = char.HP_Max || 0, epCur = char.EP_Cur || 0, epMax = char.EP_Max || 0;
      const equipSource = { ...(char['Giáp'] || {}), ...(char['Vũ Khí Và Trang Bị'] || {}), ...(char['Trang Bị'] || {}) };
      const mainWeapon = char['Vũ Khí Tay Chính'] || equipSource['Vũ Khí Tay Chính'] || equipSource['Vũ Khí Chính'] || {};
      const subWeapon = char['Vũ Khí Tay Phụ'] || equipSource['Vũ Khí Tay Phụ'] || equipSource['Vũ Khí Phụ'] || {};
      const armor = equipSource;

      const safeRenderList = (data, type) => {
        if (!data || typeof data !== 'object') return '';
        const keys = Object.keys(data);
        if (keys.length === 0) return '';
        return Object.values(data).map(item => renderAbility(item, type)).join('');
      };

      let skillsHtml = safeRenderList(char['Kỹ Năng'], 'skill') || '<div class="empty-msg" style="padding:10px;font-size:11px;">Tạm không có kỹ năng</div>';
      let talentsHtml = safeRenderList(char['Thiên Phú'], 'talent') || '<div class="empty-msg" style="padding:10px;font-size:11px;">Tạm không có thiên phú</div>';
      let buffsHtml = safeRenderList((char['Đặc Tính Buff'] || char['Buff'] || char['Đặc Tính']), 'buff') || '<div class="empty-msg" style="padding:10px;font-size:11px;">Tạm không có Đặc tính/Buff</div>';

      let equipHtml = renderCharEquip('Tay Chính', mainWeapon) + renderCharEquip('Tay Phụ', subWeapon);
      ['Đầu','Áo','Quần','Tay','Vai','Giày','Nhẫn 1','Nhẫn 2','Dây Chuyền','Thắt Lưng','Trang Sức Phụ'].forEach(slot => { equipHtml += renderCharEquip(slot, armor[slot] || {}); });

      let invHtml = Object.keys(char['Túi Đồ'] || {}).length > 0 ? Object.values(char['Túi Đồ']).map(item => {
        const iName = item['Tên'] || 'Vật phẩm chưa biết', iQty = item['Số Lượng'] || 1, qClass = getQualityClass(item['Chất Lượng']);
        let details = '';
        Object.entries(item).forEach(([k, v]) => { if(!['Tên', 'Số Lượng'].includes(k) && v) details += `<div class="char-inv-detail-row"><span class="char-inv-detail-label">${k}</span><span class="char-inv-detail-value">${typeof v==='object'?JSON.stringify(v):v}</span></div>`; });
        return `<div class="char-inv-item-wrapper"><div class="char-inv-item"><span class="char-inv-name ${qClass}">${iName}</span><span class="char-inv-qty">x${iQty}</span><span style="font-size:9px;color:#555;margin-left:auto;">▼</span></div><div class="char-inv-item-detail">${details||'<div style="color:#555;font-style:italic;">Không có thông tin chi tiết</div>'}</div></div>`;
      }).join('') : '<div class="empty-msg" style="padding:10px;font-size:11px;">Tạm không có vật phẩm</div>';

      const gender = char['Giới Tính'] || 'Chưa Rõ', isFemale = gender.includes('Nữ') || gender.toLowerCase().includes('female');
      let sexLifeHtml = '';
      if(isFemale) {
          const sl = char['Đời Sống Tình Dục'] || {}, parts = sl['Phát Triển Cơ Thể'] || {}, kinks = sl['Sở Thích Tình Dục'] || {};
          sexLifeHtml += `<div class="char-info-grid" style="margin-bottom:10px;"><div class="char-info-row"><span class="char-info-label">Độ Sa Ngã</span><span class="char-info-value" style="color:#e74c3c;">${sl['Độ Sa Ngã'] || '0'}</span></div><div class="char-info-row"><span class="char-info-label">Cúp Ngực</span><span class="char-info-value">${sl['Cúp Ngực'] || '?'}</span></div><div class="char-info-row full"><span class="char-info-label">Tư Thế Ưa Thích</span><span class="char-info-value">${sl['Tư Thế Ưa Thích'] || 'Không'}</span></div><div class="char-info-row full"><span class="char-info-label">Dâm Văn</span><span class="char-info-value" style="color:#9b59b6;">${sl['Dâm Văn'] || 'Không'}</span></div></div><div style="margin-bottom:10px;padding:8px;background:#2a2a2a;border-radius:3px;font-size:11px;"><span style="color:#7f8c8d;">💬 Đánh Giá:</span><span style="color:#bdc3c7;">${sl['Đánh Giá Chung'] || 'Chưa có đánh giá'}</span></div><div class="char-ability-list"><div style="font-size:11px;color:#e67e22;margin:5px 0;">💋 Khai Phá Cơ Thể</div>`;
          Object.entries(parts).forEach(([part, status]) => { sexLifeHtml += `<div class="ability-item buff"><div class="ability-main char-ability-main"><div class="ability-header"><span style="color:#ecf0f1">${part}</span><span class="ability-toggle">▼ Chi tiết</span></div></div><div class="ability-detail"><div class="ability-detail-desc">${typeof status === 'object' ? JSON.stringify(status) : status}</div></div></div>`; });
          sexLifeHtml += '<div style="font-size:11px;color:#9b59b6;margin:10px 0 5px 0;">⛓️ Sở Thích / Fetish</div>';
          if (Object.keys(kinks).length > 0) { Object.entries(kinks).forEach(([k, v]) => { sexLifeHtml += `<div class="ability-item talent"><div class="ability-main char-ability-main"><div class="ability-header"><span style="color:#ecf0f1">${k}</span><span class="ability-toggle">▼ Chi tiết</span></div></div><div class="ability-detail"><div class="ability-detail-desc">${v}</div></div></div>`; }); } else { sexLifeHtml += '<div class="empty-msg" style="padding:5px;">Chưa thức tỉnh sở thích</div>'; }
          sexLifeHtml += '</div>';
      }

      return `
        <div class="char-card ${isFollower ? 'follower' : 'npc'}" data-id="${id}" data-absent="${isAbsent}" data-type="${charType}">
          <div class="char-card-main">
            <div class="char-card-header">
              <span class="char-card-name">${name}${count > 1 ? `<span style="font-size:12px;color:#f39c12;margin-left:5px;">x${count}</span>` : ''}<span class="tier-badge ${tierClass}">${badgeText}</span></span>
              <div class="char-card-badges"><span class="char-type-badge ${isFollower ? 'follower' : 'npc'}">${isFollower ? 'Tùy Tùng' : 'NPC'}</span></div>
            </div>
            <div class="char-card-info">
              ${displayStage ? `<span style="grid-column: 1 / -1; color: #f39c12; font-weight: bold; border-bottom:1px dashed #444; margin-bottom:4px; padding-bottom:2px;">💭 ${displayStage}</span>` : ''}
              <span>📍 ${location}</span><span>💫 ${status}</span><span>⚔️ ${tier} Lv.${level}</span><span>❤️ ${affection}<span class="affection-bar"><span class="affection-fill" style="width:${affectionPct}%"></span></span></span>
            </div>
          </div>
          <div class="char-card-detail">
            <div class="char-detail-tabs">
              <div class="char-detail-tab active" data-pane="info">📋 Cơ Bản</div><div class="char-detail-tab" data-pane="attrs">📊 Thuộc Tính</div><div class="char-detail-tab" data-pane="equip">🗡️ Trang Bị</div><div class="char-detail-tab" data-pane="skills">⚡ Kỹ Năng</div><div class="char-detail-tab" data-pane="talents">🌟 Thiên Phú</div><div class="char-detail-tab" data-pane="buffs">✨ Buff</div><div class="char-detail-tab" data-pane="inv">🎒 Vật Phẩm</div>${isFemale ? `<div class="char-detail-tab" data-pane="sex" style="color:#e74c3c;">❤ 18+</div>` : ''}
            </div>
            <div class="char-detail-content">
              <div class="char-detail-pane active" data-pane="info">
                <div class="char-info-grid">
                  <div class="char-info-row"><span class="char-info-label">Chủng Tộc</span><span class="char-info-value">${race}</span></div><div class="char-info-row"><span class="char-info-label">Nghề Nghiệp</span><span class="char-info-value">${job}</span></div><div class="char-info-row"><span class="char-info-label">Loại</span><span class="char-info-value">${charType}</span></div><div class="char-info-row"><span class="char-info-label">Thân Phận</span><span class="char-info-value">${identity}</span></div><div class="char-info-row"><span class="char-info-label">Thế Lực</span><span class="char-info-value">${faction}</span></div><div class="char-info-row"><span class="char-info-label">Lập Trường</span><span class="char-info-value">${stance}</span></div><div class="char-info-row"><span class="char-info-label">Tính Cách</span><span class="char-info-value">${personality}</span></div><div class="char-info-row"><span class="char-info-label">Sở Thích</span><span class="char-info-value">${hobby}</span></div><div class="char-info-row"><span class="char-info-label">Độ Hảo Cảm</span><span class="char-info-value">${affection}</span></div>
                </div>
                ${innerThought ? `<div style="margin-top:10px;padding:8px;background:#2a2a2a;border-radius:4px;font-size:11px;"><span style="color:#7f8c8d;">💭 Nội Tâm:</span><span style="color:#bdc3c7;">${innerThought}</span></div>` : ''}
                <div style="margin-top:10px;"><div style="font-size:11px;color:#7f8c8d;margin-bottom:5px;">👁️ Mô Tả Ngoại Hình</div><div class="char-intro">${appearance}</div></div>
                <div style="margin-top:10px;"><div style="font-size:11px;color:#7f8c8d;margin-bottom:5px;">📖 Giới Thiệu Nhân Vật</div><div class="char-intro">${intro}</div></div>
              </div>
              <div class="char-detail-pane" data-pane="attrs">
                <div class="char-attr-grid">
                  <div class="char-attr-box"><div class="char-attr-label">Sức Mạnh</div><div class="char-attr-value">${sixDim['Sức Mạnh'] || 0}</div></div><div class="char-attr-box"><div class="char-attr-label">Nhanh Nhẹn</div><div class="char-attr-value">${sixDim['Nhanh Nhẹn'] || 0}</div></div><div class="char-attr-box"><div class="char-attr-label">Thể Chất</div><div class="char-attr-value">${sixDim['Thể Chất'] || 0}</div></div><div class="char-attr-box"><div class="char-attr-label">Trí Tuệ</div><div class="char-attr-value">${sixDim['Trí Tuệ'] || 0}</div></div><div class="char-attr-box"><div class="char-attr-label">Mị Lực</div><div class="char-attr-value">${sixDim['Mị Lực'] || 0}</div></div><div class="char-attr-box"><div class="char-attr-label">May Mắn</div><div class="char-attr-value">${sixDim['May Mắn'] || 0}</div></div>
                </div>
                <div style="display:grid;grid-template-columns:1fr;gap:8px;">
                  <div class="char-info-row"><span class="char-info-label">HP</span><span class="char-info-value">${hpCur}/${hpMax}</span></div><div class="char-info-row"><span class="char-info-label">EP</span><span class="char-info-value">${epCur}/${epMax}</span></div><div class="char-info-row"><span class="char-info-label">Vật Lý ATK</span><span class="char-info-value">${derived['Vật Lý ATK'] || 0}</span></div><div class="char-info-row"><span class="char-info-label">Vật Lý DEF</span><span class="char-info-value">${derived['Vật Lý DEF'] || 0}</span></div><div class="char-info-row"><span class="char-info-label">Pháp Thuật ATK</span><span class="char-info-value">${derived['Pháp Thuật ATK'] || 0}</span></div><div class="char-info-row"><span class="char-info-label">Pháp Thuật DEF</span><span class="char-info-value">${derived['Pháp Thuật DEF'] || 0}</span></div>
                </div>
              </div>
              <div class="char-detail-pane" data-pane="equip"><div class="char-equip-list">${equipHtml}</div></div>
              <div class="char-detail-pane" data-pane="skills"><div class="char-ability-list">${skillsHtml}</div></div>
              <div class="char-detail-pane" data-pane="talents"><div class="char-ability-list">${talentsHtml}</div></div>
              <div class="char-detail-pane" data-pane="buffs"><div class="char-ability-list">${buffsHtml}</div></div>
              <div class="char-detail-pane" data-pane="inv"><div class="char-inv-grid">${invHtml}</div></div>
              ${isFemale ? `<div class="char-detail-pane" data-pane="sex">${sexLifeHtml}</div>` : ''}
            </div>
          </div>
        </div>
      `;
    };

    const renderInventoryItem = (id, item) => {
      let realName = $('#p-name').text().trim();
      if (!realName || realName === '--') realName = 'Bạn'; 
      const name = item['Tên'] || 'Vật phẩm chưa biết', qty = item['Số Lượng'] || 1, qClass = getQualityClass(item['Chất Lượng']); 
      const detailRows = [];
      const processText = (val) => String(val || '').replace(/\{\{\s*user\s*\}\}/gi, realName);

      Object.entries(item).forEach(([key, value]) => {
        if(['Tên', 'Số Lượng'].includes(key)) return;
        if(value === null || value === undefined || value === '') return;
        if(typeof value === 'object') { detailRows.push({ key, value: processText(JSON.stringify(value)), full: true }); }
        else { detailRows.push({ key, value: processText(value), full: false }); }
      });

      let detailHtml = detailRows.length > 0 ? detailRows.map(row => `<div class="inv-detail-row ${row.full ? 'full' : ''}"><span class="inv-detail-label">${row.key}</span><span class="inv-detail-value">${row.value}</span></div>`).join('') : '<div class="inv-detail-row full"><span class="inv-detail-value" style="color:#7f8c8d;">Tạm không có thêm thông tin</span></div>';
      return `<div class="inv-item-card" data-id="${id}"><div class="inv-item-main"><div class="inv-item-left"><span class="inv-item-name ${qClass}">${name}</span><span class="inv-item-qty">x${qty}</span></div><span class="inv-item-toggle">▼ Chi tiết</span></div><div class="inv-item-detail"><div class="inv-detail-grid">${detailHtml}</div></div></div>`;
    };

    const renderFactionCard = (id, faction) => {
      if (faction['Liên Quan Cốt Truyện'] === 'Không') return '';
      const name = faction['Tên'] || 'Thế lực chưa biết', relation = faction['Quan Hệ'] || 'Trung Lập';
      const relationValue = faction['Giá Trị Danh Vọng'] || faction['Giá Trị Quan Hệ'] || 50;
      const intro = faction['Giới Thiệu'] || faction['Mô Tả'] || 'Tạm không có giới thiệu', attitude = faction['Thái Độ Với Kẻ Giao Ước'] || 'Không rõ', resource = faction['Tài Nguyên Đặc Sắc'] || 'Không rõ';
      const leader = faction['Lãnh Tụ'] || 'Chưa xác định', members = faction['Thành Viên Quan Trọng'] || {};
      const isRelevant = faction['Liên Quan Cốt Truyện'] === 'Có';

      const baseLocObj = faction['Căn Cứ Địa']; let baseLocDisplay = 'Chưa xác định';
      if (baseLocObj && typeof baseLocObj === 'object') {
          if (!baseLocObj['Tên'] && !baseLocObj['Thế Giới Sở Tại']) baseLocDisplay = 'Tạm chưa có thông tin';
          else { const bName = baseLocObj['Tên'] || 'Vị trí ẩn', bWorld = baseLocObj['Thế Giới Sở Tại'] ? ` - ${baseLocObj['Thế Giới Sở Tại']}` : '', bCoord = baseLocObj['Mô Tả Tọa Độ'] ? ` [${baseLocObj['Mô Tả Tọa Độ']}]` : ''; baseLocDisplay = `${bName}${bWorld}${bCoord}`; }
      } else if (typeof baseLocObj === 'string') baseLocDisplay = baseLocObj;

      let relationClass = 'neutral'; if(relationValue >= 70) relationClass = 'friendly'; else if(relationValue <= 30) relationClass = 'hostile';
      let membersHtml = Object.keys(members).length > 0 ? Object.entries(members).map(([mName, mDesc]) => `<div class="faction-member-item-wrapper"><div class="faction-member-item"><span class="faction-member-name">${mName}</span><span class="faction-member-role" style="font-size:9px;">Chi tiết▼</span></div><div class="faction-member-detail">${mDesc || 'Chưa có thông tin'}</div></div>`).join('') : '<div class="empty-msg" style="padding:5px;font-size:11px;">Tạm không có ghi chép</div>';

      const excludeKeys = ['UID', 'Tên', 'Quan Hệ', 'Giá Trị Danh Vọng', 'Giá Trị Quan Hệ', 'Giới Thiệu', 'Mô Tả', 'Căn Cứ Địa', 'Mục Thành Viên Quan Trọng', 'Thành Viên Quan Trọng', 'Lãnh Tụ', 'Thái Độ Với Kẻ Giao Ước', 'Tài Nguyên Đặc Sắc', 'Liên Quan Cốt Truyện'];
      let otherFieldsHtml = '';
      Object.entries(faction).forEach(([key, value]) => { if(excludeKeys.includes(key)) return; if(value === null || value === undefined || value === '') return; let displayValue = value; if(Array.isArray(value)) displayValue = value.join(', '); else if(typeof value === 'object') displayValue = JSON.stringify(value); otherFieldsHtml += `<div class="faction-detail-section"><div class="faction-detail-title">${key}</div><div class="faction-detail-content">${displayValue}</div></div>`; });

      return `
