      `;
    };

    const renderQuestCard = (id, quest) => {
      const type = quest.type || 'side', name = quest.name, desc = quest.desc, progress = quest.prog, hint = quest.hint;
      if(!name || name === 'Không' || name === '') return '';
      const typeLabels = { main: 'Chính', side: 'Phụ', hidden: 'Ẩn' };
      return `<div class="quest-card ${type}"><div class="quest-header"><div class="quest-title-row"><span class="quest-type-badge ${type}">${typeLabels[type]}</span><span class="quest-name">${name}</span></div><span class="quest-toggle">▼ Chi tiết</span></div><div class="quest-detail"><div class="quest-info-row"><span class="quest-info-label">📜 Mô Tả</span><span class="quest-info-value">${desc || 'Tạm không có mô tả'}</span></div><div class="quest-info-row"><span class="quest-info-label">📊 Tiến Độ</span><span class="quest-info-value">${progress || 'Đang tiến hành'}</span></div>${hint ? `<div class="quest-hint"><div class="quest-hint-label">💡 Gợi ý</div><div class="quest-hint-text">${hint}</div></div>` : ''}</div></div>`;
    };

    const renderTitleCard = (id, title) => {
      const name = title['Tên'] || 'Danh hiệu chưa biết', isEquipped = (title['Có Trang Bị Không'] === 'Có') || (title['Có Trang Bị'] === 'Có');
      const rank = title['Phẩm Cấp'] || title['Rank'] || '', rankClass = getRankClass(rank), excludeKeys = ['Tên', 'Có Trang Bị', 'Có Trang Bị Không', 'Phẩm Cấp', 'Rank'];
      const detailRows = [];
      Object.entries(title).forEach(([key, value]) => { if(excludeKeys.includes(key)) return; if(value === null || value === undefined || value === '') return; let displayValue = value; if(Array.isArray(value)) displayValue = value.join(', '); else if(typeof value === 'object') displayValue = JSON.stringify(value); detailRows.push({ key, value: displayValue }); });
      let detailHtml = detailRows.length > 0 ? detailRows.map(row => `<div class="title-detail-row"><span class="title-detail-label">${row.key}</span><span class="title-detail-value">${row.value}</span></div>`).join('') : '<div style="font-size:11px;color:#7f8c8d;">Tạm không có thuộc tính chi tiết</div>';
      return `<div class="title-card ${isEquipped ? 'equipped' : ''}" data-id="${id}"><div class="title-card-main"><div class="title-card-left"><span class="title-card-name ${rankClass}" style="${rankClass === 'g-f' ? 'color:#f1c40f' : ''}">${name}</span><span class="title-card-status ${isEquipped ? 'active' : ''}">${isEquipped ? '✅ Đã Đeo' : 'Chưa Đeo'}</span></div><span class="title-card-toggle">▼ Chi tiết</span></div><div class="title-card-detail">${detailHtml}</div></div>`;
    };

    const renderTeamItem = (id, item, type) => {
       const name = item['Tên'] || 'Chưa biết';
       if (type === 'skill' || type === 'buff') return renderAbility(item, type);
       if (type === 'item') return renderInventoryItem(id, item);
       let badge = '';
       if (type === 'member') badge = '<span class="space-type-badge member">Thành Viên</span>';
       else if (type === 'facility') badge = '<span class="space-type-badge facility">Cơ Sở</span>';
       let detailHtml = '';
       Object.entries(item).forEach(([k, v]) => { if (k !== 'Tên' && v) detailHtml += `<div class="space-detail-row"><span class="space-detail-label">${k}</span><span class="space-detail-value">${typeof v==='object'?JSON.stringify(v):v}</span></div>`; });
       return `<div class="space-card" data-id="${id}"><div class="space-card-main"><div class="space-card-left">${badge}<span class="space-card-name">${name}</span></div><span class="space-card-toggle">▼ Chi tiết</span></div><div class="space-card-detail"><div class="space-detail-grid">${detailHtml||'<div style="font-size:11px;color:#7f8c8d;">Tạm không có chi tiết</div>'}</div></div></div>`;
    };

    function renderPagedList(containerId, dataObj, renderFunc, pageStateKey, extraArg) {
      const $container = $(containerId); $container.empty();
      const entries = Object.entries(dataObj || {});
      const totalPages = Math.ceil(entries.length / itemsPerPage) || 1;
      if (pageStates[pageStateKey] > totalPages) pageStates[pageStateKey] = totalPages;
      if (pageStates[pageStateKey] < 1) pageStates[pageStateKey] = 1;
      const start = (pageStates[pageStateKey] - 1) * itemsPerPage;
      const pageItems = entries.slice(start, start + itemsPerPage);
      if (pageItems.length === 0) $container.html('<div class="empty-msg">Tạm không có dữ liệu</div>');
      else pageItems.forEach(([id, item]) => $container.append(renderFunc(id, item, extraArg)));
      if (totalPages > 1) {
        $container.append(renderPagination(pageStateKey, pageStates[pageStateKey], totalPages));
        $(`#btn-prev-${pageStateKey}`).off('click').on('click', function() { if (pageStates[pageStateKey] > 1) { pageStates[pageStateKey]--; render(); } });
        $(`#btn-next-${pageStateKey}`).off('click').on('click', function() { if (pageStates[pageStateKey] < totalPages) { pageStates[pageStateKey]++; render(); } });
      }
    }

    function render() {
