      if(sys['Nhiệm Vụ Phụ Hiện Tại'] && sys['Nhiệm Vụ Phụ Hiện Tại'] !== 'Không') questData['side'] = { type: 'side', name: sys['Nhiệm Vụ Phụ Hiện Tại'], desc: sys['Mô Tả Nhiệm Vụ Phụ'], prog: sys['Tiến Độ Nhiệm Vụ Phụ'], hint: sys['Gợi Ý Nhiệm Vụ Phụ'] };
