          charEntries = charEntries.filter(([,c]) => c['Loại Nhân Vật'] === 'Tùy Tùng' || c['Loại'] === 'Tùy Tùng');
      } else if (charFilterState === 'npc') {
          charEntries = charEntries.filter(([,c]) => c['Loại Nhân Vật'] !== 'Tùy Tùng' && c['Loại'] !== 'Tùy Tùng');
      }
      const charObj = Object.fromEntries(charEntries);
      renderPagedList('#char-list', charObj, renderCharCard, 'chars');
      $('.char-card-main').off('click').on('click', function() { const $detail = $(this).siblings('.char-card-detail'); $('.char-card-detail').not($detail).slideUp(150); $detail.slideToggle(200); });
      $('.dashboard-container').off('click', '.char-inv-item').on('click', '.char-inv-item', function(e) { e.stopPropagation(); $(this).next('.char-inv-item-detail').slideToggle(150); });

      $('.char-detail-tab').off('click').on('click', function(e) { e.stopPropagation(); const $tabs = $(this).parent(), $content = $tabs.siblings('.char-detail-content'), pane = $(this).data('pane'); $tabs.find('.char-detail-tab').removeClass('active'); $(this).addClass('active'); $content.find('.char-detail-pane').removeClass('active'); $content.find(`.char-detail-pane[data-pane="${pane}"]`).addClass('active'); });
      $('.char-equip-item[data-has="true"]').off('click').on('click', function() { const $detail = $(this).siblings('.item-detail-panel'); $('.item-detail-panel').not($(this).next()).slideUp(150); $(this).next('.item-detail-panel').slideToggle(150); });
      $('.dashboard-container').off('click', '.affix-item, .gem-item').on('click', '.affix-item, .gem-item', function(e) { e.stopPropagation(); $(this).siblings('.affix-detail').slideToggle(150); });

      const followerCount = charEntries.filter(([,c]) => c['Loại Nhân Vật'] === 'Tùy Tùng' || c['Loại'] === 'Tùy Tùng').length;
      $('#char-count').text(`${charEntries.length} người (Tùy Tùng:${followerCount} NPC:${charEntries.length - followerCount})`);

      renderPagedList('#inv-list', invDb, renderInventoryItem, 'inv');
      $('#inv-count').text(Object.keys(invDb).length);
      $('.inv-item-main').off('click').on('click', function() { const $detail = $(this).siblings('.inv-item-detail'); $('.inv-item-detail').not($detail).slideUp(150); $detail.slideToggle(150); });

      renderPagedList('#faction-list', factionDb, renderFactionCard, 'factions');
      $('#faction-count').text(Object.keys(factionDb).length);
      $('.faction-card-main').off('click').on('click', function() { const $detail = $(this).siblings('.faction-card-detail'); $('.faction-card-detail').not($detail).slideUp(150); $detail.slideToggle(200); });
      $('.faction-member-item').off('click').on('click', function(e) { e.stopPropagation(); $(this).next('.faction-member-detail').slideToggle(150); });

      // Xử lý click mở rộng cho các item chung (Ngoài hồ sơ nhân vật)
      $('.ability-main, .title-card-main, .space-card-main').off('click').on('click', function(e) {
        // Chỉ áp dụng cho những item không nằm trong hồ sơ nhân vật (để tránh xung đột với logic riêng)
        if($(this).closest('.char-detail-content').length === 0) {
            const $detail = $(this).siblings('.ability-detail, .title-card-detail, .space-card-detail');
            $('.ability-detail, .title-card-detail, .space-card-detail').not($detail).slideUp(150);
            $detail.slideToggle(150);
        }
      });

      // Xử lý riêng cho Skill/Talent BÊN TRONG hồ sơ nhân vật
      $('.char-detail-content .ability-main').off('click').on('click', function(e) {
          e.stopPropagation();
          const $detail = $(this).siblings('.ability-detail');
          $(this).closest('.char-ability-list').find('.ability-detail').not($detail).slideUp(150);
          $detail.slideToggle(150);
      });

      // Logic nút Thu Nhỏ/Mở Rộng Dashboard
      const $toggleBtn = $('#toggle-dashboard'); 
      const $container = $('.dashboard-container');
      const isHidden = localStorage.getItem('dashboard_minimized') === 'true';

      if(isHidden) { 
          $container.addClass('minimized'); 
          $toggleBtn.removeClass('active'); 
          $toggleBtn.text('📊'); 
      } else { 
          $toggleBtn.addClass('active'); 
          $toggleBtn.text('✕'); 
      }

      $toggleBtn.off('click').on('click', function() {
          $container.toggleClass('minimized'); 
          const isNowHidden = $container.hasClass('minimized'); 
          localStorage.setItem('dashboard_minimized', isNowHidden);

          if(isNowHidden) { 
              $(this).removeClass('active'); 
              $(this).text('📊'); 
          } else { 
              $(this).addClass('active'); 
              $(this).text('✕'); 
          }
      });
    }

    async function init() {
      await waitGlobalInitialized('Mvu');
      render();
      eventOn(Mvu.events.VARIABLE_UPDATE_ENDED, () => { render(); });

      // Xử lý chuyển Tab
      $('.nav-btn').on('click', function() {
        $('.nav-btn').removeClass('active'); 
        $(this).addClass('active');
        const target = $(this).data('tab'); 
        $('.tab-pane').removeClass('active'); 
        $(`#${target}`).addClass('active');

        // Điều chỉnh vị trí nút Fullscreen để không che nội dung
        const fsBtn = $('.fullscreen-controls');
        if (target === 'tab-main') fsBtn.removeClass('right-side'); else fsBtn.addClass('right-side');
      });

      // Xử lý bộ lọc Nhân vật
      $('.filter-btn').on('click', function() {
        $('.filter-btn').removeClass('active'); 
        $(this).addClass('active');
        charFilterState = $(this).data('filter'); 
        pageStates.chars = 1; 
        render();
      });
    }
    $(errorCatched(init));
  </script>
