<!DOCTYPE html>
<html lang="vi">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0, maximum-scale=1.0, user-scalable=no">
  <style>
    :root {
      --primary-color: #3498db;
      --secondary-color: #2c3e50;
      --accent-color: #e74c3c;
      --text-color: #ecf0f1;
      --bg-color: #1a1a1a;
      --card-bg: #252525;
      --border-radius: 4px;
      --panel-border: 1px solid #333;
    }

    body {
      font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
      background-color: var(--bg-color);
      color: var(--text-color);
      margin: 0;
      padding: 10px;
      font-size: 12px;
      line-height: 1.4;
    }

    /* --- BỐ CỤC MOBILE CỐ ĐỊNH --- */
    .dashboard-container {
      display: flex;
      flex-direction: column;
      gap: 10px;
      max-width: 100%;
      margin: 0 auto;
    }

    /* Sidebar Styles - Menu ngang cho mobile */
    .sidebar {
      background-color: var(--card-bg);
      border-radius: var(--border-radius);
      padding: 8px;
      display: flex;
      flex-direction: row;
      flex-wrap: wrap;
      gap: 5px;
      border: var(--panel-border);
      height: auto;
      align-items: center;
      justify-content: flex-start;
    }

    .profile-card {
      width: 100%;
      display: flex;
      justify-content: space-between;
      align-items: center;
      order: -1;
      padding: 0 0 5px 0;
      margin: 0 0 5px 0;
      text-align: left;
      border-bottom: 1px solid #444;
    }

    .profile-card > div { margin: 0 !important; }
    .profile-card .char-meta { justify-content: flex-start; }

    .char-name {
      font-size: 14px;
      font-weight: bold;
      color: var(--primary-color);
      margin-bottom: 2px;
    }

    .char-meta {
      font-size: 11px;
      color: #95a5a6;
      display: flex;
      gap: 5px;
    }

    /* Nút bấm dạng thẻ nhỏ (Chips) */
    .nav-btn {
      display: inline-flex;
      width: auto;
      flex-grow: 1;
      justify-content: center;
      background: #2a2a2a;
      border: 1px solid #333;
      color: #bdc3c7;
      padding: 6px 4px;
      text-align: center;
      cursor: pointer;
      border-radius: 15px;
      transition: all 0.2s;
      font-size: 10px;
      white-space: nowrap;
    }

    .nav-btn:hover {
      background-color: #333;
      color: white;
    }

    .nav-btn.active {
      background-color: var(--primary-color);
      color: white;
      font-weight: bold;
    }

    /* Main Content Styles */
    .main-content {
      display: flex;
      flex-direction: column;
      gap: 15px;
    }

    .stat-card {
      background-color: var(--card-bg);
      border-radius: var(--border-radius);
      padding: 15px;
      border: var(--panel-border);
    }

    .section-header {
      display: flex;
      justify-content: space-between;
      align-items: center;
      margin-bottom: 12px;
      padding-bottom: 5px;
      border-bottom: 2px solid var(--primary-color);
      font-size: 14px;
      font-weight: bold;
      text-transform: uppercase;
      letter-spacing: 0.5px;
    }

    /* Attributes Grid - 3 Cột */
    .attr-grid {
      display: grid;
      grid-template-columns: repeat(3, 1fr);
      gap: 8px;
      margin-bottom: 15px;
    }

    .attr-box {
      background: #333;
      padding: 8px 5px;
      border-radius: 4px;
      text-align: center;
      border: 1px solid #444;
    }

    .attr-label {
      font-size: 11px;
      color: #95a5a6;
      margin-bottom: 3px;
    }

    .attr-value {
      font-size: 16px;
      font-weight: bold;
      color: var(--primary-color);
    }

    .attr-value.real {
      color: var(--accent-color);
      text-shadow: 0 0 5px rgba(231, 76, 60, 0.3);
    }

    /* Derived Grid - 2 Cột */
    .derived-grid {
        display: grid;
        grid-template-columns: repeat(2, 1fr);
        gap: 8px;
        margin-top: 10px;
    }
    .derived-box {
        background: #2a2a2a;
        padding: 6px;
        border-radius: 3px;
        display: flex;
        justify-content: space-between;
        align-items: center;
        border: 1px solid #3d3d3d;
        font-size: 11px;
    }
    .derived-label { color: #bdc3c7; }
    .derived-val { color: #f1c40f; font-weight: bold; }

    /* Environment Description */
    .env-desc-box {
        margin-top: 10px;
        padding: 8px;
        background: #222;
        border-left: 3px solid #7f8c8d;
        border-radius: 2px;
        font-size: 12px;
        color: #bdc3c7;
        font-style: italic;
        line-height: 1.5;
    }

    /* Resource Bars - Dọc */
    .resource-row {
      display: grid;
      grid-template-columns: 1fr;
      gap: 8px;
      margin-bottom: 10px;
    }

    .bar-container {
      position: relative;
    }

    .bar-label {
      display: flex;
      justify-content: space-between;
      font-size: 11px;
      margin-bottom: 3px;
      color: #bdc3c7;
    }

    .progress-track {
      height: 6px;
      background: #444;
      border-radius: 3px;
      overflow: hidden;
    }

    .progress-fill {
      height: 100%;
      border-radius: 3px;
      transition: width 0.3s ease;
    }

    .hp-fill { background: linear-gradient(90deg, #c0392b, #e74c3c); }
    .ep-fill { background: linear-gradient(90deg, #2980b9, #3498db); }

    /* Equipment Grid - 1 Cột */
    .equip-grid { 
      display: grid; 
      grid-template-columns: 1fr; 
      gap: 8px; 
    }

    .equip-slot-wrapper {
      display: flex;
      flex-direction: column;
    }

    .equip-slot {
      background: #2a2a2a;
      padding: 6px;
      border-radius: 4px;
      display: flex;
      align-items: center;
      gap: 8px;
      border: 1px solid #3d3d3d;
      cursor: pointer;
      transition: border-color 0.2s;
    }

    .equip-slot:hover {
      border-color: #666;
    }

    .slot-label {
      font-size: 10px;
      color: #666;
      width: 30px;
      text-align: center;
      background: #1a1a1a;
      padding: 2px 0;
      border-radius: 2px;
    }

    .equip-name {
      font-size: 12px;
      font-weight: bold;
      flex: 1;
      white-space: nowrap;
      overflow: hidden;
      text-overflow: ellipsis;
    }

    /* ================= CÁC HIỆU ỨNG MỚI (Từ bản PC) ================= */
    @keyframes shimmer { 0% { opacity: 0.9; } 50% { opacity: 1; text-shadow: 0 0 8px rgba(255,255,255,0.6); } 100% { opacity: 0.9; } }
    @keyframes gold-flow { 0% { background-position: 0% 50%; filter: brightness(100%); } 50% { background-position: 100% 50%; filter: brightness(120%); } 100% { background-position: 0% 50%; filter: brightness(100%); } }
    @keyframes void-pulse { 0% { color: #e74c3c; text-shadow: 0 0 5px #e74c3c; } 33% { color: #9b59b6; text-shadow: 0 0 10px #8e44ad; } 66% { color: #3498db; text-shadow: 0 0 5px #3498db; } 100% { color: #e74c3c; text-shadow: 0 0 5px #e74c3c; } }
    @keyframes burning { 0% { text-shadow: 0 0 4px #e67e22, 0 0 8px #d35400; } 50% { text-shadow: 0 0 8px #f1c40f, 0 0 12px #e67e22; } 100% { text-shadow: 0 0 4px #e67e22, 0 0 8px #d35400; } }
    @keyframes glitch { 0% { transform: translate(0); text-shadow: -1px -1px #ff00de, 1px 1px #00eaff; } 25% { transform: translate(-1px, 1px); } 50% { transform: translate(1px, -1px); text-shadow: 1px -1px #ff00de, -1px 1px #00eaff; } 75% { transform: translate(-1px, -1px); } 100% { transform: translate(0); text-shadow: -1px -1px #ff00de, 1px 1px #00eaff; } }
    @keyframes cosmic { 0% { background-position: 0% 50%; } 50% { background-position: 100% 50%; } 100% { background-position: 0% 50%; } }
    @keyframes rainbow-border { 0% { border-color: #e74c3c; box-shadow: 0 0 5px #e74c3c; } 25% { border-color: #f1c40f; box-shadow: 0 0 5px #f1c40f; } 50% { border-color: #2ecc71; box-shadow: 0 0 5px #2ecc71; } 75% { border-color: #3498db; box-shadow: 0 0 5px #3498db; } 100% { border-color: #9b59b6; box-shadow: 0 0 5px #9b59b6; } }


    /* Class cho Rank (S-SSS, UR...) */
    .rank-f { color: #7f8c8d; }
    .rank-e { color: #bdc3c7; }
    .rank-d { color: #2ecc71; text-shadow: 0 0 2px #27ae60; }
    .rank-c { color: #3498db; text-shadow: 0 0 3px #2980b9; }
    .rank-b { color: #9b59b6; text-shadow: 0 0 4px #8e44ad; font-weight:bold; }
    .rank-a { color: #f1c40f; text-shadow: 0 0 5px #f39c12; font-weight:bold; }
    .rank-s { color: #e74c3c; text-shadow: 0 0 5px #c0392b, 0 0 10px #e74c3c; font-weight: 800; }
    .rank-ss { color: #ff0000; text-shadow: 0 0 5px #900, 0 0 10px #f00, 0 0 15px #f00; animation: burning 2s infinite alternate; font-weight: 800; }
    .rank-sss { background: linear-gradient(120deg, #d4af37, #f00, #000, #f00, #d4af37); background-size: 300% 300%; -webkit-background-clip: text; -webkit-text-fill-color: transparent; animation: gold-flow 3s ease infinite; font-weight: 900; letter-spacing: 0.5px; }
    .rank-sr { color: #fff; text-shadow: 2px 2px #ff00de, -2px -2px #00eaff; animation: glitch 3s infinite steps(1); font-weight: 900; }
    .rank-ur { background: linear-gradient(to right, #ee7752, #e73c7e, #23a6d5, #23d5ab); background-size: 200% 200%; -webkit-background-clip: text; -webkit-text-fill-color: transparent; animation: cosmic 3s ease infinite; font-weight: 900; text-shadow: 0 0 15px rgba(255, 255, 255, 0.5); }

    /* Class cho Quality */
    .q-white { color: #ecf0f1; } 
    .q-green { color: #2ecc71; text-shadow: 0 0 1px #27ae60; } 
    .q-blue  { color: #3498db; text-shadow: 0 0 2px #2980b9; } 
    .q-purple { color: #9b59b6; text-shadow: 0 0 3px rgba(155, 89, 182, 0.6); font-weight: 700; }
    .q-d-purple { color: #bfa1d9; text-shadow: 0 0 4px #8e44ad, 0 0 8px #9b59b6; }
    .q-l-gold { color: #f1c40f; text-shadow: 0 0 3px rgba(241, 196, 15, 0.5); }
    .q-gold { color: #f39c12; text-shadow: 0 0 4px #e67e22, 0 0 8px #f1c40f; animation: shimmer 3s infinite; }
    .q-d-gold { background: linear-gradient(90deg, #f39c12, #f1c40f, #d35400); background-size: 200% auto; -webkit-background-clip: text; -webkit-text-fill-color: transparent; animation: gold-flow 4s linear infinite; text-shadow: 0 0 5px rgba(243, 156, 18, 0.4); }
    .q-legend { color: #e74c3c; text-shadow: 0 0 5px #c0392b, 0 0 10px #e74c3c; animation: shimmer 2s infinite alternate; }
    .q-epic { color: #e67e22; text-shadow: 0 0 6px #d35400, 0 0 12px #e67e22; border-bottom: 1px dashed rgba(230, 126, 34, 0.5); }
    .q-holy { color: #ecf0f1; text-shadow: 0 0 5px #ffffff, 0 0 10px #f39c12, 0 0 15px #e67e22; animation: shimmer 1.5s infinite; }
    .q-void { font-weight: 800; animation: void-pulse 4s linear infinite; text-decoration: underline dotted; }

    /* Tier Badges */
    .tier-badge { font-size: 10px; padding: 2px 6px; border-radius: 3px; margin-left: 8px; font-weight: bold; text-transform: uppercase; display: inline-block; }
    .tier-t0 { background: #7f8c8d; color: #ecf0f1; border: 1px solid #95a5a6; }
    .tier-t1 { background: #27ae60; color: #fff; border: 1px solid #2ecc71; box-shadow: 0 0 3px rgba(46, 204, 113, 0.3); }
    .tier-t2 { background: #2980b9; color: #fff; border: 1px solid #3498db; box-shadow: 0 0 5px rgba(52, 152, 219, 0.4); }
    .tier-t3 { background: #8e44ad; color: #fff; border: 1px solid #9b59b6; box-shadow: 0 0 6px rgba(155, 89, 182, 0.5); }
    .tier-t4 { background: linear-gradient(135deg, #f39c12, #d35400); color: #fff; border: 1px solid #f1c40f; box-shadow: 0 0 8px rgba(243, 156, 18, 0.6); animation: shimmer 3s infinite; }
    .tier-t5 { background: linear-gradient(135deg, #c0392b, #e74c3c); color: #fff; border: 1px solid #e74c3c; box-shadow: 0 0 10px rgba(231, 76, 60, 0.7); animation: burning 2s infinite alternate; }
    .tier-t7 { background: #000; color: #fff; border: 1px solid transparent; box-shadow: 0 0 15px rgba(255, 255, 255, 0.5); animation: void-pulse 2s infinite, rainbow-border 4s linear infinite; }

    /* Panels & Details */
    .item-detail-panel {
      background: #222;
      border: 1px solid #444;
      border-top: none;
      padding: 10px;
      margin-top: -2px;
      margin-bottom: 5px;
      border-radius: 0 0 4px 4px;
      display: none;
      font-size: 12px;
      animation: fadeIn 0.2s ease;
      position: relative;
      z-index: 10;
    }

    .detail-header {
      display: flex;
      justify-content: space-between;
      border-bottom: 1px solid #444;
      padding-bottom: 5px;
      margin-bottom: 5px;
    }

    .detail-stats {
      color: #bdc3c7;
      margin-bottom: 5px;
      display: grid;
      grid-template-columns: 1fr; /* 1 Cột cho chi tiết */
      gap: 5px;
      font-size: 11px;
    }

    .detail-desc {
      color: #7f8c8d;
      font-style: italic;
      margin-top: 5px;
      padding-top: 5px;
      border-top: 1px dashed #333;
    }

    .prof-panel {
      background: #252525;
      padding: 10px;
      border-radius: 4px;
      border: 1px solid #333;
      margin-bottom: 10px;
      cursor: pointer;
    }

    .prof-header {
      display: flex;
      justify-content: space-between;
      font-weight: bold;
      color: #e67e22;
    }

    .prof-detail-content {
      display: none;
      margin-top: 10px;
      padding-top: 10px;
      border-top: 1px solid #444;
    }

    .prof-desc-full {
      font-size: 12px;
      color: #bdc3c7;
      line-height: 1.6;
      padding: 8px;
      background: #2a2a2a;
      border-radius: 4px;
      margin-bottom: 10px;
    }

    .recipe-list {
      margin-top: 10px;
      padding-top: 10px;
      border-top: 1px dashed #444;
    }

    .recipe-list-title {
      font-size: 11px;
      color: #7f8c8d;
      margin-bottom: 5px;
    }

    .recipe-item {
      background: #333;
      padding: 5px;
      margin-bottom: 5px;
      border-radius: 3px;
      font-size: 12px;
      cursor: pointer;
      transition: background 0.2s;
    }
    .recipe-item:hover {
        background: #444;
    }

    .recipe-detail {
        display: none;
        padding: 8px;
        background: #222;
        border-top: 1px solid #444;
        font-size: 11px;
        color: #bdc3c7;
        margin-bottom: 5px;
    }
    .recipe-detail-row {
        display: flex;
        justify-content: space-between;
        margin-bottom: 3px;
        border-bottom: 1px dashed #333;
        padding-bottom: 2px;
    }

    /* Ability & Skills */
    .ability-list {
      display: flex;
      flex-direction: column;
      gap: 8px;
    }

    .ability-item {
      background: #333;
      border-radius: 4px;
      border-left: 3px solid #555;
      overflow: hidden;
    }

    .ability-item.skill { border-left-color: var(--primary-color); }
    .ability-item.talent { border-left-color: #f39c12; }
    .ability-item.buff { border-left-color: #2ecc71; }
    .ability-item.record { border-left-color: #e67e22; }

    .ability-main {
      padding: 10px;
      cursor: pointer;
      transition: background 0.2s;
    }

    .ability-main:hover {
      background: #3a3a3a;
    }

    .ability-header {
      display: flex;
      justify-content: space-between;
      margin-bottom: 4px;
      font-weight: bold;
      font-size: 13px;
    }

    .ability-desc {
      font-size: 12px;
      color: #bdc3c7;
    }

    .ability-toggle {
      font-size: 10px;
      color: #7f8c8d;
      float: right;
    }

    .ability-detail {
      display: none;
      padding: 10px;
      background: #2a2a2a;
      border-top: 1px solid #444;
      animation: fadeIn 0.2s ease;
    }

    .ability-detail-grid {
      display: grid;
      grid-template-columns: 1fr; /* 1 Cột */
      gap: 6px;
      font-size: 11px;
    }

    .ability-detail-row {
      display: flex;
      justify-content: space-between;
      padding: 4px 6px;
      background: #333;
      border-radius: 3px;
    }

    .ability-detail-row.full {
      grid-column: 1 / -1;
    }

    .ability-detail-label {
      color: #7f8c8d;
    }

    .ability-detail-value {
      color: #ecf0f1;
    }

    .ability-detail-desc {
      grid-column: 1 / -1;
      padding: 8px;
      background: #333;
      border-radius: 3px;
      color: #bdc3c7;
      line-height: 1.5;
      white-space: pre-wrap;
    }

    /* Currency */
    .currency-bar {
      display: flex;
      justify-content: space-between;
      gap: 8px;
      margin-top: 10px;
      padding-top: 10px;
      border-top: 1px solid #444;
      flex-wrap: wrap;
    }

    .curr-item {
      font-size: 10px;
      display: flex;
      align-items: center;
      gap: 4px;
      width: 48%; /* Chia đôi */
    }

    .tab-pane { display: none; }
    .tab-pane.active { display: block; }

    @keyframes fadeIn {
      from { opacity: 0; transform: translateY(-5px); }
      to { opacity: 1; transform: translateY(0); }
    }

    .empty-msg {
      text-align: center;
      color: #555;
      padding: 20px;
      font-style: italic;
    }

    /* Char Cards */
    .char-list {
      display: flex;
      flex-direction: column;
      gap: 8px;
    }

    .char-card {
      background: #2a2a2a;
      border: 1px solid #3d3d3d;
      border-radius: 4px;
      overflow: hidden;
    }

    .char-card.follower { border-left: 3px solid #9b59b6; }
    .char-card.npc { border-left: 3px solid #3498db; }

    .char-card-main {
      padding: 10px;
      cursor: pointer;
      transition: all 0.2s;
    }

    .char-card-main:hover {
      background: #333;
    }

    .char-card-header {
      display: flex;
      justify-content: space-between;
      align-items: center;
      margin-bottom: 6px;
    }

    .char-card-name {
      font-weight: bold;
      font-size: 13px;
      color: var(--primary-color);
    }

    .char-card-badges {
      display: flex;
      gap: 4px;
    }

    .char-type-badge {
      font-size: 9px;
      padding: 2px 5px;
      border-radius: 3px;
      font-weight: bold;
    }

    .char-type-badge.follower { background: #9b59b6; color: white; }
    .char-type-badge.npc { background: #3498db; color: white; }

    .char-card-status {
      font-size: 10px;
      padding: 2px 6px;
      border-radius: 3px;
      background: #444;
    }

    .char-card-status.present { background: #27ae60; color: white; }
    .char-card-status.absent { background: #7f8c8d; color: #ddd; }

    .char-card-info {
      display: grid;
      grid-template-columns: 1fr; /* 1 Cột */
      gap: 4px;
      font-size: 11px;
      color: #95a5a6;
    }

    .char-card-info span {
      display: flex;
      align-items: center;
      gap: 4px;
    }

    .affection-bar {
      width: 60px;
      height: 4px;
      background: #444;
      border-radius: 2px;
      overflow: hidden;
      display: inline-block;
      vertical-align: middle;
      margin-left: 5px;
    }

    .affection-fill {
      height: 100%;
      background: linear-gradient(90deg, #e74c3c, #f39c12, #2ecc71);
      border-radius: 2px;
      transition: width 0.3s;
    }

    .char-card-detail {
      display: none;
      background: #1f1f1f;
      border-top: 1px solid #333;
      animation: fadeIn 0.2s ease;
    }

    .char-detail-tabs {
      display: flex;
      border-bottom: 1px solid #333;
      background: #252525;
      flex-wrap: wrap;
    }

    .char-detail-tab {
      padding: 8px 12px;
      font-size: 11px;
      color: #7f8c8d;
      cursor: pointer;
      border-bottom: 2px solid transparent;
      transition: all 0.2s;
    }

    .char-detail-tab:hover {
      color: #bdc3c7;
      background: #2a2a2a;
    }

    .char-detail-tab.active {
      color: var(--primary-color);
      border-bottom-color: var(--primary-color);
    }

    .char-detail-content {
      padding: 10px;
      max-height: 400px;
      overflow-y: auto;
    }

    .char-detail-pane {
      display: none;
    }

    .char-detail-pane.active {
      display: block;
    }

    .char-info-grid {
      display: grid;
      grid-template-columns: 1fr; /* 1 Cột */
      gap: 8px;
      font-size: 11px;
    }

    .char-info-row {
      display: flex;
      justify-content: space-between;
      padding: 4px 8px;
      background: #2a2a2a;
      border-radius: 3px;
    }

    .char-info-label { color: #7f8c8d; }
    .char-info-value { color: #ecf0f1; }

    .char-intro {
      padding: 10px;
      background: #2a2a2a;
      border-radius: 4px;
      font-size: 12px;
      color: #bdc3c7;
      line-height: 1.6;
      white-space: pre-wrap;
    }

    .char-attr-grid {
      display: grid;
      grid-template-columns: repeat(3, 1fr);
      gap: 6px;
      margin-bottom: 10px;
    }

    .char-attr-box {
      background: #2a2a2a;
      padding: 6px;
      border-radius: 3px;
      text-align: center;
      border: 1px solid #333;
    }

    .char-attr-label { font-size: 10px; color: #7f8c8d; }
    .char-attr-value { font-size: 14px; font-weight: bold; color: var(--primary-color); }

    .char-equip-list {
      display: flex;
      flex-direction: column;
      gap: 6px;
    }

    .char-equip-item-wrapper { display: flex; flex-direction: column; }

    .char-equip-item {
      display: flex;
      align-items: center;
      gap: 8px;
      padding: 6px 8px;
      background: #2a2a2a;
      border-radius: 3px;
      border-left: 3px solid #555;
      cursor: pointer;
    }

    .char-equip-item:hover { background: #333; }
    .char-equip-slot { font-size: 10px; color: #666; min-width: 40px; }
    .char-equip-name { flex: 1; font-size: 12px; font-weight: bold; }
    .char-equip-quality { font-size: 10px; color: #7f8c8d; }

    .char-ability-list {
      display: flex;
      flex-direction: column;
      gap: 6px;
    }

    .char-inv-grid {
      display: grid;
      grid-template-columns: 1fr; /* 1 Cột */
      gap: 6px;
    }

    .char-inv-item {
      display: flex;
      align-items: center;
      gap: 6px;
      padding: 6px;
      background: #2a2a2a;
      border-radius: 3px;
      font-size: 11px;
    }

    .char-inv-name { flex: 1; color: #ecf0f1; }
    .char-inv-qty { color: #f39c12; font-weight: bold; }

    .char-filter-bar {
      display: flex;
      gap: 8px;
      margin-bottom: 10px;
      flex-wrap: wrap;
    }

    .filter-btn {
      background: #333;
      border: 1px solid #444;
      color: #bdc3c7;
      padding: 4px 10px;
      border-radius: 3px;
      font-size: 11px;
      cursor: pointer;
      transition: all 0.2s;
    }

    .filter-btn:hover { background: #444; }
    .filter-btn.active { background: var(--primary-color); border-color: var(--primary-color); color: white; }

    .char-detail-content::-webkit-scrollbar { width: 6px; }
    .char-detail-content::-webkit-scrollbar-track { background: #1a1a1a; }
    .char-detail-content::-webkit-scrollbar-thumb { background: #444; border-radius: 3px; }

    /* Quest */
    .quest-list { display: flex; flex-direction: column; gap: 12px; }
    .quest-card { background: #2a2a2a; border-radius: 4px; border: 1px solid #3d3d3d; overflow: hidden; }
    .quest-card.main { border-left: 3px solid #e74c3c; }
    .quest-card.side { border-left: 3px solid #3498db; }
    .quest-card.hidden { border-left: 3px solid #9b59b6; }

    .quest-header {
      display: flex;
      justify-content: space-between;
      align-items: center;
      padding: 10px;
      cursor: pointer;
      transition: background 0.2s;
    }

    .quest-header:hover { background: #333; }
    .quest-title-row { display: flex; align-items: center; gap: 8px; }
    .quest-type-badge { font-size: 10px; padding: 2px 6px; border-radius: 3px; font-weight: bold; }
    .quest-type-badge.main { background: #e74c3c; color: white; }
    .quest-type-badge.side { background: #3498db; color: white; }
    .quest-type-badge.hidden { background: #9b59b6; color: white; }
    .quest-name { font-weight: bold; font-size: 13px; color: #ecf0f1; }
    .quest-toggle { font-size: 10px; color: #7f8c8d; }

    .quest-detail {
      display: none;
      padding: 10px;
      border-top: 1px solid #333;
      background: #222;
      animation: fadeIn 0.2s ease;
    }

    .quest-info-row { display: flex; margin-bottom: 8px; font-size: 12px; }
    .quest-info-label { color: #7f8c8d; min-width: 60px; }
    .quest-info-value { color: #bdc3c7; flex: 1; }

    .quest-hint {
      margin-top: 10px;
      padding: 8px;
      background: #2a2a2a;
      border-radius: 4px;
      border-left: 2px solid #f39c12;
    }

    .quest-hint-label { font-size: 10px; color: #f39c12; margin-bottom: 4px; }
