    .affix-detail { display: none; padding: 5px 8px; background: #222; color: #bdc3c7; font-size: 11px; line-height: 1.4; margin-bottom: 4px; border-radius: 0 0 3px 3px; }

    .appearance-box { padding: 10px; background: #2a2a2a; border-radius: 4px; font-size: 12px; color: #bdc3c7; line-height: 1.6; white-space: pre-wrap; border: 1px solid #3d3d3d; }

