    .char-inv-item-detail { display: none; padding: 8px; background: #222; border: 1px solid #3d3d3d; border-top: none; border-radius: 0 0 3px 3px; font-size: 11px; color: #bdc3c7; width: 100%; box-sizing: border-box; }
    .char-inv-detail-row { display: flex; justify-content: space-between; margin-bottom: 3px; border-bottom: 1px dashed #333; padding-bottom: 2px; }
    .char-inv-detail-row.full { flex-direction: column; border-bottom: none; }
    .char-inv-detail-label { color: #7f8c8d; }
    .char-inv-detail-value { color: #ecf0f1; word-break: break-all; }

  </style>
  <script type="module">
    const pageStates = {
      skills: 1,
      talents: 1,
      buffs: 1,
      titles: 1,
      records: 1,
      space: 1,
      chars: 1,
      factions: 1,
      inv: 1,
      quests: 1,
      recipes: 1,
      subProf: 1
    };
    const itemsPerPage = 10; 

    const getQualityClass = (q) => {
      if(!q) return 'q-white';
      const qStr = String(q);
      if(qStr.includes('Bất Hủ') || qStr.includes('Khởi Nguyên') || qStr.includes('Vĩnh Hằng')) return 'q-void';
      if(qStr.includes('Truyền Thuyết')) return 'q-legend';
      if(qStr.includes('Sử Thi')) return 'q-epic';
      if(qStr.includes('Thánh Linh')) return 'q-holy';
      if(qStr.includes('Ám Kim')) return 'q-d-gold';
      if(qStr.includes('Đạm Kim')) return 'q-l-gold';
      if(qStr.includes('Vàng') || qStr.includes('Kim')) return 'q-gold';
      if(qStr.includes('Ám Tử') || qStr.includes('Ám Tím')) return 'q-d-purple';
      if(qStr.includes('Tím') || qStr.includes('Tử')) return 'q-purple';
      if(qStr.includes('Lục') || qStr.includes('Xanh Lá')) return 'q-green'; 
      if(qStr.includes('Lam') || qStr.includes('Xanh')) return 'q-blue';
      if(qStr.includes('Trắng') || qStr.includes('Bạch') || qStr.includes('Phổ Thông') || qStr.includes('Bình Thường')) return 'q-white';
      return 'q-white';
    };

    const getRankClass = (rank) => {
      if(!rank) return '';
      const r = String(rank).toUpperCase();
      if(r.includes('UR') || r.includes('QUY TẮC') || r.includes('LUẬT')) return 'rank-ur';
      if(r.includes('SR')) return 'rank-sr';
      if(r.includes('SSS')) return 'rank-sss';
      if(r.includes('SS')) return 'rank-ss';
      if(r.includes('S')) return 'rank-s';
      if(r.includes('A')) return 'rank-a';
      if(r.includes('B')) return 'rank-b';
      if(r.includes('C')) return 'rank-c';
      if(r.includes('D')) return 'rank-d';
      if(r.includes('E')) return 'rank-e';
      if(r.includes('F')) return 'rank-f';
      return '';
    };

    const renderAbility = (item, type) => {
      const name = item['Tên'] || 'Chưa Đặt Tên';
      const level = item['Cấp Độ'] ? `Lv.${item['Cấp Độ']}` : (item['Số Tầng Cộng Dồn'] ? `x${item['Số Tầng Cộng Dồn']}` : '');
      const desc = item['Hiệu Quả'] || item['Mô Tả'] || 'Tạm không có mô tả';
      const rank = item['Phẩm Cấp'] || item['Rank'] || '';
      const rankClass = getRankClass(rank);

      const excludeKeys = ['Tên', 'Phẩm Cấp', 'Rank'];
      const detailRows = [];
      Object.entries(item).forEach(([key, value]) => {
        if(excludeKeys.includes(key)) return;
        if(value === null || value === undefined || value === '') return;
        if(Array.isArray(value)) {
          if(value.length > 0) detailRows.push({ key, value: value.join(', '), full: true });
        } else if(typeof value === 'object') {
          detailRows.push({ key, value: JSON.stringify(value), full: true });
        } else {
          detailRows.push({ key, value: String(value), full: false });
        }
      });
      let detailHtml = detailRows.length > 0 ? detailRows.map(row => `
        <div class="ability-detail-row ${row.full ? 'full' : ''}">
          <span class="ability-detail-label">${row.key}</span>
          <span class="ability-detail-value">${row.value}</span>
        </div>
      `).join('') : '<div class="ability-detail-row full"><span class="ability-detail-value" style="color:#7f8c8d;">Tạm không có thêm thông tin</span></div>';
      return `
        <div class="ability-item ${type}">
          <div class="ability-main">
            <div class="ability-header">
              <span class="${rankClass}" style="${rankClass ? '' : 'color:#ecf0f1'}">
                ${name} ${rank ? `<span style="font-size:10px;opacity:0.8">[${rank}]</span>` : ''}
              </span>
              <span>
                <span style="font-size:11px; color:#95a5a6; background:#222; padding:1px 5px; border-radius:3px;">${level}</span>
                <span class="ability-toggle">▼ Chi tiết</span>
              </span>
            </div>
            <div class="ability-desc">${desc}</div>
          </div>
          <div class="ability-detail">
            <div class="ability-detail-grid">${detailHtml}</div>
          </div>
        </div>
      `;
    };

    const renderPagination = (idPrefix, currentPage, totalPages) => {
      if (totalPages <= 1) return '';
      return `
        <div class="pagination-bar" id="pag-${idPrefix}">
          <button class="page-btn" id="btn-prev-${idPrefix}" ${currentPage <= 1 ? 'disabled' : ''}>◀ Trang Trước</button>
          <span class="page-info" id="info-${idPrefix}">${currentPage} / ${totalPages}</span>
          <button class="page-btn" id="btn-next-${idPrefix}" ${currentPage >= totalPages ? 'disabled' : ''}>Trang Sau ▶</button>
        </div>
      `;
    };

    const renderSubProfPagination = (idPrefix, currentPage, totalPages) => {
      if (totalPages <= 1) return '';
      return `
        <div class="subprof-pagination-container" id="pag-${idPrefix}">
          <button class="page-btn" id="btn-prev-${idPrefix}" ${currentPage <= 1 ? 'disabled' : ''} style="margin-right:5px;">◀</button>
          <span class="page-info" id="info-${idPrefix}" style="margin-right:5px;line-height:24px;">${currentPage} / ${totalPages}</span>
          <button class="page-btn" id="btn-next-${idPrefix}" ${currentPage >= totalPages ? 'disabled' : ''}>▶</button>
        </div>
      `;
    };

    const renderRecipeItem = (id, recipe) => {
      const name = recipe['Tên'] || 'Công thức chưa biết';
      const excludeKeys = ['Tên'];
      let detailsHtml = '';

      Object.entries(recipe).forEach(([key, val]) => {
          if(excludeKeys.includes(key)) return;
          if(val === null || val === undefined) return;
          let displayVal = val;
          if(typeof val === 'object') displayVal = JSON.stringify(val);
          detailsHtml += `
            <div class="recipe-detail-row">
                <span style="color:#7f8c8d;">${key}</span>
                <span style="color:#ecf0f1;">${displayVal}</span>
            </div>
          `;
      });

      if(!detailsHtml) detailsHtml = '<div style="color:#7f8c8d; font-style:italic;">Tạm không có thông tin chi tiết</div>';

      return `
        <div class="recipe-item-wrapper">
            <div class="recipe-item">📜 ${name}</div>
            <div class="recipe-detail">${detailsHtml}</div>
        </div>
      `;
    };

    const renderEquipDetailContent = (item, qClass) => {
      let affixesHtml = '';
      const affixes = item['Từ Tố'] || item['Dòng Thuộc Tính'] || []; 

      if (Array.isArray(affixes) && affixes.length > 0) {
        affixesHtml = affixes.map(affix => {
          let name = 'Từ tố chưa biết';
          let desc = 'Tạm không có hiệu quả';
          if (typeof affix === 'string') {
             const parts = affix.split(/[:：]/);
             if (parts.length > 1) {
                name = parts[0];
                desc = parts.slice(1).join(':');
             } else {
                name = affix;
             }
          } else if (typeof affix === 'object') {
             name = affix['Tên'] || affix.name || 'Từ tố chưa biết';
             desc = affix['Hiệu Quả'] || affix['Mô Tả'] || affix.effect || 'Tạm không có hiệu quả';
          }
          return `
            <div class="affix-item-wrapper">
                <div class="affix-item">
                    <span class="affix-name">${name}</span>
                    <span class="affix-toggle">▼</span>
                </div>
                <div class="affix-detail">${desc}</div>
            </div>
          `;
        }).join('');

        affixesHtml = `
          <div class="affix-section">
            <div class="affix-title">✦ Từ Tố Trang Bị</div>
            <div class="affix-list">${affixesHtml}</div>
          </div>
        `;
      }

      return `
        <div class="detail-header">
          <span class="${qClass}">${item['Tên']}</span>
          <span style="color:#f1c40f">Điểm Đánh Giá: ${item['Điểm Đánh Giá'] || 0}</span>
        </div>
        <div class="detail-stats">
          ${item['Tấn Công'] ? `<div>⚔️ Tấn Công: ${item['Tấn Công']}</div>` : ''}
          ${item['Phòng Ngự'] ? `<div>🛡️ Phòng Ngự: ${item['Phòng Ngự']}</div>` : ''}
          ${item['Loại'] ? `<div>🏷️ Loại: ${item['Loại']}</div>` : ''}
          ${item['Chất Lượng'] ? `<div>💎 Chất Lượng: ${item['Chất Lượng']}</div>` : ''}
        </div>
        ${item['Hiệu Ứng Đặc Biệt'] ? `<div style="margin-top:5px; font-size:11px; color:#3498db;">✨ Hiệu ứng: ${item['Hiệu Ứng Đặc Biệt']}</div>` : ''}
        <div class="detail-desc">${item['Mô Tả'] || 'Không có mô tả đặc biệt'}</div>
        ${affixesHtml}
      `;
    };

const renderCharEquip = (slotName, item) => {
      if(!item || !item['Tên'] || item['Tên'] === 'Chưa Trang Bị') {
        return `<div class="char-equip-item-wrapper"><div class="char-equip-item" data-has="false"><span class="char-equip-slot">${slotName}</span><span class="char-equip-name q-white">Chưa Trang Bị</span></div></div>`;
      }
      const qClass = getQualityClass(item['Chất Lượng']);
      const detailContent = renderEquipDetailContent(item, qClass);

      return `
        <div class="char-equip-item-wrapper">
          <div class="char-equip-item" data-has="true">
            <span class="char-equip-slot">${slotName}</span>
            <span class="char-equip-name ${qClass}">${item['Tên']}</span>
            <span class="char-equip-quality">${item['Chất Lượng'] || ''}</span>
          </div>
          <div class="item-detail-panel">
            ${detailContent}
          </div>
        </div>
      `;
    };

    const renderCharCard = (id, char) => {
      const name = char['Tên'] || 'Chưa biết';
      const location = char['Vị Trí'] || 'Chưa biết';
      const status = char['Trạng Thái'] || 'Bình thường';
      const affection = char['Độ Hảo Cảm'] || 0;
      const isAbsent = char['Có Phải Đã Rời Đi'] === 'Phải';
      const tier = char['Vị Giai'] || 'Chưa biết';
      const level = char['Cấp Độ'] || 0;

      const identity = char['Thân Phận'] || 'Chưa biết';
      const job = char['Nghề Nghiệp'] || 'Chưa xác định';
      const race = char['Chủng Tộc'] || 'Chưa xác định';
      const stance = char['Lập Trường'] || 'Trung Lập';
      const faction = char['Thế Lực Trực Thuộc'] || char['Thế Lực'] || 'Không';
      const personality = char['Tính Cách'] || 'Chưa biết';

      const rawStage = char['Giai Đoạn Hiện Tại'] || ''; 
      const appearance = char['Mô Tả Ngoại Hình'] || 'Tạm không có mô tả';
      const intro = char['Giới Thiệu'] || char['Giới Thiệu Nhân Vật'] || 'Tạm không có giới thiệu';
      const innerThought = char['Suy Nghĩ Nội Tâm'] || '';

      const charType = char['Loại Nhân Vật'] || char['Loại'] || 'NPC';
      const isFollower = charType === 'Tùy Tùng';
      const affectionPct = Math.min(100, Math.max(0, (affection + 100) / 2));

      // Mới: Giới tính & Sở thích
      const gender = char['Giới Tính'] || 'Chưa Rõ';
      const hobby = char['Sở Thích'] || 'Chưa rõ';
      const isFemale = gender.includes('Nữ') || gender.toLowerCase().includes('female');

      // Logic Tier/Boss Badge
      let rawTier = char['Vị Giai'] || char['Giai Đoạn Hiện Tại'] || char['Cấp Độ Boss'] || 'T0_Bình Thường';
      let tierClass = 'tier-t0';

      if(rawTier.includes('T7') || rawTier.includes('Chí Cao') || rawTier.includes('Giai 9')) tierClass = 'tier-t7';
      else if(rawTier.includes('T5') || rawTier.includes('Thế Giới') || rawTier.includes('Giai 7') || rawTier.includes('Giai 8')) tierClass = 'tier-t5';
      else if(rawTier.includes('T4') || rawTier.includes('Bá Chủ') || rawTier.includes('Giai 5') || rawTier.includes('Giai 6')) tierClass = 'tier-t4';
      else if(rawTier.includes('T3') || rawTier.includes('Lĩnh Chủ') || rawTier.includes('Giai 4')) tierClass = 'tier-t3';
      else if(rawTier.includes('T2') || rawTier.includes('Đầu Mục') || rawTier.includes('Giai 3')) tierClass = 'tier-t2';
      else if(rawTier.includes('T1') || rawTier.includes('Tinh Anh') || rawTier.includes('Giai 1') || rawTier.includes('Giai 2')) tierClass = 'tier-t1';
      else tierClass = 'tier-t0';

      // Logic Tâm trạng
      let displayStage = '';
      if (rawStage && rawStage !== rawTier) {
           displayStage = rawStage;
      }

      const count = char['Số Lượng'] || 1;
      const sixDim = char['Thuộc Tính Cơ Bản'] || {};
      const derived = char['Thuộc Tính Dẫn Xuất'] || {};
      const hpCur = char.HP_Cur || 0;
      const hpMax = char.HP_Max || 0;
      const epCur = char.EP_Cur || 0;
      const epMax = char.EP_Max || 0;

      const mainWeapon = char['Vũ Khí Tay Chính'] || {};
      const subWeapon = char['Vũ Khí Tay Phụ'] || {};
      const armor = char['Giáp'] || {};
      const skills = char['Kỹ Năng'] || {};
      const talents = char['Thiên Phú'] || {};
      const buffs = char['Đặc Tính Buff'] || {};
      const inventory = char['Túi Đồ'] || {};

      let skillsHtml = Object.keys(skills).length > 0 ? Object.values(skills).map(s => renderAbility(s, 'skill')).join('') : '<div class="empty-msg" style="padding:10px;font-size:11px;">Tạm không có kỹ năng</div>';
      let talentsHtml = Object.keys(talents).length > 0 ? Object.values(talents).map(t => renderAbility(t, 'talent')).join('') : '<div class="empty-msg" style="padding:10px;font-size:11px;">Tạm không có thiên phú</div>';
