      let equipHtml = renderCharEquip('Tay Chính', mainWeapon) + renderCharEquip('Tay Phụ', subWeapon);
      ['Đầu','Áo','Quần','Tay','Vai','Giày','Nhẫn 1','Nhẫn 2','Dây Chuyền','Thắt Lưng','Trang Sức Phụ'].forEach(slot => {
        equipHtml += renderCharEquip(slot, armor[slot] || {});
      });

      let invHtml = Object.keys(inventory).length > 0 ? Object.values(inventory).map(item => {
        const iName = item['Tên'] || 'Vật phẩm chưa biết';
        const iQty = item['Số Lượng'] || 1;
        const qClass = getQualityClass(item['Chất Lượng']);
        const excludeKeys = ['Tên', 'Số Lượng'];
        let details = '';
        Object.entries(item).forEach(([k, v]) => {
