            let valStr = typeof v === 'object' ? JSON.stringify(v) : String(v);
            const isLong = valStr.length > 20;
            details += `<div class="char-inv-detail-row ${isLong?'full':''}"><span class="char-inv-detail-label">${k}</span><span class="char-inv-detail-value">${valStr}</span></div>`;
