        if(!details) details = '<div style="color:#555;font-style:italic;">Không có thông tin chi tiết</div>';
        return `<div class="char-inv-item-wrapper" style="display:flex; flex-direction:column; width:100%; margin-bottom:2px;"><div class="char-inv-item" style="cursor:pointer;"><span class="char-inv-name ${qClass}">${iName}</span><span class="char-inv-qty">x${iQty}</span><span style="font-size:9px;color:#555;margin-left:auto;">▼</span></div><div class="char-inv-item-detail">${details}</div></div>`;
      }).join('') : '<div class="empty-msg" style="padding:10px;font-size:11px;">Tạm không có vật phẩm</div>';

      let sexLifeHtml = '';
      if(isFemale) {
          const sl = char['Đời Sống Tình Dục'] || {}; 
          const parts = sl['Phát Triển Cơ Thể'] || {};
          const kinks = sl['Sở Thích Tình Dục'] || {};
          sexLifeHtml += `<div class="char-info-grid" style="margin-bottom:10px;"><div class="char-info-row"><span class="char-info-label">Độ Sa Ngã</span><span class="char-info-value" style="color:#e74c3c;">${sl['Độ Sa Ngã'] || '0'}</span></div><div class="char-info-row"><span class="char-info-label">Cúp Ngực</span><span class="char-info-value">${sl['Cúp Ngực'] || '?'}</span></div><div class="char-info-row full"><span class="char-info-label">Tư Thế Ưa Thích</span><span class="char-info-value">${sl['Tư Thế Ưa Thích'] || 'Không'}</span></div><div class="char-info-row full"><span class="char-info-label">Dâm Văn</span><span class="char-info-value" style="color:#9b59b6;">${sl['Dâm Văn'] || 'Không'}</span></div></div><div style="margin-bottom:10px;padding:8px;background:#2a2a2a;border-radius:3px;font-size:11px;"><span style="color:#7f8c8d;">💬 Đánh Giá:</span><span style="color:#bdc3c7;">${sl['Đánh Giá Chung'] || 'Chưa có đánh giá'}</span></div>`;
          sexLifeHtml += '<div class="char-ability-list"><div style="font-size:11px;color:#e67e22;margin:5px 0;">💋 Khai Phá Cơ Thể</div>';
          Object.entries(parts).forEach(([part, status]) => { sexLifeHtml += `<div class="ability-item buff"><div class="ability-main char-ability-main"><div class="ability-header"><span style="color:#ecf0f1">${part}</span><span class="ability-toggle">▼ Chi tiết</span></div></div><div class="ability-detail"><div class="ability-detail-desc">${typeof status === 'object' ? JSON.stringify(status) : status}</div></div></div>`; });
          sexLifeHtml += '<div style="font-size:11px;color:#9b59b6;margin:10px 0 5px 0;">⛓️ Sở Thích / Fetish</div>';
          if (Object.keys(kinks).length > 0) { Object.entries(kinks).forEach(([k, v]) => { sexLifeHtml += `<div class="ability-item talent"><div class="ability-main char-ability-main"><div class="ability-header"><span style="color:#ecf0f1">${k}</span><span class="ability-toggle">▼ Chi tiết</span></div></div><div class="ability-detail"><div class="ability-detail-desc">${v}</div></div></div>`; }); } else { sexLifeHtml += '<div class="empty-msg" style="padding:5px;">Chưa thức tỉnh sở thích</div>'; }
          sexLifeHtml += '</div>';
