                  <div class="char-info-row"><span class="char-info-label">Nghề Nghiệp</span><span class="char-info-value">${job}</span></div>
                  <div class="char-info-row"><span class="char-info-label">Loại</span><span class="char-info-value">${charType}</span></div>
                  <div class="char-info-row"><span class="char-info-label">Thân Phận</span><span class="char-info-value">${identity}</span></div>
                  <div class="char-info-row"><span class="char-info-label">Thế Lực</span><span class="char-info-value">${faction}</span></div>
                  <div class="char-info-row"><span class="char-info-label">Lập Trường</span><span class="char-info-value">${stance}</span></div>

                  <div class="char-info-row"><span class="char-info-label">Giới Tính</span><span class="char-info-value">${gender}</span></div>
                  <div class="char-info-row"><span class="char-info-label">Sở Thích</span><span class="char-info-value">${hobby}</span></div>

                  <div class="char-info-row"><span class="char-info-label">Tính Cách</span><span class="char-info-value">${personality}</span></div>
                  <div class="char-info-row"><span class="char-info-label">Độ Hảo Cảm</span><span class="char-info-value">${affection}</span></div>
                </div>
                ${innerThought ? `<div style="margin-top:10px;padding:8px;background:#2a2a2a;border-radius:4px;font-size:11px;"><span style="color:#7f8c8d;">💭 Nội Tâm:</span><span style="color:#bdc3c7;">${innerThought}</span></div>` : ''}
                <div style="margin-top:10px;"><div style="font-size:11px;color:#7f8c8d;margin-bottom:5px;">👁️ Mô Tả Ngoại Hình</div><div class="char-intro">${appearance}</div></div>
                <div style="margin-top:10px;"><div style="font-size:11px;color:#7f8c8d;margin-bottom:5px;">📖 Giới Thiệu Nhân Vật</div><div class="char-intro">${intro}</div></div>
              </div>
              <div class="char-detail-pane" data-pane="attrs">
                <div class="char-attr-grid">
                  <div class="char-attr-box"><div class="char-attr-label">Sức Mạnh</div><div class="char-attr-value">${sixDim['Sức Mạnh'] || 0}</div></div>
                  <div class="char-attr-box"><div class="char-attr-label">Nhanh Nhẹn</div><div class="char-attr-value">${sixDim['Nhanh Nhẹn'] || 0}</div></div>
                  <div class="char-attr-box"><div class="char-attr-label">Thể Chất</div><div class="char-attr-value">${sixDim['Thể Chất'] || 0}</div></div>
                  <div class="char-attr-box"><div class="char-attr-label">Trí Tuệ</div><div class="char-attr-value">${sixDim['Trí Tuệ'] || 0}</div></div>
                  <div class="char-attr-box"><div class="char-attr-label">Mị Lực</div><div class="char-attr-value">${sixDim['Mị Lực'] || 0}</div></div>
                  <div class="char-attr-box"><div class="char-attr-label">May Mắn</div><div class="char-attr-value">${sixDim['May Mắn'] || 0}</div></div>
                </div>
                <div style="display:grid;grid-template-columns:1fr;gap:8px;">
                  <div class="char-info-row"><span class="char-info-label">HP</span><span class="char-info-value">${hpCur}/${hpMax}</span></div>
                  <div class="char-info-row"><span class="char-info-label">EP</span><span class="char-info-value">${epCur}/${epMax}</span></div>
                  <div class="char-info-row"><span class="char-info-label">Vật Lý ATK</span><span class="char-info-value">${derived['Vật Lý ATK'] || 0}</span></div>
                  <div class="char-info-row"><span class="char-info-label">Vật Lý DEF</span><span class="char-info-value">${derived['Vật Lý DEF'] || 0}</span></div>
                  <div class="char-info-row"><span class="char-info-label">Pháp Thuật ATK</span><span class="char-info-value">${derived['Pháp Thuật ATK'] || 0}</span></div>
                  <div class="char-info-row"><span class="char-info-label">Pháp Thuật DEF</span><span class="char-info-value">${derived['Pháp Thuật DEF'] || 0}</span></div>
                </div>
              </div>
              <div class="char-detail-pane" data-pane="equip"><div class="char-equip-list">${equipHtml}</div></div>
              <div class="char-detail-pane" data-pane="skills"><div class="char-ability-list">${skillsHtml}</div></div>
              <div class="char-detail-pane" data-pane="talents"><div class="char-ability-list">${talentsHtml}</div></div>
              <div class="char-detail-pane" data-pane="buffs"><div class="char-ability-list">${buffsHtml}</div></div>
              <div class="char-detail-pane" data-pane="inv"><div class="char-inv-grid">${invHtml}</div></div>
              ${isFemale ? `<div class="char-detail-pane" data-pane="sex">${sexLifeHtml}</div>` : ''}
            </div>
          </div>
        </div>
      `;
    };

    const renderInventoryItem = (id, item) => {
      const name = item['Tên'] || 'Vật phẩm chưa biết';
      const qty = item['Số Lượng'] || 1;
      const qClass = getQualityClass(item['Chất Lượng']);
      const excludeKeys = ['Tên'];
      const detailRows = [];
      Object.entries(item).forEach(([key, value]) => {
        if(excludeKeys.includes(key)) return;
        if(value === null || value === undefined || value === '') return;
        if(Array.isArray(value)) {
          if(value.length > 0) detailRows.push({ key, value: value.join(', '), full: true });
        } else if(typeof value === 'object') {
          detailRows.push({ key, value: JSON.stringify(value), full: true });
        } else {
          detailRows.push({ key, value: String(value), full: false });
        }
      });
      let detailHtml = detailRows.length > 0 ? detailRows.map(row => `
        <div class="inv-detail-row ${row.full ? 'full' : ''}">
          <span class="inv-detail-label">${row.key}</span>
          <span class="inv-detail-value">${row.value}</span>
        </div>
      `).join('') : '<div class="inv-detail-row full"><span class="inv-detail-value" style="color:#7f8c8d;">Tạm không có thêm thông tin</span></div>';

      return `
        <div class="inv-item-card" data-id="${id}">
          <div class="inv-item-main">
            <div class="inv-item-left">
              <span class="inv-item-name ${qClass}">${name}</span>
              <span class="inv-item-qty">x${qty}</span>
            </div>
            <span class="inv-item-toggle">▼ Chi tiết</span>
          </div>
          <div class="inv-item-detail">
            <div class="inv-detail-grid">${detailHtml}</div>
          </div>
        </div>
      `;
    };

    const renderFactionCard = (id, faction) => {
      const name = faction['Tên'] || 'Thế lực chưa biết';
      const relation = faction['Quan Hệ'] || 'Trung Lập';
      const relationValue = faction['Giá Trị Quan Hệ'] || 50;
      const intro = faction['Giới Thiệu'] || faction['Mô Tả'] || 'Tạm không có giới thiệu';
      const attitude = faction['Thái Độ Với Kẻ Giao Ước'] || 'Không rõ';
      const resource = faction['Tài Nguyên Đặc Sắc'] || 'Không rõ';

      const leader = faction['Lãnh Tụ'] || 'Chưa xác định';
      const members = faction['Mục Thành Viên Quan Trọng'] || {}; 

      const baseLocObj = faction['Căn Cứ Địa'];
      let baseLocDisplay = 'Chưa xác định';

      if (baseLocObj && typeof baseLocObj === 'object') {
          if (!baseLocObj['Tên'] && !baseLocObj['Thế Giới Sở Tại']) {
              baseLocDisplay = 'Tạm chưa có thông tin';
          } else {
              const bName = baseLocObj['Tên'] || 'Vị trí ẩn';
              const bWorld = baseLocObj['Thế Giới Sở Tại'] ? ` - ${baseLocObj['Thế Giới Sở Tại']}` : '';
              const bCoord = baseLocObj['Mô Tả Tọa Độ'] ? ` [${baseLocObj['Mô Tả Tọa Độ']}]` : '';
              baseLocDisplay = `${bName}${bWorld}${bCoord}`;
          }
      } else if (typeof baseLocObj === 'string') {
          baseLocDisplay = baseLocObj;
      }

      let relationClass = 'neutral';
      if(relationValue >= 70) relationClass = 'friendly';
      else if(relationValue <= 30) relationClass = 'hostile';

      let membersHtml = '';
      if(Object.keys(members).length > 0) {
        membersHtml = Object.entries(members).map(([mId, m]) => {
          const mName = m['Tên'] || 'Chưa biết';
          const mRole = m['Chức Vụ'] || ''; 
          let mDetailHtml = '';
          const mExclude = ['UID', 'Tên', 'Chức Vụ'];
          Object.entries(m).forEach(([k, v]) => {
             if(mExclude.includes(k)) return;
             mDetailHtml += `<div style="margin-top:2px;color:#999;">${k}: ${v}</div>`;
          });

          return `
          <div class="faction-member-item-wrapper">
            <div class="faction-member-item">
              <span class="faction-member-name">${mName}</span>
              <span class="faction-member-role">${mRole}</span>
            </div>
            ${mDetailHtml ? `<div class="faction-member-detail">${mDetailHtml}</div>` : ''}
          </div>
        `}).join('');
      } else {
        membersHtml = '<div class="empty-msg" style="padding:5px;font-size:11px;">Tạm không có ghi chép</div>';
      }

      const excludeKeys = [
          'UID', 'Tên', 'Quan Hệ', 'Giá Trị Quan Hệ', 
          'Giới Thiệu', 'Mô Tả', 
          'Căn Cứ Địa', 
          'Mục Thành Viên Quan Trọng', 'Thành Viên Quan Trọng',
          'Lãnh Tụ', 
          'Thái Độ Với Kẻ Giao Ước', 
          'Tài Nguyên Đặc Sắc'
      ];

      let otherFieldsHtml = '';
      Object.entries(faction).forEach(([key, value]) => {
        if(excludeKeys.includes(key)) return;
        if(value === null || value === undefined || value === '') return;
        let displayValue = value;
        if(Array.isArray(value)) displayValue = value.join(', ');
        else if(typeof value === 'object') displayValue = JSON.stringify(value);
        otherFieldsHtml += `
          <div class="faction-detail-section">
            <div class="faction-detail-title">${key}</div>
            <div class="faction-detail-content">${displayValue}</div>
          </div>
        `;
      });

      return `
        <div class="faction-card" data-id="${id}">
          <div class="faction-card-main">
            <div class="faction-card-header">
              <span class="faction-card-name">${name}</span>
              <span class="faction-relation-badge ${relationClass}">${relation} (${relationValue})</span>
            </div>
            <div class="faction-card-info">
              <span>👑 Lãnh Tụ: ${leader}</span>
            </div>
          </div>
          <div class="faction-card-detail">
            <div class="faction-detail-section">
                <div class="faction-detail-title">🏰 Căn Cứ Địa</div>
                <div class="faction-detail-content" style="color:#e67e22;">${baseLocDisplay}</div>
            </div>
            <div class="faction-detail-section">
              <div class="faction-detail-title">📖 Giới Thiệu</div>
              <div class="faction-detail-content" style="font-style:italic;">${intro}</div>
            </div>
            <div style="display:grid; grid-template-columns: 1fr 1fr; gap:5px; margin-bottom:10px;">
                <div class="faction-detail-section" style="margin-bottom:0;">
                    <div class="faction-detail-title">👁️ Thái Độ Với Kẻ Giao Ước</div>
                    <div class="faction-detail-content">${attitude}</div>
                </div>
                <div class="faction-detail-section" style="margin-bottom:0;">
                    <div class="faction-detail-title">💎 Tài Nguyên Đặc Sắc</div>
                    <div class="faction-detail-content">${resource}</div>
                </div>
            </div>
            <div class="faction-detail-section">
              <div class="faction-detail-title">👥 Thành Viên Quan Trọng</div>
              <div class="faction-member-list">${membersHtml}</div>
            </div>
            ${otherFieldsHtml}
          </div>
        </div>
      `;
    };

    const renderQuestCard = (id, quest) => {
      const type = quest.type || 'side';
      const name = quest.name;
      const desc = quest.desc;
      const progress = quest.prog;
      const hint = quest.hint;

      if(!name || name === 'Không' || name === '') return '';
      const typeLabels = { main: 'Chính', side: 'Phụ', hidden: 'Ẩn' };
      return `
        <div class="quest-card ${type}">
          <div class="quest-header">
            <div class="quest-title-row">
              <span class="quest-type-badge ${type}">${typeLabels[type]}</span>
              <span class="quest-name">${name}</span>
            </div>
            <span class="quest-toggle">▼ Chi tiết</span>
          </div>
          <div class="quest-detail">
            <div class="quest-info-row"><span class="quest-info-label">📜 Mô Tả</span><span class="quest-info-value">${desc || 'Tạm không có mô tả'}</span></div>
            <div class="quest-info-row"><span class="quest-info-label">📊 Tiến Độ</span><span class="quest-info-value">${progress || 'Đang tiến hành'}</span></div>
            ${hint ? `<div class="quest-hint"><div class="quest-hint-label">💡 Gợi ý</div><div class="quest-hint-text">${hint}</div></div>` : ''}
          </div>
        </div>
      `;
    };

    const renderTitleCard = (id, title) => {
      const name = title['Tên'] || 'Danh hiệu chưa biết';
      const isEquipped = (title['Có Trang Bị Không'] === 'Có') || (title['Có Trang Bị'] === 'Có');
      const rank = title['Phẩm Cấp'] || title['Rank'] || ''; 
      const rankClass = getRankClass(rank); 

      const excludeKeys = ['Tên', 'Có Trang Bị', 'Có Trang Bị Không', 'Phẩm Cấp', 'Rank'];
      const detailRows = [];
      Object.entries(title).forEach(([key, value]) => {
        if(excludeKeys.includes(key)) return;
        if(value === null || value === undefined || value === '') return;
        let displayValue = value;
        if(Array.isArray(value)) displayValue = value.join(', ');
        else if(typeof value === 'object') displayValue = JSON.stringify(value);
        detailRows.push({ key, value: displayValue });
      });
      let detailHtml = detailRows.length > 0 ? detailRows.map(row => `
