            <span class="title-card-toggle">▼ Chi tiết</span>
          </div>
          <div class="title-card-detail">
            ${detailHtml}
          </div>
        </div>
      `;
    };

    const renderSpaceItem = (id, item, type) => {
      const name = item['Tên'] || 'Chưa biết';
      const excludeKeys = ['Tên'];
      const detailRows = [];
      Object.entries(item).forEach(([key, value]) => {
        if(excludeKeys.includes(key)) return;
        if(value === null || value === undefined || value === '') return;
        let displayValue = value;
        if(Array.isArray(value)) displayValue = value.join(', ');
        else if(typeof value === 'object') displayValue = JSON.stringify(value);
        detailRows.push({ key, value: displayValue });
      });
      let detailHtml = detailRows.length > 0 ? detailRows.map(row => `
        <div class="space-detail-row ${row.value.length > 20 ? 'full' : ''}">
          <span class="space-detail-label">${row.key}</span>
          <span class="space-detail-value">${row.value}</span>
        </div>
      `).join('') : '<div style="font-size:11px;color:#7f8c8d;">Tạm không có thông tin chi tiết</div>';

      let typeBadge = '';
      if(type === 'build') typeBadge = '<span class="space-type-badge build">Kiến Trúc</span>';
      else if(type === 'res') typeBadge = '<span class="space-type-badge res">Tài Nguyên</span>';
      else if(type === 'pop') typeBadge = '<span class="space-type-badge pop">Cư Dân</span>';

      return `
        <div class="space-card" data-id="${id}">
          <div class="space-card-main">
            <div class="space-card-left">
              ${typeBadge}
              <span class="space-card-name">${name}</span>
            </div>
            <span class="space-card-toggle">▼ Chi tiết</span>
          </div>
          <div class="space-card-detail">
            <div class="space-detail-grid">${detailHtml}</div>
          </div>
        </div>
      `;
    };

    function renderPagedList(containerId, dataObj, renderFunc, pageStateKey, extraArg) {
      const $container = $(containerId);
      $container.empty();

      const entries = Object.entries(dataObj || {});
      const totalPages = Math.ceil(entries.length / itemsPerPage) || 1;

      if (pageStates[pageStateKey] > totalPages) pageStates[pageStateKey] = totalPages;
      if (pageStates[pageStateKey] < 1) pageStates[pageStateKey] = 1;

      const start = (pageStates[pageStateKey] - 1) * itemsPerPage;
      const end = start + itemsPerPage;
      const pageItems = entries.slice(start, end);

      if (pageItems.length === 0) {
        $container.html('<div class="empty-msg">Tạm không có dữ liệu</div>');
      } else {
        pageItems.forEach(([id, item]) => {
          $container.append(renderFunc(id, item, extraArg));
        });
      }

      if (totalPages > 1) {
        $container.append(renderPagination(pageStateKey, pageStates[pageStateKey], totalPages));

        $(`#btn-prev-${pageStateKey}`).off('click').on('click', function() {
          if (pageStates[pageStateKey] > 1) {
            pageStates[pageStateKey]--;
            render();
          }
        });
        $(`#btn-next-${pageStateKey}`).off('click').on('click', function() {
          if (pageStates[pageStateKey] < totalPages) {
            pageStates[pageStateKey]++;
            render();
          }
        });
      }
    }

    function render() {
      const all = getAllVariables();
      const char = _.get(all, 'stat_data.Nhân Vật Chính', {});
      const base = _.get(char, 'Thông Tin Cơ Bản', {});
      const stats = _.get(char, 'Bảng Chỉ Số', {});
      const equip = _.get(char, 'Vũ Khí Và Trang Bị', {});
      const sys = _.get(all, 'stat_data.Hệ Thống Nhạc Viên.Nhiệm Vụ Và Tiến Độ Thế Giới', {});
      const subProf = _.get(char, 'Nghề Nghiệp Phụ', {});
      const charDb = _.get(all, 'stat_data.Kho Hồ Sơ Nhân Vật', {});
      const invDb = _.get(all, 'stat_data.Túi Đồ', {});
      const factionDb = _.get(all, 'stat_data.Kho Hồ Sơ Thế Lực', {});
      const titleDb = _.get(all, 'stat_data.Kho Danh Hiệu', {});
      const recordDb = _.get(all, 'stat_data.Hệ Thống Thành Tựu', {});
      const spaceDb = _.get(all, 'stat_data.Không Gian Riêng', {});

      $('#p-name').text(base['Họ Tên'] || 'Chưa biết');
      $('#p-lv').text(`Lv.${base['Cấp Độ']}`);
      $('#p-tier').text(base['Vị Giai']);
      $('#p-class').text(char['Nghề Nghiệp Chính']?.['Tên'] || 'Không Nghề Nghiệp');
      $('#p-title').text(base['Danh Hiệu'] || 'Không Danh Hiệu');
      $('#p-identity').text(base['Thân Phận'] || 'Không Thân Phận');
      $('#p-brand-lv').text(`Lạc Ấn Lv.${base['Cấp Độ Lạc Ấn'] || 0}`);

      const hpPct = Math.min(100, (stats.HP_Cur / stats.HP_Max) * 100) || 0;
      const epPct = Math.min(100, (stats.EP_Cur / stats.EP_Max) * 100) || 0;
      $('#hp-val').text(`${stats.HP_Cur}/${stats.HP_Max}`);
      $('#hp-bar').css('width', `${hpPct}%`);
      $('#ep-val').text(`${stats.EP_Cur}/${stats.EP_Max}`);
      $('#ep-bar').css('width', `${epPct}%`);

      const attrs = stats['Sáu Chỉ Số'] || {};
      ['Sức Mạnh','Nhanh Nhẹn','Thể Chất','Trí Tuệ','Mị Lực','May Mắn'].forEach(k => {
        const val = attrs[k] || 0;
        const real = attrs[`${k} Thực`] || 0;
        const $el = $(document.getElementById(`attr-${k}`));
        $el.text(real > 0 ? `${val}(Thực)` : val);
        if(real > 0) $el.addClass('real');
      });

      const derived = stats['Thuộc Tính Dẫn Xuất'] || {};
      $('#derived-patk').text(derived['Vật Lý ATK'] || 0);
      $('#derived-pdef').text(derived['Vật Lý DEF'] || 0);
      $('#derived-matk').text(derived['Pháp Thuật ATK'] || 0);
      $('#derived-mdef').text(derived['Pháp Thuật DEF'] || 0);

      $('#val-coin').text(base['Nhạc Viên Tệ'] || 0);
      $('#val-soul').text(base['Linh Hồn Tiền Tệ'] || 0);
      $('#val-sp').text(base['Điểm Kỹ Năng'] || 0);
      $('#val-ap').text(base['Điểm Thuộc Tính'] || 0);
      $('#val-adv').text(base['Điểm Tiến Giai'] || 0);
      $('#val-gold-sp').text(base['Điểm Kỹ Năng Vàng'] || 0);

      const appearance = base['Ngoại Hình'] || base['Mô Tả Ngoại Hình'] || char['Mô Tả Ngoại Hình'] || 'Tạm không có mô tả chi tiết';
      $('#appearance-text').text(appearance);

      const $equipList = $('#equip-list');
      $equipList.empty();
      const slots = [
        {k:'Vũ Khí Chính', n:'Tay Chính'}, {k:'Vũ Khí Phụ', n:'Tay Phụ'},
        {k:'Đầu', n:'Đầu'}, {k:'Áo', n:'Áo'},
        {k:'Quần', n:'Quần'}, {k:'Giày', n:'Giày'},
        {k:'Tay', n:'Tay'}, {k:'Vai', n:'Vai'},
        {k:'Dây Chuyền', n:'Dây Chuyền'}, {k:'Thắt Lưng', n:'Thắt Lưng'},
        {k:'Nhẫn 1', n:'Nhẫn T'}, {k:'Nhẫn 2', n:'Nhẫn P'},
        {k:'Trang Sức Phụ', n:'Trang Sức'}
      ];
      slots.forEach(slot => {
        const item = equip[slot.k] || {'Tên':'Chưa Trang Bị', 'Chất Lượng':'Phổ Thông'};
        const qClass = getQualityClass(item['Chất Lượng']);
        const hasItem = item['Tên'] && item['Tên'] !== 'Chưa Trang Bị' && item['Tên'] !== '';

        const detailContent = renderEquipDetailContent(item, qClass);

        const html = `
          <div class="equip-slot-wrapper">
            <div class="equip-slot" data-has="${hasItem}">
              <div class="slot-label">${slot.n}</div>
              <div class="equip-name ${qClass}">${item['Tên'] || 'Chưa Trang Bị'}</div>
            </div>
            ${hasItem ? `
              <div class="item-detail-panel">
                ${detailContent}
              </div>
            ` : ''}
          </div>
        `;
        $equipList.append(html);
      });
      $('.equip-slot[data-has="true"]').off('click').on('click', function() {
        $('.item-detail-panel').not($(this).next()).slideUp(150);
        $(this).next('.item-detail-panel').slideToggle(150);
      });

      const subProfsList = Object.values(subProf || {});
      const totalProfPages = subProfsList.length;

      if (pageStates.subProf > totalProfPages) pageStates.subProf = totalProfPages;
      if (pageStates.subProf < 1) pageStates.subProf = 1;

      const currentSubProf = subProfsList.length > 0 ? subProfsList[pageStates.subProf - 1] : {};

      const profName = currentSubProf['Tên'] || 'Chưa Có Nghề Nghiệp Phụ';
      const profDesc = currentSubProf['Mô Tả'] || 'Tạm chưa mở hệ thống Nghề Nghiệp Phụ';
      $('#prof-name-tab').text(profName);
      $('#prof-desc-full-tab').text(profDesc);

      const recipes = currentSubProf['Mục Công Thức'] || {};
      renderPagedList('#recipe-list-tab', recipes, renderRecipeItem, 'recipes');

      $('#subprof-pagination').html('');
      if (totalProfPages > 1) {
          const paginationHtml = renderSubProfPagination('subProf', pageStates.subProf, totalProfPages);
          $('#subprof-pagination').html(paginationHtml);

          $(`#btn-prev-subProf`).off('click').on('click', function() {
              if (pageStates.subProf > 1) {
                  pageStates.subProf--;
                  pageStates.recipes = 1; 
                  render();
              }
          });
          $(`#btn-next-subProf`).off('click').on('click', function() {
              if (pageStates.subProf < totalProfPages) {
                  pageStates.subProf++;
                  pageStates.recipes = 1; 
                  render();
              }
          });
      }

      $('.recipe-item').off('click').on('click', function(e) {
          e.stopPropagation();
          $(this).next('.recipe-detail').slideToggle(150);
      });

      renderPagedList('#list-skills', char['Kỹ Năng'], (id, item) => renderAbility(item, 'skill'), 'skills');
      renderPagedList('#list-talents', char['Thiên Phú'], (id, item) => renderAbility(item, 'talent'), 'talents');
      renderPagedList('#list-buffs', char['Đặc Tính Buff'], (id, item) => renderAbility(item, 'buff'), 'buffs');
      renderPagedList('#list-records', recordDb, (id, item) => renderAbility(item, 'record'), 'records');
      renderPagedList('#title-list', titleDb, renderTitleCard, 'titles');

      const allSpaceItems = {
          ...(spaceDb['Kiến Trúc'] || {}), 
          ...(spaceDb['Tài Nguyên Không Gian'] || {}), 
          ...(spaceDb['Cư Dân Không Gian'] || {})
      };

      renderPagedList('#space-list', allSpaceItems, (id, item) => {
         let type = 'build'; 
         if(spaceDb['Tài Nguyên Không Gian'] && spaceDb['Tài Nguyên Không Gian'][id]) type = 'res';
         if(spaceDb['Cư Dân Không Gian'] && spaceDb['Cư Dân Không Gian'][id]) type = 'pop';

         return renderSpaceItem(id, item, type);
      }, 'space');

      const spaceName = spaceDb['Tên Không Gian'] || 'Chưa đặt tên';
      const spaceLv = spaceDb['Cấp Độ Không Gian'] ? `Lv.${spaceDb['Cấp Độ Không Gian']}` : 'Lv.1';
      const spaceEffect = spaceDb['Hiệu Quả Không Gian'] || 'Không có hiệu quả đặc biệt';

      $('#space-main-name').text(spaceName);
      $('#space-main-lv').text(spaceLv);
      $('#space-main-effect').text(spaceEffect);

      $('.space-card-main').off('click').on('click', function() {
        const $detail = $(this).siblings('.space-card-detail');
        $('.space-card-detail').not($detail).slideUp(150);
        $detail.slideToggle(150);
      });

      $('#world-name').text(sys['Thế Giới Hiện Tại'] || 'Lĩnh Vực Chưa Biết');
      $('#world-loc').text(char['Vị Trí Và Trạng Thái']?.['Vị Trí Hiện Tại'] || 'Chưa biết');
      $('#world-time').text(char['Vị Trí Và Trạng Thái']?.['Thời Gian Hiện Tại'] || 'Thời Gian Chưa Biết');
      const worldDiff = sys['Cấp Độ Khó Thế Giới Hiện Tại'] || 'Lv.??';
      $('#world-diff').text(worldDiff);
      const envDesc = char['Vị Trí Và Trạng Thái']?.['Mô Tả Môi Trường Hiện Tại'] || 'Tạm không có mô tả môi trường';
      $('#env-desc').text(envDesc);

      const questData = {};
      if(sys['Nhiệm Vụ Chính Hiện Tại'] && sys['Nhiệm Vụ Chính Hiện Tại'] !== 'Không') {
          questData['main'] = { type: 'main', name: sys['Nhiệm Vụ Chính Hiện Tại'], desc: sys['Mô Tả Nhiệm Vụ Chính'], prog: sys['Tiến Độ Nhiệm Vụ Chính'], hint: sys['Gợi Ý Nhiệm Vụ Chính'] };
      }
      if(sys['Nhiệm Vụ Phụ Hiện Tại'] && sys['Nhiệm Vụ Phụ Hiện Tại'] !== 'Không') {
          questData['side'] = { type: 'side', name: sys['Nhiệm Vụ Phụ Hiện Tại'], desc: sys['Mô Tả Nhiệm Vụ Phụ'], prog: sys['Tiến Độ Nhiệm Vụ Phụ'], hint: sys['Gợi Ý Nhiệm Vụ Phụ'] };
      }
      if(sys['Nhiệm Vụ Ẩn Hiện Tại'] && sys['Nhiệm Vụ Ẩn Hiện Tại'] !== 'Không') {
          questData['hidden'] = { type: 'hidden', name: sys['Nhiệm Vụ Ẩn Hiện Tại'], desc: sys['Mô Tả Nhiệm Vụ Ẩn'], prog: sys['Tiến Độ Nhiệm Vụ Ẩn'], hint: sys['Gợi Ý Nhiệm Vụ Ẩn'] };
      }

      renderPagedList('#quest-list', questData, renderQuestCard, 'quests');

      $('.quest-header').off('click').on('click', function() { $(this).siblings('.quest-detail').slideToggle(150); });

      const charEntries = Object.entries(charDb).filter(([,c]) => c['Có Phải Đã Rời Đi'] !== 'Phải' && c['Trạng Thái'] !== 'Rời Khỏi');
      const charObj = Object.fromEntries(charEntries);
      renderPagedList('#char-list', charObj, renderCharCard, 'chars');
      $('.char-card-main').off('click').on('click', function() {
        const $detail = $(this).siblings('.char-card-detail');
        $('.char-card-detail').not($detail).slideUp(150);
        $detail.slideToggle(200);
      });
      $('.dashboard-container').off('click', '.char-inv-item').on('click', '.char-inv-item', function(e) {
        e.stopPropagation();
        const $detail = $(this).next('.char-inv-item-detail');
        $detail.slideToggle(150);
      });
      $('.char-detail-tab').off('click').on('click', function(e) {
        e.stopPropagation();
        const $tabs = $(this).parent();
        const $content = $tabs.siblings('.char-detail-content');
        const pane = $(this).data('pane');
        $tabs.find('.char-detail-tab').removeClass('active');
        $(this).addClass('active');
        $content.find('.char-detail-pane').removeClass('active');
        $content.find(`.char-detail-pane[data-pane="${pane}"]`).addClass('active');
      });
      $('.char-ability-main').off('click').on('click', function() {
         const $detail = $(this).siblings('.ability-detail');
         $(this).parent().parent().find('.ability-detail').not($detail).slideUp(150);
         $detail.slideToggle(150);
      });
      $('.ability-main').off('click').on('click', function() {
        const $detail = $(this).siblings('.ability-detail');
        $('.ability-detail').not($detail).slideUp(150);
        $detail.slideToggle(150);
      });
      $('.title-card-main').off('click').on('click', function() {
        const $detail = $(this).siblings('.title-card-detail');
        $('.title-card-detail').not($detail).slideUp(150);
        $detail.slideToggle(150);
      });
      $('.char-equip-item[data-has="true"]').off('click').on('click', function() {
        const $detail = $(this).siblings('.item-detail-panel');
        $('.item-detail-panel').not($(this).next()).slideUp(150);
        $(this).next('.item-detail-panel').slideToggle(150);
      });

      const followerCount = charEntries.filter(([,c]) => c['Loại Nhân Vật'] === 'Tùy Tùng' || c['Loại'] === 'Tùy Tùng').length;
      const npcCount = charEntries.filter(([,c]) => c['Loại Nhân Vật'] !== 'Tùy Tùng' && c['Loại'] !== 'Tùy Tùng').length;
      const presentCount = charEntries.length;
      $('#char-count').text(`${presentCount} người (Tùy Tùng:${followerCount} NPC:${npcCount})`);

      renderPagedList('#inv-list', invDb, renderInventoryItem, 'inv');
      $('#inv-count').text(Object.keys(invDb).length);
      $('.inv-item-main').off('click').on('click', function() {
        const $detail = $(this).siblings('.inv-item-detail');
        $('.inv-item-detail').not($detail).slideUp(150);
        $detail.slideToggle(150);
      });

      renderPagedList('#faction-list', factionDb, renderFactionCard, 'factions');
      $('#faction-count').text(Object.keys(factionDb).length);
      $('.faction-card-main').off('click').on('click', function() {
        const $detail = $(this).siblings('.faction-card-detail');
        $('.faction-card-detail').not($detail).slideUp(150);
        $detail.slideToggle(200);
      });

      $('.faction-member-item').off('click').on('click', function(e) {
          e.stopPropagation();
          $(this).next('.faction-member-detail').slideToggle(150);
      });
    }

      $('.dashboard-container').off('click', '.affix-item').on('click', '.affix-item', function(e) {
        e.stopPropagation();
        const $detail = $(this).siblings('.affix-detail');
        $detail.slideToggle(150);
      });

      $('.dashboard-container').off('click', '.char-inv-item').on('click', '.char-inv-item', function(e) {
        e.stopPropagation();
        const $detail = $(this).next('.char-inv-item-detail');
        $detail.slideToggle(150);
      });

    function filterChars(filter) {
      $('.char-card').each(function() {
        const charType = $(this).data('type');
        if(filter === 'all') $(this).show();
        else if(filter === 'follower') $(this).toggle(charType === 'Tùy Tùng');
        else if(filter === 'npc') $(this).toggle(charType !== 'Tùy Tùng');
      });
    }

    async function init() {
      await waitGlobalInitialized('Mvu');
      render();
      eventOn(Mvu.events.VARIABLE_UPDATE_ENDED, () => { render(); });
      $('.nav-btn').on('click', function() {
        $('.nav-btn').removeClass('active');
        $(this).addClass('active');
        const target = $(this).data('tab');
        $('.tab-pane').removeClass('active');
        $(`#${target}`).addClass('active');
      });
      $('.filter-btn').on('click', function() {
        $('.filter-btn').removeClass('active');
        $(this).addClass('active');
        const filter = $(this).data('filter');
        filterChars(filter);
      });
    }

    $(errorCatched(init));
  </script>
</head>
<body>
  <div class="dashboard-container">
    <div class="sidebar">
      <div class="profile-card">
        <div class="char-name" id="p-name">--</div>
        <div class="char-meta">
          <span id="p-tier">--</span>
          <span id="p-lv">--</span>
        </div>
        <div style="font-size:11px; color:#e67e22; margin-top:3px;" id="p-class">--</div>
        <div style="font-size:11px; color:#f1c40f; margin-top:3px;" id="p-title">--</div>

        <div style="margin-top:5px; padding-top:5px; border-top:1px dashed #444; display:grid; grid-template-columns:1fr 1fr; gap:5px;">
            <div style="font-size:10px; color:#bdc3c7;">🆔 <span id="p-identity">--</span></div>
            <div style="font-size:10px; color:#bdc3c7;">🔱 <span id="p-brand-lv">--</span></div>
        </div>
      </div>

      <button class="nav-btn active" data-tab="tab-main"><span>📊</span> Tổng Hợp</button>
      <button class="nav-btn" data-tab="tab-skills"><span>⚡</span> Kỹ Năng</button>
      <button class="nav-btn" data-tab="tab-talents"><span>🌟</span> Thiên Phú</button>
      <button class="nav-btn" data-tab="tab-buffs"><span>✨</span> Buff</button>
      <button class="nav-btn" data-tab="tab-subprof"><span>🛠️</span> Nghề Phụ</button>
      <button class="nav-btn" data-tab="tab-titles"><span>🏆</span> Danh Hiệu</button>
      <button class="nav-btn" data-tab="tab-records"><span>🏅</span> Thành Tựu</button>
      <button class="nav-btn" data-tab="tab-space"><span>🏰</span> Không Gian</button>
      <button class="nav-btn" data-tab="tab-chars"><span>👥</span> Nhân Vật</button>
      <button class="nav-btn" data-tab="tab-factions"><span>🏛️</span> Thế Lực</button>
      <button class="nav-btn" data-tab="tab-inv"><span>🎒</span> Túi Đồ</button>
      <button class="nav-btn" data-tab="tab-quest"><span>📜</span> Nhiệm Vụ</button>
    </div>

    <div class="main-content">
      <div id="tab-main" class="tab-pane active">
        <div class="stat-card">
          <div class="section-header">
            <span>Dấu Hiệu Sự Sống</span>
            <span style="font-size:11px; color:#bdc3c7; font-weight:normal;">
              <span style="color:#e74c3c; font-weight:bold; margin-right:8px;">Độ khó: <span id="world-diff">--</span></span>
              📍 <span id="world-loc">--</span>
              <span style="margin-left:8px; color:#7f8c8d;">🕒 <span id="world-time">--</span></span>
            </span>
          </div>
          <div class="resource-row">
            <div class="bar-container">
              <div class="bar-label"><span>HP (Sinh Mệnh)</span><span id="hp-val">--</span></div>
              <div class="progress-track"><div class="progress-fill hp-fill" id="hp-bar"></div></div>
            </div>
            <div class="bar-container">
              <div class="bar-label"><span>EP (Pháp Lực)</span><span id="ep-val">--</span></div>
              <div class="progress-track"><div class="progress-fill ep-fill" id="ep-bar"></div></div>
            </div>
          </div>
          <div class="env-desc-box" id="env-desc">--</div>
        </div>

        <div class="stat-card" style="margin-top:10px;">
          <div class="section-header">
            <span>Thuộc Tính Cơ Bản</span>
            <span style="font-size:11px; color:#e67e22; font-weight:normal;">Điểm: <span id="val-ap">0</span></span>
          </div>
          <div class="attr-grid">
            <div class="attr-box"><div class="attr-label">Sức Mạnh</div><div class="attr-value" id="attr-Sức Mạnh">0</div></div>
            <div class="attr-box"><div class="attr-label">Nhanh Nhẹn</div><div class="attr-value" id="attr-Nhanh Nhẹn">0</div></div>
            <div class="attr-box"><div class="attr-label">Thể Chất</div><div class="attr-value" id="attr-Thể Chất">0</div></div>
