        <div class="world-option" data-index="10"><div class="radio-indicator"></div><div class="world-title">【LOADING】</div><div class="world-description">...</div></div>
        <div class="world-option" data-index="11"><div class="radio-indicator"></div><div class="world-title">【LOADING】</div><div class="world-description">...</div></div>
