    <script>
      document.addEventListener('DOMContentLoaded', () => {
          try {
              const chat_message = getChatMessages(getCurrentMessageId())[0];
              const matchContent = chat_message.message;
              const missionRegex = /<mission>([\s\S]*?)<\/mission>/gi;
              const worldRegex = /【([^】]+)】[\s\n]*\[([\s\S]*?)\]/g;

              const messageToParseMatch = matchContent.match(missionRegex);
              if (!messageToParseMatch) throw new Error("Không tìm thấy thẻ <mission>.");
              const messageToParse = messageToParseMatch[0];

              const matches = [...messageToParse.matchAll(worldRegex)];
              const worldData = [];

              if (matches.length > 0) {
                  for (const match of matches) {
                      worldData.push({
                          title: match[1].trim(),
                          description: match[2].trim()
                      });
                  }
              }

              if (worldData.length === 0) throw new Error("Không thể phân tích bất kỳ dữ liệu thế giới nào từ thẻ <mission>.");

              const allWorldElements = document.querySelectorAll('.world-option');
              allWorldElements.forEach((element, index) => {
                  const titleEl = element.querySelector('.world-title');
                  const descEl = element.querySelector('.world-description');
                  if (worldData[index]) {
                      element.style.display = '';
                      titleEl.textContent = `【${worldData[index].title}】`;
                      descEl.innerHTML = escapeHtml(worldData[index].description);
                  } else {
                      element.style.display = 'none';
                  }
              });

              applyDescHighlight({ force: true });
              applyWarningStyles();

          } catch (e) {
              console.error("Đã xảy ra lỗi khi xử lý dữ liệu thế giới:", e);
              const container = document.querySelector('.options-container');
              container.innerHTML = `<p style="color: var(--accent-alert); text-align: center; font-size: 1.1rem; line-height: 1.8; font-family: monospace;"><b>DATA CORRUPTED</b><br>${e.message}</p>`;
          }

          let selectedIndex = null;
          const worldOptions = document.querySelectorAll('.world-option');
          const confirmButton = document.getElementById('executeBtn');
          const warningMessageEl = document.getElementById('selection-warning');

          worldOptions.forEach(option => {
              option.addEventListener('click', function () {
                  if (this.style.display === 'none') return;

                  if (this.dataset.abnormal === 'true') {
                      warningMessageEl.textContent = 'WARNING: SPATIAL ANOMALY DETECTED. HIGH RISK.';
                      warningMessageEl.classList.add('visible');
                  } else {
                      warningMessageEl.textContent = '';
                      warningMessageEl.classList.remove('visible');
                  }

                  worldOptions.forEach(opt => opt.classList.remove('selected'));
                  this.classList.add('selected');
                  selectedIndex = parseInt(this.getAttribute('data-index'));
              });
          });

          function applyDescHighlight({ force = true, treatDotAsPeriod = false } = {}) {
              const descEls = document.querySelectorAll('.world-description');
              descEls.forEach(el => {
                  if (!force && el.dataset.hlDone === '1') return;
                  const text = el.textContent;
                  const periodChar = treatDotAsPeriod ? /[。\.]/g : /[。]/g;
                  let res = '';
                  let i = 0;
                  while (i < text.length) {
                      const idxAscii = text.indexOf(':', i);
                      const idxCjk = text.indexOf('：', i);
                      let colon = -1;
                      if (idxAscii === -1) colon = idxCjk;
                      else if (idxCjk === -1) colon = idxAscii;
                      else colon = Math.min(idxAscii, idxCjk);
                      if (colon === -1) break;
                      const before = text.slice(0, colon);
                      const m = [...before.matchAll(periodChar)].pop();
                      const p = m ? m.index : -1;
                      if (p < i) {
                          res += text.slice(i, colon + 1);
                          i = colon + 1;
                          continue;
                      }
                      res += text.slice(i, p + 1);
                      res += '<br><span class="label-highlight">';
                      res += escapeHtml(text.slice(p + 1, colon).trim());
                      res += '</span>';
                      res += text[colon];
                      i = colon + 1;
                  }
                  res += text.slice(i);
                  el.innerHTML = res;
                  el.dataset.hlDone = '1';
              });
          }

          function escapeHtml(s) {
              if (typeof s !== 'string') return '';
              return s.replace(/[&<>"]/g, c => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;' })[c] || c);
          }

          function applyWarningStyles() {
              const visibleWorlds = Array.from(document.querySelectorAll('.world-option')).filter(el => el.style.display !== 'none');
              const worldCount = visibleWorlds.length;
              const abnormalIndices = new Set();
              if (worldCount > 2) {
                  while (abnormalIndices.size < 2) {
                      const randomIndex = Math.floor(Math.random() * worldCount);
                      abnormalIndices.add(randomIndex);
                  }
              }
              abnormalIndices.forEach(index => {
                  const abnormalWorld = visibleWorlds[index];
                  if (abnormalWorld) {
                      abnormalWorld.classList.add('warning');
                      abnormalWorld.dataset.abnormal = 'true';
                  }
              });
          }

          confirmButton.addEventListener('click', function() {
              if (selectedIndex === null) {
                  alert('ERROR: NO TARGET SELECTED.');
                  return;
              }
              confirmButton.disabled = true;
              confirmButton.textContent = 'LOCKING COORDINATES...';

              const selectedOption = document.querySelector(`.world-option[data-index="${selectedIndex}"]`);
              const isAbnormal = selectedOption.dataset.abnormal === 'true';
              const worldStatus = isAbnormal ? 'Dị thường' : 'Bình thường';
              const worldTitle = selectedOption.querySelector('.world-title').textContent.trim();
              const worldDescription = selectedOption.querySelector('.world-description').textContent.trim();

              let message = '';
              if (isAbnormal) {
                  message += 'Thế giới này tồn tại hiện tượng dị thường, đang phân tích...\n\n';
              }
              message += `## 【Thông Tin Thế Giới】
  **Tên Thế Giới:** ${worldTitle}

  ## 【Bối Cảnh Thế Giới】
  ${worldDescription}

  ## Đang tiến vào thế giới này...`.trim();

              processSelection(message, worldStatus);

              setTimeout(() => {
                  confirmButton.disabled = false;
                  confirmButton.textContent = 'INITIATE TRANSPORT';
              }, 5000);
          });

          async function processSelection(message, worldStatus) {
              console.log('Chuẩn bị cập nhật MVU và gửi lệnh...');

              try {
                  await waitGlobalInitialized('Mvu');
                  const mvu_data = Mvu.getMvuData({ type: 'message', message_id: getCurrentMessageId() });

                  if (!mvu_data.stat_data) {
                      mvu_data.stat_data = {};
                  }
                  mvu_data.stat_data.Thế_Giới_Dị_Thường = worldStatus;

                  await Mvu.replaceMvuData(mvu_data, { type: 'message', message_id: getCurrentMessageId() });
                  await Mvu.replaceMvuData(mvu_data, { type: 'chat' });
                  console.log(`MVU cập nhật thành công: stat_data.Thế_Giới_Dị_Thường = ${worldStatus}`);
              } catch(e) {
                  console.error('Cập nhật dữ liệu MVU thất bại:', e);
                  alert('Cập nhật biến trạng thái thất bại, vui lòng kiểm tra console!');
                  confirmButton.textContent = 'UPDATE FAILED';
                  return;
              }

              const command = `/send ${message}|/trigger`;
              confirmButton.textContent = 'Lệnh đã gửi';
              try {
                  if (typeof triggerSlash === 'function') {
                      triggerSlash(command);
                      console.log('Gửi thành công qua triggerSlash');
                      return;
                  }
              } catch (e) { console.warn('triggerSlash không khả dụng'); }

              try {
                  if (window.parent && window.parent !== window) {
                      window.parent.postMessage({ type: 'world_selection', content: message }, '*');
                      console.log('Gửi thành công qua postMessage');
                      return;
                  }
              } catch (e) { console.warn('postMessage không khả dụng'); }

              try {
                  navigator.clipboard.writeText(message).then(() => {
                      console.log('Lệnh đã được sao chép vào bộ nhớ tạm');
                      alert('Lệnh đã được sao chép vào bộ nhớ tạm! Vui lòng dán và gửi thủ công.');
                      confirmButton.textContent = 'Đã sao chép';
                  });
              } catch (e) {
                  console.error('Tất cả các phương thức gửi đều thất bại:', e);
                  alert('Gửi tự động thất bại, vui lòng sao chép lệnh thủ công.');
                  confirmButton.textContent = 'Gửi thất bại';
              }
          }
      });
    </script>
  </body>
  </html>
