    .pagination-bar{display:flex;justify-content:center;align-items:center;gap:8px;margin-top:10px;margin-bottom:2px;flex-wrap:wrap;user-select:none;}
    .pagination-bar.hidden{display:none}
    .page-btn{padding:8px 12px;background:transparent;border:1px solid var(--border-color);color:var(--text-color);font-family:var(--font-display);font-size:.85rem;cursor:pointer;transition:all .2s ease;border-radius:6px;}
    .page-btn:hover{background:var(--accent-glow);color:#fff}
    .page-btn:disabled{opacity:.35;cursor:not-allowed}
    .page-btn.active{background:var(--accent-color);color:var(--bg-dark);border-color:var(--accent-color);font-weight:700;box-shadow:0 0 10px var(--accent-glow);}
    .page-indicator{font-family:var(--font-display);color:var(--accent-color);font-size:.85rem;padding:6px 8px;border:1px dashed var(--border-color);border-radius:6px;background:rgba(0,240,255,0.04);}
  </style>
</head>
<body>
  <div class="terminal-container">
    <div class="corner-bottom-left"><div class="corner-bottom-right"></div></div>
    <div class="header">Thiết Bị Đổi Thưởng</div>

    <div id="categoryTabs" class="category-tabs"></div>
    <div id="itemsContainer" class="items-container">
      <p style="text-align: center;">Đang kết nối dữ liệu Luân Hồi Nhạc Viên...</p>
    </div>
    <div id="paginationBar" class="pagination-bar hidden"></div>
    <button id="executeBtn" class="execute-button" disabled>Vui lòng chọn mục mua/bán</button>
  </div>

<script>
  // =================================================================
  // CẤU HÌNH TƯƠNG THÍCH ZOD VIỆT HÓA
  // =================================================================

  // Các thuộc tính cốt lõi (Tên hiển thị)
  const CORE_ATTRIBUTES = ["Sức Mạnh", "Thể Chất", "Nhanh Nhẹn", "Trí Tuệ", "Tinh Thần", "Mị Lực"];
  // Map Emoji
  const ATTR_EMOJIS = { "Sức Mạnh": "💪", "Thể Chất": "❤️", "Nhanh Nhẹn": "⚡", "Trí Tuệ": "🧠", "Tinh Thần": "✨", "Mị Lực": "👑" };

  const Utils = {
    valOf: (v, def = 'N/A') => {
      if (v === null || v === undefined) return def;
      if (Array.isArray(v) && v.length > 0) return v[0] ?? def;
      return v ?? def;
    },
    listOf: (v) => Array.isArray(v) ? v : (v ? [v] : [])
  };

  (async () => {
    let fullMessageText;
    let initialCoins = 0;
    const baseCurrency = 'Nhạc Viên Tệ';
    let marketData = {};

    let selectedItems = []; 
    let sellItems = [];     

    let lastCategory = null;
    let currentCategory = null;
    let currentPage = 1;

    const powerTiers = {
      'F':{min:0,max:29,cost:25},'E':{min:30,max:99,cost:30},'D':{min:100,max:299,cost:40},
      'C':{min:300,max:999,cost:50},'B':{min:1000,max:2999,cost:75},'A':{min:3000,max:9999,cost:100},
      'S':{min:10000,max:29999,cost:150},'SS':{min:30000,max:99999,cost:200},'SSS':{min:100000,max:Infinity,cost:300}
    };
    const tierOrder = ['F','E','D','C','B','A','S','SS','SSS'];
    const bloodlineTierNames = { 'F':'Phổ Thông','E':'Kiên Cường','D':'Tinh Nhuệ','C':'Siêu Phàm','B':'Anh Hùng','A':'Vương Giả','S':'Thánh Vực','SS':'Thần Thoại','SSS':'Chí Cao' };

    let allBloodlines = [];
    let canAddPoints = false;
    let selectedBloodlineIndex = 0;
    let initialBloodlineBonuses = {};
    let initialBonusSum = 0;
    let panelBaseAttributes = {};
    let attributePoints = {};

    const tabsContainer = document.getElementById('categoryTabs');
    const itemsContainer = document.getElementById('itemsContainer');
    const paginationBar = document.getElementById('paginationBar');
    const executeBtn = document.getElementById('executeBtn');

    const getPageSize = () => 6;

    const resetPageIfCategoryChanged = (category) => {
      currentCategory = category;
      if (category !== lastCategory) {
        currentPage = 1;
        lastCategory = category;
      }
    };

    const renderPagination = (totalItems, category) => {
      if (category === 'Cộng Điểm Thuộc Tính') {
        paginationBar.classList.add('hidden');
        paginationBar.innerHTML = '';
        paginationBar.dataset.totalPages = '1';
        return;
      }
      const pageSize = getPageSize();
      const totalPages = Math.max(1, Math.ceil(totalItems / pageSize));
      paginationBar.dataset.totalPages = String(totalPages);

      if (totalPages <= 1) {
        paginationBar.classList.add('hidden');
        paginationBar.innerHTML = '';
        return;
      }

      currentPage = Math.max(1, Math.min(currentPage, totalPages));
      paginationBar.classList.remove('hidden');

      let start = Math.max(1, currentPage - 2);
      let end = Math.min(totalPages, start + 4);
      start = Math.max(1, end - 4);

      const pageBtns = [];
      pageBtns.push(`<button class="page-btn" data-act="prev" ${currentPage === 1 ? 'disabled' : ''}>Trang Trước</button>`);
      for (let p = start; p <= end; p++) {
        pageBtns.push(`<button class="page-btn ${p === currentPage ? 'active' : ''}" data-act="page" data-page="${p}">${p}</button>`);
      }
      pageBtns.push(`<button class="page-btn" data-act="next" ${currentPage === totalPages ? 'disabled' : ''}>Trang Sau</button>`);
      pageBtns.push(`<button class="page-btn" data-act="flip">Lật Trang</button>`);
      pageBtns.push(`<span class="page-indicator">Trang ${currentPage} / ${totalPages}</span>`);
      paginationBar.innerHTML = pageBtns.join('');
    };

    paginationBar.addEventListener('click', (e) => {
      const btn = e.target.closest('button');
      if (!btn) return;

      const act = btn.dataset.act;
      const totalPages = parseInt(paginationBar.dataset.totalPages || '1', 10) || 1;

      if (act === 'prev') currentPage = Math.max(1, currentPage - 1);
      else if (act === 'next') currentPage = Math.min(totalPages, currentPage + 1);
      else if (act === 'page') currentPage = parseInt(btn.dataset.page, 10) || 1;
      else if (act === 'flip') currentPage = (currentPage % totalPages) + 1;

      renderItems(currentCategory);
    });

    function isSellCategory(categoryName) {
      return /(Kho Vật Phẩm|Túi Đồ|Balo)/.test(String(categoryName || ''));
    }

    function isPropLikeCategory(categoryName) {
      return /(Đạo Cụ|Tiếp Tế|Nguyên Liệu|Tài Nguyên|Hồi Phục|Cường Hóa|Tiêu Hao)/.test(String(categoryName || ''));
    }

    function getMaxQtyFromItem(item) {
      const a = item?.attributes || {};
      const keys = ['Số Lượng Sở Hữu','Số Lượng','count','qty'];
      for (const k of keys) {
        const v = a[k];
        const n = parseInt(String(v ?? '').replace(/,/g,''), 10);
        if (!Number.isNaN(n) && n > 0) return n;
      }
      return Infinity;
    }

    const parseBonusString = (bonusStr) => {
      const bonuses = Object.fromEntries(CORE_ATTRIBUTES.map(attr => [attr, 0]));
      if (!bonusStr) return bonuses;
      // Map các biến thể tên gọi
      const attrMappings = { 'Sức Mạnh':['Sức Mạnh'], 'Thể Chất':['Thể Chất'], 'Nhanh Nhẹn':['Nhanh Nhẹn'], 'Trí Tuệ':['Trí Tuệ'], 'Tinh Thần':['Tinh Thần'], 'Mị Lực':['Mị Lực'] };
      const reverseMapping = {};
      Object.entries(attrMappings).forEach(([main, aliases]) => aliases.forEach(a => reverseMapping[a.toLowerCase()] = main));

      if (typeof bonusStr === 'string') {
        bonusStr.split(',').forEach(part => {
          const match = part.match(/(\S+)\s*\+(\d+)/);
          if (match) {
             const key = match[1].trim();
             // Xử lý đặc biệt nếu Zod lưu là "May Mắn" nhưng hiển thị là "Tinh Thần" (hoặc ngược lại)
             const stdKey = reverseMapping[key.toLowerCase()] || key;
             if(bonuses[stdKey] !== undefined) bonuses[stdKey] = parseInt(match[2], 10);
          }
        });
      } else if (typeof bonusStr === 'object') {
        Object.entries(bonusStr).forEach(([key, value]) => {
          if (CORE_ATTRIBUTES.includes(key)) bonuses[key] = parseInt(value, 10) || 0;
        });
      }
      return bonuses;
    };

    const getRatingForSum = (sum) => { for (const tier of tierOrder) if (sum <= powerTiers[tier].max) return tier; return 'SSS'; };

    const calculateDynamicCost = (baseSum, pointsToAdd) => {
      if (pointsToAdd <= 0) return 0;
      let totalCost = 0, remainingPoints = pointsToAdd, currentSum = baseSum;
      while(remainingPoints > 0) {
        const currentTier = getRatingForSum(currentSum);
        const costPerPoint = powerTiers[currentTier].cost;
        const pointsToNextTier = (powerTiers[currentTier].max - currentSum) + 1;
        const pointsInThisTier = Math.min(remainingPoints, pointsToNextTier);
        if(pointsInThisTier <= 0) { currentSum++; continue; }
        totalCost += pointsInThisTier * costPerPoint;
        currentSum += pointsInThisTier;
        remainingPoints -= pointsInThisTier;
      }
      return totalCost;
    };

    // Hàm load dữ liệu Thiên Phú (được coi là Huyết Thống trong Zod này)
    function loadBloodlineData(charData) {
      try {
        // Zod của bạn không có key "Huyết Thống" mà dùng "Thiên Phú"
        const rawTalents = charData['Thiên Phú'];
        if (!rawTalents || typeof rawTalents !== 'object') return;

        const bloodlineList = Object.keys(rawTalents).map(k => ({ key: k, data: rawTalents[k] || {} }));

        allBloodlines = bloodlineList.map(b => {
          const name = b.data['Tên'] || b.key;
          // Zod dùng key "Cộng Thuộc Tính" (String)
          const bonuses = parseBonusString(b.data['Cộng Thuộc Tính']);
          if (name) return { key: b.key, name, data: b.data, bonuses };
          return null;
        }).filter(Boolean);

        canAddPoints = allBloodlines.length > 0;
      } catch (e) {
        console.error('Lỗi tải dữ liệu Thiên Phú/Huyết Thống:', e);
        canAddPoints = false;
      }
    }

    function updateCurrentBloodlineData() {
      if (!canAddPoints) return false;
      try {
        selectedBloodlineIndex = Math.max(0, Math.min(selectedBloodlineIndex, allBloodlines.length - 1));
        const currentBloodline = allBloodlines[selectedBloodlineIndex];
        if (!currentBloodline) throw new Error('Không tìm thấy dữ liệu');

        initialBloodlineBonuses = currentBloodline.bonuses || {};
        initialBonusSum = Object.values(initialBloodlineBonuses).reduce((s, b) => s + b, 0);
        return true;
      } catch (e) {
        console.error('Lỗi cập nhật huyết thống:', e);
        return false;
      }
    }

    function parseMarketData(text) {
      const market = {};
      if (!text) return market;

      const normalizeKey = (k) => String(k || '').trim();

      // Regex hỗ trợ cả Tiếng Việt và Tiếng Anh/Trung cho chắc chắn
      const isPriceKey = (k) => /^(Giá|Price|价格)/i.test(String(k || '').trim());
      const isQualityKey = (k) => /^(Phẩm Chất|Cấp Bậc|Xếp Hạng|Quality|Rating)/i.test(String(k || '').trim());

      const parsePriceValue = (raw) => {
        const out = { price: 0, currency: baseCurrency, priceText: '' };
        if (raw === null || raw === undefined) return out;
        const s = String(raw).trim();
        out.priceText = s;
        const m = s.match(/^\s*([\d,]+)/);
        if (m) out.price = parseInt(m[1].replace(/,/g, ''), 10) || 0;
        out.currency = baseCurrency;
        return out;
      };

      try {
        const categoryBlocks = text.split(/---\s*/).filter(block => block.trim());

        categoryBlocks.forEach(block => {
          const titleRegex = /^\s*【([^】]+)】/gm;
          const allMatches = [...block.matchAll(titleRegex)];
          if (allMatches.length < 2) return;

          const categoryName = allMatches[0][1].trim();
          const itemMatches = allMatches.slice(1);
          const items = [];

          itemMatches.forEach((currentMatch, index) => {
            const item = {
              name: currentMatch[1].trim(),
              attributes: {},
              price: undefined,
              currency: baseCurrency,
              priceText: undefined,
              quality: undefined,
              rating: undefined,
            };

            const dataStart = currentMatch.index + currentMatch[0].length;
            const dataEnd = (index + 1 < itemMatches.length) ? itemMatches[index + 1].index : block.length;
            const dataBlock = block.substring(dataStart, dataEnd).trim();

            // Tìm nội dung trong ngoặc vuông []
            const bracketStart = dataBlock.indexOf('[');
            if (bracketStart === -1) return;

            let bracketCount = 1;
            let bracketEnd = bracketStart + 1;
            while (bracketEnd < dataBlock.length && bracketCount > 0) {
              if (dataBlock[bracketEnd] === '[') bracketCount++;
              else if (dataBlock[bracketEnd] === ']') bracketCount--;
              bracketEnd++;
            }
            if (bracketCount !== 0) return;

            const content = dataBlock.substring(bracketStart + 1, bracketEnd - 1);

            content.split('|').map(part => part.trim()).forEach(part => {
              part.split(',').map(p => p.trim()).forEach(p => {
                if (!p) return;

                const sepIdx = p.search(/[:：]/);
                if (sepIdx > -1) {
                  const key = normalizeKey(p.substring(0, sepIdx));
                  const value = p.substring(sepIdx + 1).trim();

                  if (isPriceKey(key)) {
                    const pv = parsePriceValue(value);
                    item.price = pv.price;
                    item.currency = baseCurrency;
                    item.priceText = pv.priceText;
                    return;
                  }

                  if (isQualityKey(key)) {
                    if (key === 'Xếp Hạng') item.rating = value;
                    else item.quality = value;
                    return;
                  }

                  item.attributes[key] = value;
                  return;
                }

                const priceMatch = p.match(/^([\d,]+)\s*(Nhạc Viên Tệ|乐园币)$/i);
                if (priceMatch) {
                  item.price = parseInt(priceMatch[1].replace(/,/g, ''), 10) || 0;
                  item.currency = baseCurrency;
                  item.priceText = `${priceMatch[1]} Nhạc Viên Tệ`;
                  return;
                }
              });
            });

            if (!item.rating && item.quality) item.rating = item.quality;
            if (!item.rating) item.rating = '—';

            const allowNoRating = isSellCategory(categoryName) || isPropLikeCategory(categoryName);
            if (typeof item.price === 'number' && (allowNoRating || item.rating)) {
              if (!item.priceText) item.priceText = `${item.price} Nhạc Viên Tệ`;
              items.push(item);
            }
          });

          if (items.length > 0) market[categoryName] = items;
        });
      } catch (e) {
        console.error('Lỗi phân tích market:', e);
      }

      return market;
    }

    function renderTabs() {
      tabsContainer.innerHTML = '';
      const categories = [...Object.keys(marketData)];
      if (canAddPoints) categories.splice(1, 0, 'Cộng Điểm Thuộc Tính');

      categories.forEach((c, i) => {
        const t = document.createElement('button');
        t.className = `tab-button ${i === 0 ? 'active' : ''}`;
        t.textContent = c;
        t.addEventListener('click', () => {
          tabsContainer.querySelector('.active')?.classList.remove('active');
          t.classList.add('active');
          renderItems(c);
        });
        tabsContainer.appendChild(t);
      });

      if (categories.length > 0) renderItems(categories[0]);
    }

    function updateBuyQuantity(itemName, category, change, isAbsolute = false) {
      let item = selectedItems.find(si => si.name === itemName && si.category === category);
      const marketItem = (marketData[category] || []).find(mi => mi.name === itemName);
      if (!marketItem) return;

      if (!item) {
        if ((isAbsolute && change > 0) || (!isAbsolute && change > 0)) {
          item = { ...marketItem, category, quantity: isAbsolute ? change : Math.max(0, change) };
          selectedItems.push(item);
        }
      } else {
        if (isAbsolute) item.quantity = Math.max(0, change);
        else item.quantity = Math.max(0, (item.quantity || 0) + change);
        if (item.quantity <= 0) selectedItems = selectedItems.filter(si => !(si.name === itemName && si.category === category));
      }
      updatePriceAndButton();
    }

    function updateSellMarketQuantity(itemName, category, change, isAbsolute = false) {
      let item = sellItems.find(si => si.name === itemName && si.category === category);
      const marketItem = (marketData[category] || []).find(mi => mi.name === itemName);
      if (!marketItem) return;

      const maxQty = getMaxQtyFromItem(marketItem);
      const clamp = (n) => {
        const v = Math.max(0, parseInt(n, 10) || 0);
        return Number.isFinite(maxQty) ? Math.min(maxQty, v) : v;
      };

      if (!item) {
        const qty = clamp(isAbsolute ? change : Math.max(0, change));
        if (qty > 0) sellItems.push({ ...marketItem, category, quantity: qty });
      } else {
        item.quantity = clamp(isAbsolute ? change : (item.quantity || 0) + change);
        if (item.quantity <= 0) sellItems = sellItems.filter(si => !(si.name === itemName && si.category === category));
      }

      updatePriceAndButton();
    }

    function renderItems(category) {
      resetPageIfCategoryChanged(category);
      itemsContainer.innerHTML = '';

      if (category === 'Cộng Điểm Thuộc Tính') {
        paginationBar.classList.add('hidden');
        paginationBar.innerHTML = '';
        paginationBar.dataset.totalPages = '1';

        if (!canAddPoints) { itemsContainer.innerHTML = '<div class="error-message">Không tìm thấy Thiên Phú để nâng cấp</div>'; return; }

        try {
          if (!updateCurrentBloodlineData()) throw new Error('Dữ liệu Thiên Phú lỗi');
          itemsContainer.className = 'items-container attributes-mode';
          const currentBloodline = allBloodlines[selectedBloodlineIndex];

          itemsContainer.innerHTML = `
            <div class="mobile-enhancement-panel">
              <div class="enhancement-header-mobile">
                <div class="bloodline-selector">
                  <button id="prevBloodlineBtn" class="selector-btn" ${allBloodlines.length <= 1 ? 'disabled' : ''}>ᐊ</button>
                  <div id="bloodline-title" title="${currentBloodline.name}">${currentBloodline.name}</div>
                  <button id="nextBloodlineBtn" class="selector-btn" ${allBloodlines.length <= 1 ? 'disabled' : ''}>ᐅ</button>
                </div>
                <div class="stats-row">
                  <div class="stat-box"><div class="stat-label">Tổng Cộng Điểm</div><div class="stat-value" id="total-points">0</div></div>
                  <div class="stat-box"><div class="stat-label">Tiêu Hao</div><div class="stat-value cost" id="total-cost">0</div></div>
                </div>
              </div>
              <div class="attributes-list" id="attributes-list"></div>
              <div class="evolution-section">
                <div class="evolution-title">Tiến Độ Tiến Hóa</div>
                <div class="evolution-bar">
                  <div class="evolution-fill" id="evolution-fill" style="width: 0%"><span class="evolution-text" id="evolution-percent">0%</span></div>
                </div>
                <div class="evolution-info">
                  <div class="evolution-current" id="evolution-current"></div>
                  <div class="evolution-next" id="evolution-next"></div>
                </div>
              </div>
            </div>
          `;

          const attrList = document.getElementById('attributes-list');
          CORE_ATTRIBUTES.forEach(attr => {
            const panelValue = panelBaseAttributes[attr] || 0;
            const bonusValue = initialBloodlineBonuses[attr] || 0;
            const card = document.createElement('div');
            card.className = 'attr-card';
            card.innerHTML = `
              <div class="attr-header">
                <div class="attr-name-icon">
                  <span class="attr-emoji">${ATTR_EMOJIS[attr] || '❓'}</span>
                  <span class="attr-name-mobile">${attr}</span>
                </div>
                <div class="attr-values">
                  <div class="attr-base">Hiện Tại: ${panelValue} (Thiên Phú +${bonusValue})</div>
                  <div class="attr-total" id="total-${attr}">${panelValue}</div>
                </div>
              </div>
              <div class="attr-controls-mobile">
                <button class="attr-btn-mobile minus" data-attr="${attr}">−</button>
                <input type="number" inputmode="numeric" class="attr-input-mobile" id="input-${attr}" data-attr="${attr}" value="${attributePoints[attr] || 0}" min="0">
                <button class="attr-btn-mobile plus" data-attr="${attr}">+</button>
              </div>
            `;
            attrList.appendChild(card);
          });

          attrList.querySelectorAll('.attr-btn-mobile, .attr-input-mobile').forEach(el => {
            const attr = el.dataset.attr;
            const input = document.getElementById(`input-${attr}`);
            const update = (newValue) => {
              const value = Math.max(0, parseInt(newValue, 10) || 0);
              input.value = value;
              attributePoints[attr] = value;
              updatePriceAndButton();
            };
            if (el.tagName === 'BUTTON') {
              el.addEventListener('click', e => {
                e.preventDefault();
                update(parseInt(input.value, 10) + (el.classList.contains('plus') ? 1 : -1));
              });
            } else {
              el.addEventListener('input', e => update(e.target.value));
            }
          });

          // Sự kiện vuốt đổi huyết thống (nếu có nhiều cái)
          const panel = document.querySelector('.mobile-enhancement-panel');
          if (panel && 'ontouchstart' in window) {
            let touchStartX = 0;
            panel.addEventListener('touchstart', e => touchStartX = e.changedTouches[0].screenX, { passive: true });
            panel.addEventListener('touchend', e => {
              const diff = touchStartX - e.changedTouches[0].screenX;
              if (Math.abs(diff) > 50 && allBloodlines.length > 1) {
                selectedBloodlineIndex = (selectedBloodlineIndex + (diff > 0 ? 1 : -1) + allBloodlines.length) % allBloodlines.length;
                attributePoints = Object.fromEntries(CORE_ATTRIBUTES.map(a => [a, 0]));
                renderItems('Cộng Điểm Thuộc Tính');
              }
            });
          }
        } catch (e) {
          console.error('Render thuộc tính lỗi:', e);
          itemsContainer.innerHTML = `<div class="error-message">Lỗi giao diện: ${e.message}</div>`;
        }

        updatePriceAndButton();
        return;
      }

      // Render vật phẩm chợ
      itemsContainer.className = 'items-container';
      const allItems = marketData[category] || [];
      const isSell = isSellCategory(category);
      const propLike = isPropLikeCategory(category);

      const pageSize = getPageSize();
      const totalItems = allItems.length;
      const totalPages = Math.max(1, Math.ceil(totalItems / pageSize));
      currentPage = Math.max(1, Math.min(currentPage, totalPages));
      const startIdx = (currentPage - 1) * pageSize;
      const items = allItems.slice(startIdx, startIdx + pageSize);

      if (items.length === 0) {
        itemsContainer.innerHTML = '<p style="text-align:center;color:#888;padding:20px 0;">Không có hàng hóa</p>';
      } else {
        items.forEach(item => {
          const card = document.createElement('div');
          card.className = 'item-card';
          card.dataset.itemName = item.name;
          card.dataset.itemCategory = category;
          card.dataset.itemType = isSell ? 'sell' : 'shop';

          const attributesHtml = Object.entries(item.attributes || {}).map(([k, v]) => `<p><strong>${k}:</strong> ${v}</p>`).join('');

          let footerHtml = '';
          if (propLike) {
            const maxQty = getMaxQtyFromItem(item);
            const maxAttr = Number.isFinite(maxQty) ? `max="${maxQty}"` : '';
            footerHtml = `
              <div class="item-price" data-currency="${baseCurrency}">${item.price}</div>
              <div class="quantity-controls">
                <button class="quantity-btn minus" data-name="${item.name}">-</button>
                <input type="number" class="quantity-input" value="0" min="0" ${maxAttr} data-name="${item.name}">
                <button class="quantity-btn plus" data-name="${item.name}">+</button>
              </div>
            `;
          } else {
            footerHtml = `
              <div class="item-price" data-currency="${baseCurrency}">${item.price}</div>
              <div class="item-rating" data-rating="${item.rating || '—'}">${item.rating || '—'}</div>
            `;
          }

          card.innerHTML = `
            <div class="item-name">${item.name}</div>
            <div class="item-attributes">${attributesHtml}</div>
            <div class="item-footer">${footerHtml}</div>
          `;

          if (!propLike) {
            card.addEventListener('click', () => {
              if (isSell) {
                const idx = sellItems.findIndex(si => si.name === item.name && si.category === category);
                if (idx > -1) sellItems.splice(idx, 1);
                else sellItems.push({ ...item, category, quantity: 1 });
              } else {
                const idx = selectedItems.findIndex(si => si.name === item.name && si.category === category);
                if (idx > -1) selectedItems.splice(idx, 1);
                else selectedItems.push({ ...item, category, quantity: 1 });
              }
              updatePriceAndButton();
            });
          }

          itemsContainer.appendChild(card);
        });

        // Event listeners cho nút số lượng
        if (propLike) {
          itemsContainer.querySelectorAll('.quantity-btn').forEach(btn => {
            btn.addEventListener('click', e => {
              e.stopPropagation();
              const itemName = e.target.dataset.name;
              const delta = e.target.classList.contains('plus') ? 1 : -1;
              const current = isSell
                ? (sellItems.find(si => si.name === itemName && si.category === category)?.quantity || 0)
                : (selectedItems.find(si => si.name === itemName && si.category === category)?.quantity || 0);

              const next = Math.max(0, current + delta);
              if (isSell) updateSellMarketQuantity(itemName, category, next, true);
              else updateBuyQuantity(itemName, category, next, true);
            });
          });

          itemsContainer.querySelectorAll('.quantity-input').forEach(input => {
            input.addEventListener('input', e => {
              e.stopPropagation();
              const itemName = e.target.dataset.name;
              const value = parseInt(e.target.value, 10) || 0;
              if (isSell) updateSellMarketQuantity(itemName, category, value, true);
              else updateBuyQuantity(itemName, category, value, true);
            });
          });

          itemsContainer.querySelectorAll('.item-card').forEach(card => {
             card.addEventListener('click', () => {
               // Logic chọn nhanh cho item số lượng: click vào card = toggle 0/1 nếu chưa chọn
               const name = card.dataset.itemName;
               const current = isSell
                ? (sellItems.find(si => si.name === name && si.category === category)?.quantity || 0)
                : (selectedItems.find(si => si.name === name && si.category === category)?.quantity || 0);
               const next = current > 0 ? 0 : 1; // Toggle
               if (isSell) updateSellMarketQuantity(name, category, next, true);
               else updateBuyQuantity(name, category, next, true);
             });
          });
        }
      }

      renderPagination(totalItems, category);
      updatePriceAndButton();
    }

    function updatePriceAndButton() {
      try {
        // Cập nhật giao diện thẻ được chọn
        document.querySelectorAll('.item-card').forEach(card => {
          const type = card.dataset.itemType || 'shop';
          const name = card.dataset.itemName;
          const category = card.dataset.itemCategory;
          const selected = (type === 'sell')
            ? sellItems.find(si => si.name === name && si.category === category)
            : selectedItems.find(si => si.name === name && si.category === category);
          card.classList.toggle('selected', !!selected);
          const input = card.querySelector('.quantity-input');
          if (input) input.value = selected ? (selected.quantity || 0) : 0;
        });

        const itemsTotalPrice = selectedItems.reduce((sum, item) => sum + (item.price * (item.quantity || 1)), 0);
        const sellTotalPrice  = sellItems.reduce((sum, item) => sum + (item.price * (item.quantity || 1)), 0);

        const totalAttrPointsToAdd = Object.values(attributePoints).reduce((sum, pts) => sum + pts, 0);
        const attrTotalPrice = (canAddPoints && totalAttrPointsToAdd > 0) ? calculateDynamicCost(initialBonusSum, totalAttrPointsToAdd) : 0;

        // Cập nhật UI phần cộng điểm
        if (document.querySelector('.mobile-enhancement-panel')) {
          CORE_ATTRIBUTES.forEach(attr => {
            const totalEl = document.getElementById(`total-${attr}`);
            const baseEl = totalEl ? totalEl.previousElementSibling : null;
            if (totalEl && baseEl) {
              const panelValue = panelBaseAttributes[attr] || 0;
              const newPoints = attributePoints[attr] || 0;
              totalEl.textContent = panelValue + newPoints;
              totalEl.classList.toggle('enhanced', newPoints > 0);
              const initialBonus = initialBloodlineBonuses[attr] || 0;
              baseEl.textContent = `Hiện Tại: ${panelValue} (Thiên Phú +${initialBonus + newPoints})`;
            }
          });

          const newBloodlineBonusSum = initialBonusSum + totalAttrPointsToAdd;
          const newTier = getRatingForSum(newBloodlineBonusSum);
          const titleEl = document.getElementById('bloodline-title');
          const currentBloodlineName = allBloodlines[selectedBloodlineIndex].name;
          const evolvedBloodlineName = (bloodlineTierNames[newTier] || '') + currentBloodlineName;

          document.getElementById('total-points').textContent = totalAttrPointsToAdd;
          document.getElementById('total-cost').textContent = attrTotalPrice;

          if (newTier !== getRatingForSum(initialBonusSum)) {
            const isMobile = window.innerWidth < 768;
            titleEl.innerHTML = isMobile ? `<span class="evolution-tag">[Tiến Hóa!]</span> ${evolvedBloodlineName}` : `${evolvedBloodlineName} [Tiến Hóa!]`;
          } else {
            titleEl.textContent = currentBloodlineName;
          }

          const tierInfo = powerTiers[newTier];
          const progressInTier = newBloodlineBonusSum - tierInfo.min;
          const tierSize = tierInfo.max - tierInfo.min;
          const progressPercent = tierSize === Infinity ? 100 : Math.min(100, (progressInTier / tierSize) * 100);
          document.getElementById('evolution-fill').style.width = `${progressPercent}%`;
          document.getElementById('evolution-percent').textContent = `${Math.round(progressPercent)}%`;
          document.getElementById('evolution-current').textContent = `Cấp ${newTier} (${newBloodlineBonusSum})`;
          document.getElementById('evolution-next').textContent = tierInfo.max === Infinity ? 'Max' : `Next: ${tierInfo.max + 1}`;
        }

        const grandTotal = itemsTotalPrice + attrTotalPrice - sellTotalPrice;
        const hasAnySelection = (selectedItems.length > 0) || (sellItems.length > 0) || (Object.values(attributePoints).reduce((s,p)=>s+p,0) > 0);

        if (!hasAnySelection) {
          executeBtn.disabled = true;
          executeBtn.textContent = 'Vui lòng chọn mục mua/bán';
          return;
        }

        executeBtn.disabled = false;
        const isMobile = window.innerWidth < 768;
        executeBtn.textContent = isMobile ? `Thanh Toán (${grandTotal})` : `Thanh Toán (Thực tế: ${grandTotal} Nhạc Viên Tệ)`;
      } catch (e) { console.error('Lỗi update UI:', e); }
    }

    function sendData(data) {
      console.log('Gửi lệnh:', data);
      executeBtn.textContent = 'Đang xử lý...';
      try {
        if (typeof triggerSlash === 'function') {
          triggerSlash(`/send ${data}|/trigger`);
        } else {
          navigator.clipboard.writeText(data).then(() => alert('Lệnh đã copy!'));
        }
        executeBtn.textContent = 'Đã gửi';
      } catch (e) {
        executeBtn.textContent = 'Lỗi gửi';
      }
      setTimeout(() => { executeBtn.disabled = false; updatePriceAndButton(); }, 4000);
    }

    try {
      const msgs = await getChatMessages(getCurrentMessageId());
      fullMessageText = msgs?.[0]?.message;

      // === PHẦN QUAN TRỌNG: ĐỌC DỮ LIỆU TỪ ZOD VIỆT HÓA ===
      // Cấu trúc Zod: stat_data["Nhân Vật Chính"]
      const charData = msgs?.[0]?.data?.stat_data?.["Nhân Vật Chính"] || {};
      const basicInfo = charData["Thông Tin Cơ Bản"] || {};
      const stats = charData["Bảng Chỉ Số"]?.["Sáu Chỉ Số"] || {};

      // Load tiền
      initialCoins = parseInt(String(Utils.valOf(basicInfo["Nhạc Viên Tệ"], '0')).replace(/,/g, '')) || 0;

      // Load thuộc tính cơ bản
      // Lưu ý: Zod của bạn có "May Mắn" nhưng không có "Tinh Thần".
      // Code này sẽ tự động điền 0 cho Tinh Thần nếu không tìm thấy.
      panelBaseAttributes = Object.fromEntries(
        CORE_ATTRIBUTES.map(attr => {
            // Thử map tên (VD: Tinh Thần -> May Mắn nếu cần, hiện tại giữ nguyên key)
            // Nếu bạn muốn hiển thị May Mắn thay vì Tinh Thần, hãy đổi CORE_ATTRIBUTES ở trên.
            return [attr, parseInt(String(Utils.valOf(stats[attr], '0')).replace(/,/g, '')) || 0]
        })
      );
      attributePoints = Object.fromEntries(CORE_ATTRIBUTES.map(attr => [attr, 0]));

      // Load Huyết Thống (thực chất là lấy từ Thiên Phú)
      loadBloodlineData(charData);

      const marketMatch = fullMessageText?.match(/<market>([\s\S]*?)<\/market>/);
      marketData = parseMarketData(marketMatch?.[1]);

      itemsContainer.addEventListener('click', (e) => {
        let target = e.target.closest('.selector-btn');
        if (target && allBloodlines.length > 1) {
          selectedBloodlineIndex = (selectedBloodlineIndex + (target.id === 'nextBloodlineBtn' ? 1 : -1) + allBloodlines.length) % allBloodlines.length;
          attributePoints = Object.fromEntries(CORE_ATTRIBUTES.map(a => [a, 0]));
          renderItems('Cộng Điểm Thuộc Tính');
        }
      });

      executeBtn.addEventListener('click', () => {
        try {
          const fmt = (it) => {
            const q = (it.quantity && it.quantity > 1) ? `x${it.quantity}` : '';
            return `${it.name}${q}`;
          };
          // Gửi lệnh Mua/Bán bằng tiếng Trung để hệ thống prompt hiểu (vì prompt thường dùng tiếng Trung)
          // Nếu prompt của bạn dùng tiếng Việt (Mua/Bán), hãy sửa "购买"->"Mua", "卖出"->"Bán"
          const buyPart  = selectedItems.length ? `购买${selectedItems.map(fmt).join('，')}` : '';
          const sellPart = sellItems.length     ? `卖出${sellItems.map(fmt).join('，')}`     : '';

          const out = [buyPart, sellPart].filter(Boolean).join('，');
          if (out) sendData(out);
        } catch (e) { console.error('Lỗi checkout:', e); }
      });

      window.addEventListener('resize', () => updatePriceAndButton());
      renderTabs();
    } catch (e) {
      console.error("Lỗi khởi tạo:", e);
      itemsContainer.innerHTML = `
        <div class="raw-data-display">
          <b>Lỗi kết nối dữ liệu:</b><br>${e.message}<br><br>
          <b>Vui lòng kiểm tra lại Zod Schema hoặc nội dung thẻ.</b>
        </div>`;
      executeBtn.disabled = true;
      executeBtn.textContent = 'Lỗi dữ liệu';
    }
  })();
</script>
</body>
</html>
